function isSegmentationDecorativeItem(itemOrText = "") {
  const text = typeof itemOrText === "string"
    ? itemOrText
    : `${itemOrText?.element || ""} ${itemOrText?.category || ""} ${itemOrText?.detectedMaterial || ""}`;
  return VISION_TAKEOFF_DECORATIVE_PATTERN.test(normalizeName(text));
}

function isSegmentationEligibleTakeoffItem(item) {
  if (!item?.inScope) return false;
  if (typeof item?.includeInSegmentation === "boolean") return item.includeInSegmentation;
  return !isSegmentationDecorativeItem(item);
}
