function createDefaultDesignProfile(overrides = {}) {
  return {
    sector: String(overrides.sector || "").trim(),
    philosophy: String(overrides.philosophy || "").trim(),
    budgetTone: String(overrides.budgetTone || "").trim(),
    interventionLevel: String(overrides.interventionLevel || "").trim(),
    colorApproach: {
      corporateColors: Array.isArray(overrides.colorApproach?.corporateColors) ? overrides.colorApproach.corporateColors.filter(Boolean).slice(0, 6) : [],
      preferredFamily: String(overrides.colorApproach?.preferredFamily || "").trim(),
      avoidColors: Array.isArray(overrides.colorApproach?.avoidColors) ? overrides.colorApproach.avoidColors.filter(Boolean) : [],
      notes: String(overrides.colorApproach?.notes || "").trim(),
    },
    materialApproach: {
      priority: String(overrides.materialApproach?.priority || "").trim(),
      preferredMaterials: Array.isArray(overrides.materialApproach?.preferredMaterials) ? overrides.materialApproach.preferredMaterials.filter(Boolean) : [],
      avoidMaterials: Array.isArray(overrides.materialApproach?.avoidMaterials) ? overrides.materialApproach.avoidMaterials.filter(Boolean) : [],
      notes: String(overrides.materialApproach?.notes || "").trim(),
    },
    lightingApproach: {
      temperatureRange: String(overrides.lightingApproach?.temperatureRange || "").trim(),
      preference: String(overrides.lightingApproach?.preference || "").trim(),
      avoidLighting: Array.isArray(overrides.lightingApproach?.avoidLighting) ? overrides.lightingApproach.avoidLighting.filter(Boolean) : [],
      notes: String(overrides.lightingApproach?.notes || "").trim(),
    },
    furnitureApproach: {
      priority: String(overrides.furnitureApproach?.priority || "").trim(),
      avoidFurniture: Array.isArray(overrides.furnitureApproach?.avoidFurniture) ? overrides.furnitureApproach.avoidFurniture.filter(Boolean) : [],
      notes: String(overrides.furnitureApproach?.notes || "").trim(),
    },
    generalNotes: String(overrides.generalNotes || "").trim(),
    sustainability: !!overrides.sustainability,
    templateId: String(overrides.templateId || "").trim(),
    customized: !!overrides.customized,
  };
}

function isDesignProfileConfigured(profile) {
  if (!profile || typeof profile !== "object") return false;
  return !!(profile.sector || profile.philosophy || profile.budgetTone || profile.generalNotes
    || profile.colorApproach?.preferredFamily || profile.materialApproach?.priority);
}

function summarizeDesignProfileForPrompt(profile) {
  if (!isDesignProfileConfigured(profile)) return "";
  const parts = [];
  if (profile.sector) parts.push(`Sektor: ${profile.sector}`);
  if (profile.philosophy) parts.push(`Felsefe: ${profile.philosophy}`);
  if (profile.budgetTone) parts.push(`Butce tonu: ${profile.budgetTone}`);
  if (profile.interventionLevel) parts.push(`Mudahale: ${profile.interventionLevel}`);
  const ca = profile.colorApproach;
  if (ca?.preferredFamily || ca?.notes || ca?.avoidColors?.length) {
    const cp = [`RENK PROFILI:`];
    if (ca.corporateColors?.length) cp.push(`kurumsal renkler: ${ca.corporateColors.join(", ")}`);
    if (ca.preferredFamily) cp.push(`tercih edilen ton ailesi: ${ca.preferredFamily}`);
    if (ca.avoidColors?.length) cp.push(`kacinilacak: ${ca.avoidColors.join(", ")}`);
    if (ca.notes) cp.push(ca.notes);
    parts.push(cp.join(". "));
  }
  const ma = profile.materialApproach;
  if (ma?.priority || ma?.preferredMaterials?.length || ma?.avoidMaterials?.length) {
    const mp = [`MALZEME PROFILI:`];
    if (ma.priority) mp.push(`oncelik: ${ma.priority}`);
    if (ma.preferredMaterials?.length) mp.push(`tercih: ${ma.preferredMaterials.join(", ")}`);
    if (ma.avoidMaterials?.length) mp.push(`kacinilacak: ${ma.avoidMaterials.join(", ")}`);
    if (ma.notes) mp.push(ma.notes);
    parts.push(mp.join(". "));
  }
  const la = profile.lightingApproach;
  if (la?.preference || la?.temperatureRange) {
    const lp = [`AYDINLATMA PROFILI:`];
    if (la.temperatureRange) lp.push(`sicaklik araligi: ${la.temperatureRange}K`);
    if (la.preference) lp.push(`tercih: ${la.preference}`);
    if (la.avoidLighting?.length) lp.push(`kacinilacak: ${la.avoidLighting.join(", ")}`);
    if (la.notes) lp.push(la.notes);
    parts.push(lp.join(". "));
  }
  const fa = profile.furnitureApproach;
  if (fa?.priority || fa?.avoidFurniture?.length) {
    const fp = [`MOBILYA PROFILI:`];
    if (fa.priority) fp.push(`oncelik: ${fa.priority}`);
    if (fa.avoidFurniture?.length) fp.push(`kacinilacak: ${fa.avoidFurniture.join(", ")}`);
    if (fa.notes) fp.push(fa.notes);
    parts.push(fp.join(". "));
  }
  if (profile.generalNotes) parts.push(`GENEL DUYARLILIKLAR: ${profile.generalNotes}`);
  if (profile.sustainability) parts.push("Surdurulebilirlik onceliklidir.");
  return parts.join(" ");
}

function getDesignProfileTemplateLabel(templateId) {
  return DESIGN_PROFILE_TEMPLATES[templateId]?.label || "";
}

