function createEmptyColorGrade() {
  return {
    h: 0,
    s: 0,
    l: 0,
    temperature: 0,
    tint: 0,
    contrast: 0,
    highlights: 0,
    shadows: 0,
  };
}

function createEmptyTargetColorDecision() {
  return {
    hex: "",
    strength: 0,
    lightness: 0,
    blendMode: "color",
    applicationMode: "direct",
  };
}

function normalizeTargetColorDecision(decision = {}) {
  const base = createEmptyTargetColorDecision();
  return {
    hex: String(decision?.hex || "").trim() ? normalizeHexColor(decision.hex) : "",
    strength: clampNumber(Number.isFinite(Number(decision?.strength)) ? Number(decision.strength) : base.strength, 0, 1),
    lightness: clampNumber(Number.isFinite(Number(decision?.lightness)) ? Number(decision.lightness) : base.lightness, -40, 40),
    blendMode: String(decision?.blendMode || base.blendMode || "color").trim() || "color",
    applicationMode: ["direct", "neutralized"].includes(String(decision?.applicationMode || "").trim()) ? String(decision.applicationMode).trim() : base.applicationMode,
  };
}

function hasActiveTargetColorDecision(decision = {}) {
  const normalized = normalizeTargetColorDecision(decision);
  return !!normalized.hex && normalized.strength > 0.001;
}

