async function initApp() {
  await loadCostDatabase();
  cacheDom();
  const migrationResult = await migrateFromLocalStorage();
  const appSettings = await getAppSettings();
  createDebugPanels();
  bindEvents();
  window.addEventListener("beforeunload", revokeRuntimeObjectUrls);
  window.addEventListener("popstate", () => {
    if (suppressHashChange) return;
    Object.assign(appLocation, hashToLocation());
    void applyLocation();
  });

  const hashLoc = hashToLocation();
  if (hashLoc.view !== "projects") {
    Object.assign(appLocation, hashLoc);
    await applyLocation();
    return;
  }

  const preferredProjectId = migrationResult?.projectId || appSettings.lastProjectId || "";
  const preferredSpaceId = migrationResult?.spaceId || appSettings.lastSpaceId || "";
  if (preferredProjectId && preferredSpaceId) {
    const space = await getSpace(preferredSpaceId);
    if (space && space.status !== "archived") {
      await goTo({ view: "space", projectId: space.projectId, spaceId: space.id });
      return;
    }
  }
  await goTo({ view: "projects" });
}

async function loadSpaceState(space) {
  revokeRuntimeObjectUrls();
  colorOriginalPeekActive = false;
  appState = space;
  currentProject = createDefaultProjectRecord(await getProject(space.projectId));
  dashboardState.projectId = currentProject?.id || "";
  dashboardState.projectTab = "identity";
  appLocation.view = "space";
  appLocation.projectId = currentProject?.id || space.projectId || "";
  appLocation.spaceId = space.id || "";
  appLocation.tab = "identity";
  resetIdentityDraft();
  applyProjectIdentityToState(currentProject, appState);
  const settings = await getAppSettings();
  appState.apiSettings = { ...createInitialState().apiSettings, ...(settings.apiSettings || {}), ...(appState.apiSettings || {}) };
  appState.debugPanel = { ...createInitialState().debugPanel, ...(settings.debugPanel || {}), ...(appState.debugPanel || {}) };
  if (!appState.currentPage || !STEP_TO_PAGE[appState.currentStep]) {
    appState.currentPage = STEP_TO_PAGE[appState.currentStep] || "kurulum";
  } else {
    appState.currentPage = STEP_TO_PAGE[appState.currentStep] || appState.currentPage;
  }
  if (!Array.isArray(appState.reportBasket)) appState.reportBasket = [];

  // Blob URLs re-hydration
  const medias = await getMediaForSpace(space.id);
  const mediaMap = {};
  medias.forEach(m => mediaMap[m.id] = m);

  for (let r of (appState.uploadedRenders || [])) {
    if (mediaMap[r.mediaId]) {
      const media = mediaMap[r.mediaId];
      if (media.blob) r.preview = trackObjectUrl(URL.createObjectURL(media.blob));
      if (media.hubPreviewBlob) r.hubPreview = trackObjectUrl(URL.createObjectURL(media.hubPreviewBlob));
      else r.hubPreview = r.preview;
    }
  }

  if (appState.uploadedPlan && mediaMap[appState.uploadedPlan.mediaId]) {
    const media = mediaMap[appState.uploadedPlan.mediaId];
    if (media.blob) appState.uploadedPlan.preview = trackObjectUrl(URL.createObjectURL(media.blob));
    if (media.hubPreviewBlob) appState.uploadedPlan.hubPreview = trackObjectUrl(URL.createObjectURL(media.hubPreviewBlob));
    else appState.uploadedPlan.hubPreview = appState.uploadedPlan.preview;
  }

  (appState.presetDraftImages || []).forEach((image) => {
    const media = mediaMap[image.mediaId];
    if (!media) return;
    if (media.blob) image.preview = trackObjectUrl(URL.createObjectURL(media.blob));
    if (media.hubPreviewBlob) image.hubPreview = trackObjectUrl(URL.createObjectURL(media.hubPreviewBlob));
  });

  (appState.reportData?.externalEntries || []).forEach((entry) => {
    const media = mediaMap[entry.mediaId];
    if (!media?.blob) return;
    entry.imageUrl = trackObjectUrl(URL.createObjectURL(media.blob));
  });

  renderLoadedSpaceWorkspace();
}

function renderLoadedSpaceWorkspace() {
  document.getElementById("dashboard")?.classList.remove("active");
  document.querySelector(".top-nav")?.classList.remove("hidden");
  syncTransientFields();
  renderTopNav();
  renderHeaderStepActions();
  renderProjectSummary();
  renderBreadcrumb();
  renderUploadedFiles();
  renderQuantityTable();
  renderReferencePanel();
  renderAlternatives();
  renderVisualPanels();
  renderDatabaseTables();
  syncAllHubImages();
  renderAllHubOverlays();
  renderReport();
  renderAISettings();
  renderMoodboardPresets();
  renderDebugPanels();
  sanitizeStaticUiText(document.body);
  showStep(appState.currentStep, { skipGuard: true });
}

async function showDashboard() {
  projectIdentityCompassOpen = false;
  colorOriginalPeekActive = false;
  document.querySelectorAll(".step-section").forEach(s => s.classList.remove("active"));
  const dashboardEl = document.getElementById("dashboard");
  dashboardEl.classList.add("active");
  document.querySelector(".top-nav")?.classList.add("hidden");
  if (ui.headerStepActionLeft) ui.headerStepActionLeft.innerHTML = "";
  if (ui.headerStepActionRight) ui.headerStepActionRight.innerHTML = "";
  if (ui.projectSummary) ui.projectSummary.innerHTML = "";

  const heading = document.getElementById("dashboard-heading");
  const grid = document.getElementById("dashboard-grid");
  const query = normalizeName(dashboardState.query || "");
  const statusFilter = dashboardState.status || "all";
  const allProjects = (await getAllProjects())
    .map((project) => createDefaultProjectRecord(project))
    .sort((a, b) => new Date(b.updatedAt || 0) - new Date(a.updatedAt || 0));

  const filteredProjects = allProjects.filter((project) => {
    const matchesQuery = !query
      || normalizeName(project.name).includes(query)
      || normalizeName(project.client).includes(query)
      || normalizeName(project.notes).includes(query);
    const matchesStatus = statusFilter === "all" || (project.status || "active") === statusFilter;
    return matchesQuery && matchesStatus;
  });

  if (dashboardState.view === "project" && dashboardState.projectId) {
    const project = createDefaultProjectRecord(await getProject(dashboardState.projectId));
    currentProject = project;
    if (!project?.id) {
      dashboardState.view = "projects";
      dashboardState.projectId = "";
      await showDashboard();
      return;
    }
    syncProjectEditorState(project);
    const spaces = (await getSpacesForProject(project.id))
      .sort((a, b) => new Date(b.updatedAt || 0) - new Date(a.updatedAt || 0));
    dashboardEl.classList.add("dashboard-project-view");
    grid.classList.remove("projects-grid");
    grid.classList.add("dashboard-project-grid");
    const toolbar = document.getElementById("dashboard-toolbar");
    if (toolbar) toolbar.classList.add("hidden");
    const activeTab = normalizeProjectTab(dashboardState.projectTab);
    heading.innerHTML = "";
    grid.innerHTML = `
      <section class="project-detail-shell">
        <div class="project-detail-body">
          ${renderProjectSettingsTab(project, spaces, activeTab)}
        </div>
      </section>
    `;
    syncProjectIdentityDomRefs();
    renderMoodboardPresets();
  } else {
    currentProject = null;
    dashboardState.view = "projects";
    dashboardState.projectId = "";
    dashboardState.projectTab = "settings";
    dashboardEl.classList.remove("dashboard-project-view");
    grid.classList.add("projects-grid");
    grid.classList.remove("dashboard-project-grid");
    const toolbar = document.getElementById("dashboard-toolbar");
    if (toolbar) toolbar.classList.remove("hidden");
    heading.innerHTML = "";
    const projectCardsMarkup = filteredProjects.length
      ? (await Promise.all(filteredProjects.map(async (project) => {
        const spaces = await getSpacesForProject(project.id);
        const totalTakeoff = spaces.reduce((sum, space) => sum + Number(space.quantityTakeoff?.length || 0), 0);
        return `
          <article class="project-card" data-dashboard-open-project="${project.id}">
            <div class="project-card-header">
              <div>
                <h3 class="project-card-title">${escapeHtml(project.name)}</h3>
                <p class="project-card-meta">${escapeHtml(project.client || "Musteri belirtilmedi")}</p>
              </div>
              <span class="badge ${project.status === "archived" ? "warning" : "success"}">${escapeHtml(project.status || "active")}</span>
            </div>
            <div class="project-card-body">
              ${project.globalPalette?.colors?.length ? `
              <div class="project-card-palette-strip">
                ${project.globalPalette.colors.map(hex => `<span style="background:${escapeHtml(hex)}"></span>`).join('')}
              </div>
              ` : ''}
              <p class="project-card-description">${escapeHtml(project.notes || "Proje kimligi, global palet ve mahal kararlarini saklayan ana konteyner.")}</p>
              <div class="project-card-stats">
                <span class="project-card-stat">${spaces.length} mahal</span>
                <span class="project-card-stat">${totalTakeoff} metraj kalemi</span>
                <span class="project-card-stat">${(project.moodboardPresets || []).length} preset</span>
              </div>
            </div>
            <div class="project-card-footer">
              <small>${new Date(project.updatedAt || Date.now()).toLocaleDateString("tr-TR")}</small>
              <div class="project-actions">
                <button type="button" class="icon-button" data-dashboard-action="rename-project" data-project-id="${project.id}" title="Projeyi duzenle">✎</button>
                <button type="button" class="icon-button" data-dashboard-action="toggle-project-archive" data-project-id="${project.id}" title="${project.status === "archived" ? "Projeyi arsivden cikar" : "Projeyi arsivle"}">${project.status === "archived" ? "↺" : "⎘"}</button>
                <button type="button" class="icon-button" data-dashboard-action="delete-project" data-project-id="${project.id}" title="Projeyi sil">×</button>
              </div>
            </div>
          </article>
        `;
      }))).join("")
      : "";
    grid.innerHTML = renderProjectsOverview(projectCardsMarkup, !!filteredProjects.length);
  }

  if (ui.dashboardSearchInput) ui.dashboardSearchInput.value = dashboardState.query;
  if (ui.dashboardStatusFilter) ui.dashboardStatusFilter.value = dashboardState.status;
  sanitizeStaticUiText(document.getElementById("dashboard"));
  renderBreadcrumb();
}

