function normalizeHubPreferences(preferences, currentStep = 1) {
  const defaultKeys = HUB_DEFINITIONS.map((item) => item.key);
  const preferredKeys = Array.isArray(preferences?.activeKeys)
    ? preferences.activeKeys.filter((key) => defaultKeys.includes(key))
    : defaultKeys;
  const activeKeys = Array.from(new Set([...REQUIRED_HUB_KEYS, ...preferredKeys]));
  const configured = typeof preferences?.configured === "boolean"
    ? preferences.configured
    : Number(currentStep || 1) >= 4;
  return {
    configured,
    activeKeys: activeKeys.length ? activeKeys : [...REQUIRED_HUB_KEYS],
  };
}

function getActiveHubKeys() {
  const preferences = normalizeHubPreferences(appState.hubPreferences, appState.currentStep);
  return preferences.activeKeys;
}

function isHubKeyActive(key) {
  return getActiveHubKeys().includes(key);
}

function isHubStep(stepNumber) {
  return HUB_DEFINITIONS.some((item) => item.step === Number(stepNumber));
}

function getHubDefinitionByStep(stepNumber) {
  return HUB_DEFINITIONS.find((item) => item.step === Number(stepNumber)) || null;
}

function getVisibleHubDefinitions() {
  return HUB_DEFINITIONS.filter((item) => isHubKeyActive(item.key));
}

function getHubImageSrc(file) {
  return file?.hubPreview || file?.preview || "";
}

function getActiveHubSteps() {
  return HUB_DEFINITIONS.filter((item) => isHubKeyActive(item.key)).map((item) => item.step);
}

function getHubGroupKeyForStep(stepNumber) {
  const step = Number(stepNumber);
  if (HUB_GROUPS.production.steps.includes(step)) return "production";
  if (HUB_GROUPS.evaluation.steps.includes(step)) return "evaluation";
  return "";
}

function getVisibleHubGroupSteps(groupKey) {
  const group = HUB_GROUPS[groupKey];
  if (!group) return [];
  return group.steps.filter((step) => getActiveHubSteps().includes(step));
}

function getHubGroupEntryStep(groupKey) {
  const visibleSteps = getVisibleHubGroupSteps(groupKey);
  if (!visibleSteps.length) return null;
  return visibleSteps.includes(Number(appState.currentStep)) ? Number(appState.currentStep) : visibleSteps[0];
}

function getRequiredHubPoolProgress() {
  const pool = ensureAlternativeResourcePool();
  return {
    color: {
      key: "color",
      label: "Renk",
      count: pool.colorNotes.length,
      target: 1,
      complete: pool.colorNotes.length >= 1,
    },
    material: {
      key: "material",
      label: "Malzeme",
      count: pool.materials.length,
      target: 1,
      complete: pool.materials.length >= 1,
    },
    lighting: {
      key: "lighting",
      label: "Isik",
      count: pool.lightingSuggestions.length,
      target: 1,
      complete: pool.lightingSuggestions.length >= 1,
    },
  };
}

function getRequiredHubQuestProgressList() {
  const progress = getRequiredHubPoolProgress();
  return REQUIRED_HUB_KEYS.map((key) => progress[key]);
}

function getFirstIncompleteRequiredHubKey() {
  const next = getRequiredHubQuestProgressList().find((item) => !item.complete);
  return next?.key || "";
}

