const QUEST_DESCRIPTIONS = {
  color: "Ana ton kararini ver",
  material: "1 tasiyici yuzey sec",
  lighting: "1 atmosfer senaryosu sec",
};

function resetHubDomBindings() {
  ui.hubPanelColor = ui.hubPanelUnified;
  ui.hubPanelMaterial = ui.hubPanelUnified;
  ui.hubPanelLighting = ui.hubPanelUnified;
  ui.hubPanelPlan = ui.hubPanelUnified;
  ui.hubPanelFurniture = ui.hubPanelUnified;
  ui.hubPanelAcoustics = ui.hubPanelUnified;
  ui.hubInlineDetailColor = ui.hubInlineDetailUnified;
  ui.hubInlineDetailMaterial = ui.hubInlineDetailUnified;
  ui.hubSplitDividerColor = ui.hubSplitDividerUnified;
  ui.hubSplitHandleColor = ui.hubSplitHandleUnified;
}

function getHubRegistryEntry(hubKey) {
  return HUB_REGISTRY[hubKey] || null;
}

function hubSupportsSplitView(hubKey) {
  return !!getHubRegistryEntry(hubKey)?.splitViewDefault;
}

function hubSupportsRegionSelection(hubKey) {
  const mode = getHubRegistryEntry(hubKey)?.interactionMode || "";
  return mode === "surface_mask" || mode === "bounding_box" || mode === "point_source";
}

function getHubInteractionCopy(hubKey) {
  const mode = getHubRegistryEntry(hubKey)?.interactionMode || "";
  const map = {
    surface_mask: "Yuzeyleri secip ayni dilde karar verin.",
    point_source: "Aydinlatma kaynaklarini ve vurgu mantigini okuyun.",
    "2d_overlay": "Plani organizasyon mantigi ve akis olarak okuyun.",
    bounding_box: "Mobilya ailelerini obje bazli degerlendirin.",
    heatmap: "Akustik performansi isi haritasi gibi okuyun.",
  };
  return map[mode] || "Hub baglamina gore etkilesim degisir.";
}

function getHubSplitState(hubKey = appState.activeAnalizHub) {
  appState.hubViewState = appState.hubViewState || {};
  const registry = getHubRegistryEntry(hubKey);
  const fallbackEnabled = !!registry?.splitViewDefault;
  const raw = appState.hubViewState[hubKey] || {};
  if (hubKey === "color") {
    appState.colorTool = normalizeColorToolState(appState.colorTool);
    return {
      enabled: typeof raw.splitEnabled === "boolean" ? raw.splitEnabled : !!appState.colorTool.splitViewEnabled,
      position: Number.isFinite(Number(raw.splitPosition)) ? clampNumber(Number(raw.splitPosition), 15, 85) : clampNumber(Number(appState.colorTool.splitPosition || 50), 15, 85),
    };
  }
  return {
    enabled: typeof raw.splitEnabled === "boolean" ? raw.splitEnabled : fallbackEnabled,
    position: Number.isFinite(Number(raw.splitPosition)) ? clampNumber(Number(raw.splitPosition), 15, 85) : 50,
  };
}

function setHubSplitState(hubKey, nextState = {}, options = {}) {
  const { persist = false } = options;
  appState.hubViewState = appState.hubViewState || {};
  const current = getHubSplitState(hubKey);
  const merged = {
    enabled: typeof nextState.enabled === "boolean" ? nextState.enabled : current.enabled,
    position: Number.isFinite(Number(nextState.position)) ? clampNumber(Number(nextState.position), 15, 85) : current.position,
  };
  appState.hubViewState[hubKey] = merged;
  if (hubKey === "color") {
    appState.colorTool = normalizeColorToolState(appState.colorTool);
    appState.colorTool.splitViewEnabled = merged.enabled;
    appState.colorTool.splitPosition = merged.position;
  }
  if (persist) saveState();
  return merged;
}

function syncHubCanvasToolbar(hubKey) {
  const splitState = getHubSplitState(hubKey);
  if (ui.hubInteractionBadgeUnified) ui.hubInteractionBadgeUnified.hidden = true;
  if (ui.hubToolbarCopyUnified) ui.hubToolbarCopyUnified.hidden = true;
  if (ui.hubViewerSplitToggleUnified) {
    const supported = hubSupportsSplitView(hubKey);
    ui.hubViewerSplitToggleUnified.hidden = !supported;
    ui.hubViewerSplitToggleUnified.classList.toggle("is-active", supported && splitState.enabled);
    ui.hubViewerSplitToggleUnified.setAttribute("aria-pressed", supported && splitState.enabled ? "true" : "false");
  }
}

function applyHubViewerTransform() {
  if (!ui.hubCanvasStageUnified || !ui.hubCanvasContainerUnified) return;
  ui.hubCanvasStageUnified.style.setProperty("--hub-scale", String(hubViewerState.scale));
  ui.hubCanvasStageUnified.style.setProperty("--hub-pan-x", `${Math.round(hubViewerState.panX)}px`);
  ui.hubCanvasStageUnified.style.setProperty("--hub-pan-y", `${Math.round(hubViewerState.panY)}px`);
  ui.hubCanvasContainerUnified.classList.toggle("is-pan-mode", !!hubViewerState.panMode);
  ui.hubCanvasContainerUnified.classList.toggle("is-panning", !!hubViewerState.panning);
  if (ui.hubViewerPanToggleUnified) {
    ui.hubViewerPanToggleUnified.classList.toggle("is-active", !!hubViewerState.panMode);
    ui.hubViewerPanToggleUnified.setAttribute("aria-pressed", hubViewerState.panMode ? "true" : "false");
  }
}

function resetHubViewerTransform() {
  hubViewerState.scale = 1;
  hubViewerState.panX = 0;
  hubViewerState.panY = 0;
  hubViewerState.panning = false;
  hubViewerState.pointerId = null;
  applyHubViewerTransform();
}

function adjustHubViewerZoom(delta = 0) {
  hubViewerState.scale = clampNumber(Number(hubViewerState.scale || 1) + Number(delta || 0), 1, 2.8);
  if (hubViewerState.scale === 1) {
    hubViewerState.panX = 0;
    hubViewerState.panY = 0;
  }
  applyHubViewerTransform();
}

function toggleHubViewerPanMode() {
  hubViewerState.panMode = !hubViewerState.panMode;
  if (!hubViewerState.panMode) hubViewerState.panning = false;
  applyHubViewerTransform();
}

function toggleHubSplitView() {
  const hubKey = appState.activeAnalizHub || "color";
  if (!hubSupportsSplitView(hubKey)) return;
  const current = getHubSplitState(hubKey);
  setHubSplitState(hubKey, { enabled: !current.enabled }, { persist: true });
  syncHubCanvasToolbar(hubKey);
  renderHubSplitDivider(hubKey);
  renderHubOverlayNow();
}

function handleHubViewerPointerDown(event) {
  if (!hubViewerState.panMode || hubViewerState.scale <= 1) return;
  if (event.target?.closest(".hub-split-divider")) return;
  hubViewerState.panning = true;
  hubViewerState.pointerId = event.pointerId;
  hubViewerState.startX = event.clientX;
  hubViewerState.startY = event.clientY;
  hubViewerState.originPanX = hubViewerState.panX;
  hubViewerState.originPanY = hubViewerState.panY;
  ui.hubCanvasContainerUnified?.setPointerCapture?.(event.pointerId);
  window.addEventListener("pointermove", handleHubViewerPointerMove);
  window.addEventListener("pointerup", handleHubViewerPointerUp);
  window.addEventListener("pointercancel", handleHubViewerPointerUp);
  applyHubViewerTransform();
}

function handleHubViewerPointerMove(event) {
  if (!hubViewerState.panning) return;
  const dx = event.clientX - hubViewerState.startX;
  const dy = event.clientY - hubViewerState.startY;
  hubViewerState.panX = hubViewerState.originPanX + dx;
  hubViewerState.panY = hubViewerState.originPanY + dy;
  applyHubViewerTransform();
}

function handleHubViewerPointerUp(event) {
  if (!hubViewerState.panning) return;
  ui.hubCanvasContainerUnified?.releasePointerCapture?.(event.pointerId);
  hubViewerState.panning = false;
  hubViewerState.pointerId = null;
  window.removeEventListener("pointermove", handleHubViewerPointerMove);
  window.removeEventListener("pointerup", handleHubViewerPointerUp);
  window.removeEventListener("pointercancel", handleHubViewerPointerUp);
  applyHubViewerTransform();
}

function handleHubViewerWheel(event) {
  if (!event.ctrlKey && !event.metaKey) return;
  event.preventDefault();
  adjustHubViewerZoom(event.deltaY > 0 ? -0.08 : 0.08);
}

function applyUnifiedHubBindings(hubKey) {
  if (!ui.unifiedHubShell) return;
  resetHubDomBindings();
  ui.unifiedHubShell.dataset.activeHub = hubKey || "";
  ui.unifiedHubShell.dataset.interactionMode = getHubRegistryEntry(hubKey)?.interactionMode || "";
}

function getHubReferenceFileForKey(hubKey) {
  return hubKey === "plan" ? appState.uploadedPlan : getSelectedReferenceRender();
}

function updateUnifiedHubFrame(hubKey) {
  if (!ui.unifiedHubShell) return;
  const usesRegionSelection = hubUsesRegionSelection(hubKey);
  const splitState = getHubSplitState(hubKey);
  if (hubKey !== "color") colorOriginalPeekActive = false;
  ui.unifiedHubShell.dataset.hubLayout = hubUsesRegionSelection(hubKey) ? "split" : "full";
  if (ui.hubRefImageUnified) {
    const file = getHubReferenceFileForKey(hubKey);
    ui.hubRefImageUnified.src = file ? getHubImageSrc(file) : "";
    ui.hubRefImageUnified.alt = hubKey === "plan" ? "Referans Plan" : "Referans Render";
  }
  if (ui.hubSelectionInfoUnified) {
    ui.hubSelectionInfoUnified.style.display = "";
  }
  if (ui.hubInlineDetailUnified) {
    ui.hubInlineDetailUnified.style.display = "none";
    ui.hubInlineDetailUnified.innerHTML = "";
  }
  if (ui.hubSplitDividerUnified) {
    ui.hubSplitDividerUnified.style.display = hubSupportsSplitView(hubKey) && splitState.enabled ? "" : "none";
  }
  syncHubCanvasToolbar(hubKey);
  resetHubViewerTransform();
  syncHubOriginalPeekPlacement();
  syncColorOriginalPeekButton();
}

function syncHubOriginalPeekPlacement() {
  const button = ui.hubOriginalPeekButtonUnified;
  if (!button) return;
  const stack = ui.headerStepActionRight?.querySelector(".header-step-action-stack");
  const shouldAttachToHeader = !!stack && isHubStep(appState.currentStep);
  if (shouldAttachToHeader) {
    if (button.parentElement !== stack) stack.insertBefore(button, stack.firstChild);
    button.classList.add("is-header-action");
    return;
  }
  if (ui.hubOriginalPeekStash && button.parentElement !== ui.hubOriginalPeekStash) {
    ui.hubOriginalPeekStash.appendChild(button);
  }
  button.classList.remove("is-header-action");
}

function renderHubPanelForKey(hubKey) {
  const entry = getHubRegistryEntry(hubKey);
  if (!entry?.panelBuilder || !ui.hubPanelUnified || !ui.hubInlineDetailUnified) return;
  applyUnifiedHubBindings(hubKey);
  updateUnifiedHubFrame(hubKey);
  const config = entry.panelBuilder(entry);
  ui.hubInlineDetailUnified.style.display = "";
  ui.hubInlineDetailUnified.innerHTML = renderHubContextMarkup(config) || '<div class="hub-panel-placeholder"><p>Genel degerlendirme hazir degil.</p></div>';
  ui.hubPanelUnified.innerHTML = renderHubBodyMarkup(config);
  renderHubSplitDivider(hubKey);
  renderUnifiedHubSelectionInfo();
  renderUnifiedHubOverlay();
  ensureHubEvaluation(hubKey);
}

function renderHubPoolWidget(hubKey) {
  const pool = ensureAlternativeResourcePool();
  const strategyItems = (pool.strategyNotes || []).filter((item) => item.meta?.hubKey === hubKey);
  const configMap = {
    color: { title: "Renk kararlari", copy: "Alternatif briefine giden karar notlari", items: pool.colorNotes },
    material: { title: "Malzeme havuzu", copy: "Secili yuzeylerden toplanan oneriler", items: pool.materials },
    lighting: { title: "Isik senaryolari", copy: "Alternatiflere aktarilan AI aydinlatma yonleri", items: pool.lightingSuggestions },
    plan: { title: "Plan notlari", copy: "Mekansal organizasyon kararlari ortak sepette saklanir.", items: strategyItems },
    furniture: { title: "Mobilya notlari", copy: "Ergonomi ve yerlesim kararlarini alternatif briefine tasir.", items: strategyItems },
    acoustics: { title: "Akustik notlari", copy: "Akustik strateji ve konfor notlari ortak sepette tutulur.", items: strategyItems },
  };
  const config = configMap[hubKey];
  if (config) {
    const latestItems = config.items.slice(0, 2);
    return `
      <section class="hub-pool-widget">
        <div class="hub-pool-widget-head">
          <div>
            <p class="section-kicker">Karar Havuzu</p>
            <strong>${escapeHtml(config.title)}</strong>
          </div>
          <span class="badge ${config.items.length ? "success" : "neutral"}">${config.items.length}</span>
        </div>
        <p class="hub-pool-widget-copy">${escapeHtml(config.copy)}</p>
        ${latestItems.length ? `
          <div class="hub-pool-widget-list">
            ${latestItems.map((item) => `
              <article class="hub-pool-widget-item">
                <strong>${escapeHtml(item.title || config.title)}</strong>
                <p>${escapeHtml(compactHubText(item.body || item.summary || "", 120))}</p>
                ${renderPoolProvenanceMarkup(item)}
              </article>
            `).join("")}
          </div>
        ` : `<div class="hub-pool-widget-empty">Bu hub'dan havuza eklenen kararlar burada gorunecek.</div>`}
      </section>
    `;
  }
  const cached = getValidHubCache(hubKey, null);
  if (!cached?.summary) return "";
  const sourceBadge = getHubSourceBadge(getHubDisplaySource(cached.source), cached?._timestamp);
  return `
    <section class="hub-pool-widget">
      <div class="hub-pool-widget-head">
        <div>
          <p class="section-kicker">AI Ozeti</p>
          <strong>${escapeHtml(HUB_BY_KEY[hubKey]?.navLabel || "Hub")}</strong>
        </div>
        <span class="badge ${escapeHtml(sourceBadge.className)}">${escapeHtml(sourceBadge.label)}</span>
      </div>
      <p class="hub-pool-widget-copy">${escapeHtml(compactHubText(cached.summary, 180))}</p>
    </section>
  `;
}

function addHubStrategyNoteToAlternativePool(hubKey) {
  const cached = getValidHubCache(hubKey, null);
  if (!cached?.summary) {
    showAlert("Once bu hub icin AI ozetini olusturun.", "warning");
    return;
  }
  const pool = ensureAlternativeResourcePool();
  const titleMap = {
    plan: "Plan stratejisi",
    furniture: "Mobilya stratejisi",
    acoustics: "Akustik stratejisi",
  };
  const note = {
    id: `${hubKey}_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
    type: "strategy",
    title: titleMap[hubKey] || "Hub stratejisi",
    summary: compactHubText(cached.summary, 180),
    body: (cached.recommendations || []).map((item) => `${item.title}: ${item.body}`).slice(0, 3).join(" ") || compactHubText(cached.summary, 280),
    sourceLabel: HUB_BY_KEY[hubKey]?.navLabel || hubKey,
    meta: { hubKey },
    provenance: {
      source: cached.source === HUB_SOURCE_AI ? "ai" : "fallback",
      dataInputs: ["render", "analysis"],
      affectedSurfaces: [],
      alternativeImpact: compactHubText(cached.summary, 120),
    },
    createdAt: new Date().toISOString(),
  };
  const exists = pool.strategyNotes.some((item) => item.meta?.hubKey === hubKey && normalizeName(item.summary || "") === normalizeName(note.summary || ""));
  if (exists) {
    showAlert("Bu strateji notu zaten ortak sepette var.", "warning");
    return;
  }
  pool.strategyNotes.unshift(note);
  saveState();
  renderHubPanels();
  renderAlternatives();
  renderPromptBuilder();
  showAlert(`${HUB_BY_KEY[hubKey]?.navLabel || "Hub"} notu ortak sepete eklendi.`, "success");
}

function getFirstHubStep() {
  return getActiveHubSteps()[0] || 4;
}

function getLastHubStep() {
  const activeSteps = getActiveHubSteps();
  return activeSteps[activeSteps.length - 1] || 2;
}

function getNextConfiguredStep(currentStep) {
  const stepNumber = Number(currentStep);
  if (stepNumber === 2) return getFirstHubStep();
  if (isHubStep(stepNumber)) {
    const activeSteps = getActiveHubSteps();
    const currentIndex = activeSteps.indexOf(stepNumber);
    return activeSteps[currentIndex + 1] || 3;
  }
  if (stepNumber === 3) return 10;
  if (stepNumber === 10) return 11;
  if (stepNumber === 11) return 12;
  if (stepNumber === 12) return 13;
  return null;
}

function getPreviousConfiguredStep(currentStep) {
  const stepNumber = Number(currentStep);
  if (isHubStep(stepNumber)) {
    const activeSteps = getActiveHubSteps();
    const currentIndex = activeSteps.indexOf(stepNumber);
    return currentIndex > 0 ? activeSteps[currentIndex - 1] : 2;
  }
  if (stepNumber === 3) return getLastHubStep();
  if (stepNumber === 10) return 3;
  if (stepNumber === 11) return 10;
  if (stepNumber === 12) return 11;
  if (stepNumber === 13) return 12;
  return null;
}



