function createDebugPanels() {
  document.querySelectorAll(".step-section").forEach((section) => {
    const stepNumber = Number(section.id.replace("step-", "")) || 0;
    let panel = section.querySelector("[data-debug-panel]");
    if (!panel) {
      panel = document.createElement("article");
      panel.className = "panel debug-panel";
      panel.setAttribute("data-debug-panel", String(stepNumber));
      panel.innerHTML = `
        <div class="panel-header">
          <div>
            <h3>Debug Prompt Monitor</h3>
            <p>Bu gecici panel canli prompt onizlemelerini ve son model ciktilarini gosterir.</p>
          </div>
        </div>
        <div class="debug-panel-body"></div>
      `;
      section.appendChild(panel);
    }
    ui.debugPanels[stepNumber] = panel.querySelector(".debug-panel-body");
  });
}

function formatDebugText(value) {
  if (value == null) return "";
  if (typeof value === "string") return value.trim();
  try {
    return JSON.stringify(value, null, 2);
  } catch (_) {
    return String(value);
  }
}

function truncateDebugText(value, max = 24000) {
  const text = formatDebugText(value);
  if (text.length <= max) return text;
  return `${text.slice(0, max).trim()}\n\n...[truncated for debug panel]`;
}

function recordDebugExchange(
  label,
  {
    source = "api",
    model = "",
    prompt = "",
    response = "",
    parsed = null,
    imageUrl = "",
  } = {},
) {
  appState.debugPanel = appState.debugPanel || createInitialState().debugPanel;
  const entry = {
    id: createId("debug"),
    timestamp: new Date().toLocaleTimeString("tr-TR", { hour: "2-digit", minute: "2-digit", second: "2-digit" }),
    label,
    source,
    model,
    prompt: truncateDebugText(prompt),
    response: truncateDebugText(response || parsed),
    imageUrl,
  };
  appState.debugPanel.history = [entry, ...(appState.debugPanel.history || [])].slice(0, 24);
  renderDebugPanels();
}

function buildDebugPromptItems() {
  const items = [];
  const unifiedPrompt = buildUnifiedDesignPrompt();
  items.push({ title: "Unified Brief", body: unifiedPrompt || "Henuz olusmadi." });

  if (appState.uploadedRenders.length && appState.uploadedPlan) {
    items.push({
      title: "Vision Quantity Prompt",
      body: buildVisionAnalysisQuantityPrompt(appState.uploadedRenders, appState.uploadedPlan),
    });
    items.push({
      title: "Vision Critique Prompt",
      body: buildVisionAnalysisCritiquePrompt(appState.uploadedRenders, appState.uploadedPlan),
    });
  }

  if (appState.quantityTakeoff.length) {
    items.push({
      title: "Alternative Generation Prompt",
      body: buildAlternativeGenerationPrompt(
        unifiedPrompt,
        appState.quantityTakeoff,
        appState.scopeSelections,
        getAlternativeCountRequest(),
      ),
    });

    const brief = buildStructuredBriefContract(
      unifiedPrompt,
      appState.quantityTakeoff,
      appState.scopeSelections,
      getAlternativeCountRequest(),
    );
    items.push({
      title: "Concept Agent Prompt",
      body: buildConceptGenerationPrompt(brief, appState.quantityTakeoff, getAlternativeCountRequest()),
    });

    const conceptAlternatives = (appState.alternatives || []).slice(0, 4).map((alternative, index) => ({
      id: alternative.pipelineId || `A${index + 1}`,
      title: alternative.title || "",
      concept: alternative.concept || "",
      reasonWhy: alternative.reasonWhy || "",
      differenceSummary: alternative.differenceSummary || "",
      budgetPosture: alternative.budgetImpact || "",
      statusLabel: alternative.statusLabel || "",
    }));

    if (conceptAlternatives.length) {
      items.push({
        title: "DNA Resolution Prompt",
        body: buildDNAResolutionPrompt(brief, conceptAlternatives, appState.quantityTakeoff, appState.scopeSelections),
      });

      const resolvedAlternatives = (appState.alternatives || []).slice(0, 4).map((alternative, index) => ({
        id: alternative.pipelineId || `A${index + 1}`,
        changedItems: Array.isArray(alternative.changedItems) ? alternative.changedItems : [],
        preservedItems: Array.isArray(alternative.preservedItems) ? alternative.preservedItems : [],
        materials: Array.isArray(alternative.materials)
          ? alternative.materials.map((material) => ({ name: material.name, quantity: material.quantity }))
          : [],
        colorDNA: alternative.colorDNA || "",
        suggestedColors: Array.isArray(alternative.suggestedColors) ? alternative.suggestedColors : [],
        budgetImpact: alternative.budgetImpact || "",
        statusLabel: alternative.statusLabel || "",
        dnaDecisions: Array.isArray(alternative.dnaDecisions) ? alternative.dnaDecisions : [],
      }));
      items.push({
        title: "Prompt Composer Prompt",
        body: buildPromptComposerPrompt(brief, resolvedAlternatives),
      });
    }
  }

  const activeAlternative =
    appState.alternatives.find((alternative) => alternative.selected)
    || appState.alternatives[0]
    || null;

  if (activeAlternative) {
    items.push({
      title: "Visual Prompt Generator",
      body: buildVisualPromptGenerationPrompt(activeAlternative, activeAlternative.revisionPrompt || "", appState.preserveGeometry),
    });
    items.push({
      title: "Controlled Visual Prompt",
      body: buildControlledVisualPrompt(activeAlternative, activeAlternative.revisionPrompt || "", appState.preserveGeometry),
    });
  }

  return items.filter((item) => item.body);
}

function renderDebugPanels() {
  if (!ui.debugPanels) return;
  const livePrompts = buildDebugPromptItems();
  const history = (appState.debugPanel?.history || []).slice(0, 8);
  const resolveVisibleDebugStep = () => {
    if (appState.currentPage === "analiz") {
      const activeHubStep = HUB_BY_KEY[appState.activeAnalizHub || ""]?.step;
      return Number(activeHubStep || 2);
    }
    return Number(appState.currentStep || 1);
  };
  const visibleStep = resolveVisibleDebugStep();
  const markup = `
    <div class="debug-grid">
      <section class="debug-column">
        <div class="debug-section-title">Canli Promptlar</div>
        ${livePrompts.length ? livePrompts.map((item, index) => `
          <details class="debug-card" ${index === 0 ? "open" : ""}>
            <summary>${escapeHtml(item.title)}</summary>
            <textarea class="debug-textarea" rows="10" readonly>${escapeHtml(item.body)}</textarea>
          </details>
        `).join("") : '<div class="debug-empty">Bu step icin henuz prompt olusmadi.</div>'}
      </section>
      <section class="debug-column">
        <div class="debug-section-title">Son Model Ciktilari</div>
        ${history.length ? history.map((entry, index) => `
          <details class="debug-card" ${index === 0 ? "open" : ""}>
            <summary>${escapeHtml(entry.label)} <span class="debug-meta">${escapeHtml(entry.timestamp)} / ${escapeHtml(entry.source)}${entry.model ? ` / ${escapeHtml(entry.model)}` : ""}</span></summary>
            <div class="debug-subtitle">Istek</div>
            <textarea class="debug-textarea" rows="8" readonly>${escapeHtml(entry.prompt || "Kaydedilmedi.")}</textarea>
            <div class="debug-subtitle">Cevap</div>
            <textarea class="debug-textarea" rows="8" readonly>${escapeHtml(entry.response || "Henuz cevap yok.")}</textarea>
            ${entry.imageUrl ? `
              <div class="debug-subtitle">Gorsel</div>
              <a class="debug-image-link" href="${escapeHtml(entry.imageUrl)}" target="_blank" rel="noreferrer">
                <img class="debug-image" src="${escapeHtml(entry.imageUrl)}" alt="${escapeHtml(entry.label)} onizleme gorseli">
              </a>
            ` : ""}
          </details>
        `).join("") : '<div class="debug-empty">Henuz model cagrisi kaydi yok.</div>'}
      </section>
    </div>
  `;
  Object.entries(ui.debugPanels).forEach(([stepKey, container]) => {
    if (!container) return;
    const panel = container.closest("[data-debug-panel]");
    const shouldShow = Number(stepKey) === visibleStep;
    if (panel) panel.style.display = shouldShow ? "" : "none";
    if (shouldShow) container.innerHTML = markup;
  });
}

