function syncTransientFields() {
  const incomingWorkflowVersion = Number(appState.workflowVersion || 1);
  if (incomingWorkflowVersion < WORKFLOW_VERSION) {
    if (incomingWorkflowVersion < 7) {
      if (appState.currentStep >= 4) {
        appState.currentStep += 4;
      }
    }
    if (incomingWorkflowVersion < 2 && Number(appState.currentStep || 1) >= 3) {
      appState.currentStep = Number(appState.currentStep) + 1;
    }
    if (incomingWorkflowVersion < 3) {
      const hasLegacyDefaultBudget =
        Number(appState.budgetPreference ?? 0) === 0 &&
        Number(appState.budgetRange?.min ?? 0) === 0 &&
        Number(appState.budgetRange?.max ?? 0) === 0;
      const hasLegacyDefaultAggressiveness =
        Number(appState.designAggressiveness ?? 2) === 2 &&
        Number(appState.designAggressivenessRange?.min ?? 2) === 2 &&
        Number(appState.designAggressivenessRange?.max ?? 2) === 2;
      const hasLegacyDefaultAlternativeCount =
        Number(appState.alternativeCount ?? 4) === 4 &&
        Number(appState.alternativeCountRange?.min ?? 4) === 4 &&
        Number(appState.alternativeCountRange?.max ?? 4) === 4;

      if (hasLegacyDefaultBudget) {
        appState.budgetRange = { min: 1, max: 3 };
        appState.budgetPreference = 2;
      }
      if (hasLegacyDefaultAggressiveness) {
        appState.designAggressivenessRange = { min: 1, max: 2 };
        appState.designAggressiveness = 1;
      }
      if (hasLegacyDefaultAlternativeCount) {
        appState.alternativeCountRange = { min: 3, max: 4 };
        appState.alternativeCount = 4;
      }
    }
    if (incomingWorkflowVersion < 8) {
      if (Number(appState.currentStep || 1) >= 8) {
        appState.currentStep = Number(appState.currentStep) + 1;
      }
    }
    if (incomingWorkflowVersion < 9) {
      const initialState = createInitialState();
      const hasLegacyMockAnalysis = appState.analysisSummary?.mode === "mock";
      if (hasLegacyMockAnalysis) {
        appState.analysisSummary = null;
        appState.quantityTakeoff = [];
        appState.scopeSelections = { ...initialState.scopeSelections };
        appState.segmentation = { ...initialState.segmentation };
        appState.decisionLog = [];
        appState.alternatives = [];
        appState.alternativeBoard = { ...initialState.alternativeBoard };
        appState.alternativeResourcePool = { ...initialState.alternativeResourcePool };
        appState.generatedVisuals = {};
        appState.hubEvaluations = {};
        appState.materialAtlas = { ...initialState.materialAtlas };
        appState.currentStep = 1;
        appState.currentPage = "kurulum";
      }
      if (appState.materialAtlas?.mode === "mock") {
        appState.materialAtlas = { ...initialState.materialAtlas };
      }
      if (appState.generatedVisuals && typeof appState.generatedVisuals === "object") {
        appState.generatedVisuals = Object.fromEntries(
          Object.entries(appState.generatedVisuals).filter(([, visual]) => visual?.mode !== "mock"),
        );
      }
    }
    appState.workflowVersion = WORKFLOW_VERSION;
  }
  appState.segmentation = { ...createInitialState().segmentation, ...(appState.segmentation || {}) };
  appState.decisionLog = Array.isArray(appState.decisionLog) ? appState.decisionLog : [];
  appState.designBrief = { ...createInitialState().designBrief, ...(appState.designBrief || {}) };
  appState.currentStep = Math.min(13, Math.max(1, Number(appState.currentStep || 1)));
  appState.loading = createInitialState().loading;
  appState.scopeSelections = { ...createInitialState().scopeSelections, ...(appState.scopeSelections || {}) };
  appState.identityBindings = { ...createInitialState().identityBindings, ...(appState.identityBindings || {}) };
  appState.costDatabase = Array.isArray(appState.costDatabase) && appState.costDatabase.length ? appState.costDatabase : deepClone(DEFAULT_COST_DATABASE);
  appState.budgetRange = normalizeBudgetRange(appState.budgetRange || { min: appState.budgetPreference, max: appState.budgetPreference });
  appState.budgetPreference = getBudgetRepresentativeLevel(appState.budgetRange);
  appState.designAggressivenessRange = normalizeAggressivenessRange(appState.designAggressivenessRange || { min: appState.designAggressiveness, max: appState.designAggressiveness });
  appState.designAggressiveness = getAggressivenessRepresentativeLevel(appState.designAggressivenessRange);
  appState.alternativeCountRange = normalizeAlternativeCountRange(appState.alternativeCountRange || { min: appState.alternativeCount, max: appState.alternativeCount });
  appState.alternativeCount = getAlternativeCountRepresentativeLevel(appState.alternativeCountRange);
  appState.alternativeViewMode = appState.alternativeViewMode === "detail" ? "detail" : "summary";
  appState.alternativeFilter = ["active", "report", "rejected", "base", "all"].includes(appState.alternativeFilter) ? appState.alternativeFilter : "active";
  appState.promptSelections = { ...createInitialState().promptSelections, ...(appState.promptSelections || {}) };
  PROMPT_MULTI_FIELDS.forEach((field) => {
    appState.promptSelections[field] = normalizePromptSelectionValues(appState.promptSelections[field], createInitialState().promptSelections[field]);
  });
  appState.promptSelectionSource = appState.promptSelectionSource || {};
  appState.promptOptionExpansion = { ...createInitialState().promptOptionExpansion, ...(appState.promptOptionExpansion || {}) };
  appState.hubPreferences = normalizeHubPreferences(appState.hubPreferences, appState.currentStep);
  appState.promptBuilder = { ...createInitialState().promptBuilder, ...(appState.promptBuilder || {}) };
  appState.colorTool = normalizeColorToolState(appState.colorTool);
  appState.hubEvaluations = appState.hubEvaluations && typeof appState.hubEvaluations === "object" ? appState.hubEvaluations : {};
  appState.hubEvaluations.color = normalizeColorHubCache(appState.hubEvaluations.color);
  if (typeof appState.designPrompt === "string" && /Japandi tarz/i.test(appState.designPrompt)) {
    appState.designPrompt = "";
  }
  appState.quantityTakeoff = normalizeQuantityTakeoffItems(appState.quantityTakeoff, appState.scopeSelections);
  appState.alternatives = Array.isArray(appState.alternatives) ? appState.alternatives.map(normalizeAlternativeState) : [];
  appState.savedAlternatives = Array.isArray(appState.savedAlternatives) ? appState.savedAlternatives : [];
  appState.alternativeBoard = normalizeAlternativeBoardState(appState.alternativeBoard);
  appState.alternativeResourcePool = normalizeAlternativeResourcePool(appState.alternativeResourcePool);
  appState.materialTool = { ...createInitialState().materialTool, ...(appState.materialTool || {}) };
  appState.materialTool.selectedByTarget = appState.materialTool.selectedByTarget && typeof appState.materialTool.selectedByTarget === "object" ? appState.materialTool.selectedByTarget : {};
  appState.materialTool.surpriseByTarget = appState.materialTool.surpriseByTarget && typeof appState.materialTool.surpriseByTarget === "object" ? appState.materialTool.surpriseByTarget : {};
  appState.materialTool.aiByTarget = appState.materialTool.aiByTarget && typeof appState.materialTool.aiByTarget === "object" ? appState.materialTool.aiByTarget : {};
  appState.materialTool.dismissedByTarget = appState.materialTool.dismissedByTarget && typeof appState.materialTool.dismissedByTarget === "object" ? appState.materialTool.dismissedByTarget : {};
  appState.pendingLightingScenarioIndex = Number.isFinite(Number(appState.pendingLightingScenarioIndex)) ? Number(appState.pendingLightingScenarioIndex) : -1;
  appState.approvedAlternatives = Array.isArray(appState.approvedAlternatives) ? appState.approvedAlternatives : [];
  appState.generatedVisuals = appState.generatedVisuals || {};
  appState.materialAtlas = { ...createInitialState().materialAtlas, ...(appState.materialAtlas || {}) };
  appState.unknownMaterials = Array.isArray(appState.unknownMaterials) ? appState.unknownMaterials : [];
  appState.moodboardPresets = Array.isArray(appState.moodboardPresets) ? appState.moodboardPresets : [];
  appState.activePresetId = appState.moodboardPresets.some((preset) => preset.id === appState.activePresetId) ? appState.activePresetId : (appState.moodboardPresets[0]?.id || "");
  appState.presetDraftImages = Array.isArray(appState.presetDraftImages) ? appState.presetDraftImages : [];
  appState.apiSettings = { ...createInitialState().apiSettings, ...(appState.apiSettings || {}) };
  appState.apiSettings.primaryKey = appState.apiSettings.primaryKey || appState.apiSettings.llmKey || "";
  appState.apiSettings.showAdvancedKeys = !!appState.apiSettings.showAdvancedKeys;
  appState.reportData = { ...createInitialState().reportData, ...(appState.reportData || {}) };
  appState.reportData.refinedPackets = Array.isArray(appState.reportData.refinedPackets) ? appState.reportData.refinedPackets : [];
  appState.reportData.externalEntries = Array.isArray(appState.reportData.externalEntries) ? appState.reportData.externalEntries : [];
  appState.reportData.sourceOrder = Array.isArray(appState.reportData.sourceOrder) ? appState.reportData.sourceOrder : [];
  if (!String(appState.reportData.projectTitle || "").trim()) {
    const fallbackProjectTitle = [currentProject?.name, appState.name].filter(Boolean).join(" / ");
    appState.reportData.projectTitle = fallbackProjectTitle || createInitialState().reportData.projectTitle;
  }
  appState.debugPanel = { ...createInitialState().debugPanel, ...(appState.debugPanel || {}) };
  appState.debugPanel.history = Array.isArray(appState.debugPanel.history) ? appState.debugPanel.history.slice(0, 24) : [];
  if (!appState.alternatives.some((alternative) => alternative.id === appState.reportData.selectedDesignId)) {
    appState.reportData.selectedDesignId = "";
  }
  if (!appState.uploadedRenders.some((file) => file.id === appState.selectedReferenceRenderId)) {
    appState.selectedReferenceRenderId = appState.uploadedRenders[0]?.id || "";
  }
  appState.uploadedRenders = (appState.uploadedRenders || []).map((file) => ({
    ...file,
    hubPreview: file.hubPreview || file.preview || "",
  }));
  if (appState.uploadedPlan) {
    appState.uploadedPlan = {
      ...appState.uploadedPlan,
      hubPreview: appState.uploadedPlan.hubPreview || appState.uploadedPlan.preview || "",
    };
  }
  if ((!appState.uploadedRenders.length || !appState.uploadedPlan) && Number(appState.currentStep || 1) > 1) {
    appState.currentStep = 1;
  }
  syncScopeSelectionsFromTakeoff();
  syncUnknownMaterialsFromAlternatives();
}

async function saveState() {
  if (appState.id) {
    try {
      await saveSpace(sanitizeStateForPersistence(appState));
      await saveGlobalSettingsPatch({
        apiSettings: getGlobalApiSettingsFromState(appState),
        debugPanel: deepClone(appState.debugPanel || createInitialState().debugPanel),
        lastProjectId: appState.projectId || currentProject?.id || null,
        lastSpaceId: appState.id || null,
      });
    } catch(e) {
      console.error("Failed to save state to IndexedDB", e);
      if(typeof showAlert === "function") showAlert("Veri kaydedilemedi", "error");
    }
  }
}

function resetReportSelectionState(options = {}) {
  const { clearApprovals = false, invalidateRefined = true } = options;
  appState.reportBasket = [];
  appState.reportData = {
    ...appState.reportData,
    selectedDesignId: "",
  };
  if (clearApprovals) appState.approvedAlternatives = [];
  if (invalidateRefined) invalidateRefinedReportData();
}

function getSerializableState(mode = "full") {
  const isLite = mode === "lite";
  const isMinimal = mode === "minimal";
  const snapshot = deepClone({ ...appState, loading: undefined });
  delete snapshot.debugPanel;

  if (isLite || isMinimal) {
    // Pixel-level segmentation data grows very quickly and is safe to recompute.
    snapshot.segmentation = {
      ...createInitialState().segmentation,
      ...(snapshot.segmentation || {}),
      status: "idle",
      regions: [],
      pixelData: null,
    };

    if (snapshot.generatedVisuals && typeof snapshot.generatedVisuals === "object") {
      snapshot.generatedVisuals = Object.fromEntries(
        Object.entries(snapshot.generatedVisuals).map(([altId, visual]) => {
          const safeUrl = (isMinimal || String(visual?.url || "").startsWith("data:image/"))
            ? ""
            : String(visual?.url || "");
          return [altId, { ...visual, url: safeUrl }];
        }),
      );
    }

    if (snapshot.materialAtlas?.url && (isMinimal || String(snapshot.materialAtlas.url).startsWith("data:image/"))) {
      snapshot.materialAtlas.url = "";
      snapshot.materialAtlas.fingerprint = "";
      snapshot.materialAtlas.mode = "idle";
    }
  }

  if (isMinimal) {
    snapshot.uploadedRenders = snapshot.uploadedRenders.map((file) => ({
      ...file,
      preview: createFilePlaceholder(file.name, file.typeLabel, "#56606a", "#d7dbde"),
      hubPreview: createFilePlaceholder(file.name, file.typeLabel, "#56606a", "#d7dbde"),
    }));

    if (snapshot.materialAtlas) {
      snapshot.materialAtlas.url = "";
      snapshot.materialAtlas.fingerprint = "";
      snapshot.materialAtlas.mode = "idle";
    }

    if (snapshot.uploadedPlan) {
      const planPreview = createFilePlaceholder(snapshot.uploadedPlan.name, snapshot.uploadedPlan.typeLabel, "#3a434c", "#dfe3e6");
      snapshot.uploadedPlan.preview = planPreview;
      snapshot.uploadedPlan.hubPreview = planPreview;
    }
  }

  return snapshot;
}

function showPage(pageKey) {
  const page = PAGE_BY_KEY[pageKey];
  if (!page) return;
  showStep(page.defaultStep, { skipGuard: true });
}

function showStep(stepNumber, options = {}) {
  // Redirect step 12 → open cost database drawer instead
  if (stepNumber === 12) {
    openCostDatabaseDrawer();
    return;
  }

  if (!options.skipGuard && !canAccessStep(stepNumber)) return;
  const previousStep = appState.currentStep;
  appState.currentStep = stepNumber;
  appState.currentPage = STEP_TO_PAGE[stepNumber] || appState.currentPage;

  // Hub steps now render inside the unified Analiz shell.
  if (isHubStep(stepNumber)) {
    appState.activeAnalizHub = getHubDefinitionByStep(stepNumber)?.key || "";
    document.querySelectorAll(".step-section").forEach((section) => {
      section.classList.toggle("active", section.id === "step-2");
    });
  } else {
    document.querySelectorAll(".step-section").forEach((section) => {
      section.classList.toggle("active", section.id === `step-${stepNumber}`);
    });
    if (STEP_TO_PAGE[stepNumber] === "analiz") {
      appState.activeAnalizHub = "";
    }
  }

  if (previousStep === 1 && isHubStep(stepNumber) && appState.quantityTakeoff.length) {
    void ensureSegmentationReady({ background: true, reason: "takeoff-transition" });
  }
  renderProjectSummary();
  renderTopNav();
  renderHeaderStepActions();
  if (stepNumber === 13) renderReport();
  // Render Analiz page content when on analiz page
  if (appState.currentPage === "analiz") {
    renderAnalizPage();
  }
  renderDebugPanels();
  const activeSection = isHubStep(stepNumber)
    ? document.getElementById("step-2")
    : document.getElementById(`step-${stepNumber}`);
  if (activeSection) sanitizeStaticUiText(activeSection);
  saveState();
}

function canAccessStep(stepNumber) {
  const wantsHubStep = isHubStep(stepNumber);
  const targetHubKey = getHubDefinitionByStep(stepNumber)?.key || "";
  const needsSegmentation = wantsHubStep && hubRequiresSegmentation(targetHubKey);
  const hasUploads = !!appState.uploadedRenders.length && !!appState.uploadedPlan;
  const hasAnalysis = !!appState.quantityTakeoff.length;
  const segmentationStatus = appState.segmentation?.status || "idle";

  // Hub steps are now accessed inline from Analiz page — no modal gate needed
  if (needsSegmentation && hasUploads && hasAnalysis && segmentationStatus !== "ready") {
    void ensureSegmentationReady({ background: true, reason: "hub-navigation" });
  }

  const stepState = getWorkflowStepState(stepNumber);
  if (stepState.locked) {
    showAlert(stepState.hint || "Bu adima gecmek icin onceki asamalari tamamlamalisiniz.", "warning");
    return false;
  }
  return true;
}

function renderTopNav() {
  const aiStatus = getAiStatusMeta();
  ui.topNav.innerHTML = PAGE_DEFINITIONS.map((page) => `
    <button
      type="button"
      class="nav-button ${appState.currentPage === page.key ? "active" : ""}"
      data-page="${page.key}"
      title="${escapeHtml(page.label)}"
    >
      <span class="nav-button-label">${escapeHtml(page.label)}</span>
    </button>
  `).join("");

  ui.topNav.querySelectorAll("[data-page]").forEach((button) => {
    button.addEventListener("click", () => showPage(button.dataset.page));
  });
  if (ui.aiStatusPill) ui.aiStatusPill.textContent = aiStatus.label;
  sanitizeStaticUiText(ui.topNav);
}

function getHeaderStepActions(stepNumber) {
  const pageKey = appState.currentPage;
  const pageActionMap = {
    kurulum: {
      left: { label: "← Proje Detayina Don", mode: "event", action: "open-project-detail", variant: "secondary" },
      right: {
        label: appState.loading.analysis ? "Analiz Calisiyor..." : "Analiz Et",
        mode: "event",
        action: "analyze",
        variant: "primary",
        disabled: appState.loading.analysis,
      },
    },
    analiz: {
      left: { label: "← Proje Detayina Don", mode: "event", action: "open-project-detail", variant: "secondary" },
      right: {
        label: appState.loading.alternatives ? "Alternatifler Uretiliyor..." : "Alternatifleri Uret",
        mode: "event",
        action: "generate-alternatives",
        variant: "primary",
        disabled: appState.loading.alternatives,
      },
    },
    uretim: {
      left: { label: "Analize Don", mode: "page", page: "analiz", variant: "secondary" },
      right: null,
    },
    rapor: {
      left: { label: "Uretime Don", mode: "page", page: "uretim", variant: "secondary" },
      right: { label: "Sunumu Hazirla", mode: "event", action: "export-report", variant: "primary" },
    },
  };
  return pageActionMap[pageKey] || { left: null, right: null };
}

function shouldShowProjectIdentityCompass() {
  return !!currentProject?.id && !!appState?.id && !document.getElementById("dashboard")?.classList.contains("active");
}

function renderProjectIdentityCompass() {
  if (!shouldShowProjectIdentityCompass()) return "";
  const context = getProjectIdentityCompassData();
  if (!context) return "";
  const selectedPresets = Array.isArray(context.selectedPresets) ? context.selectedPresets : [];
  const paletteColors = Array.isArray(context.globalPalette?.colors) ? context.globalPalette.colors.filter(Boolean).slice(0, 6) : [];
  return `
    <div class="project-identity-compass-shell${projectIdentityCompassOpen ? " is-open" : ""}">
      <button
        type="button"
        class="header-step-action secondary project-identity-compass-trigger"
        data-header-action="toggle-identity-compass"
        aria-expanded="${projectIdentityCompassOpen ? "true" : "false"}"
        aria-haspopup="dialog">
        Proje Kimligi
      </button>
      <div class="project-identity-compass-popover${projectIdentityCompassOpen ? "" : " hidden"}" aria-hidden="${projectIdentityCompassOpen ? "false" : "true"}">
        <div class="project-identity-compass-head">
          <div>
            <p class="section-kicker">AI Degerlendirme Baglami</p>
            <strong>${escapeHtml(context.projectName || "Adsiz Proje")} / ${escapeHtml(context.spaceName || "Adsiz Mahal")}</strong>
          </div>
          <span class="badge neutral">${escapeHtml(context.aiProfileLabel)}</span>
        </div>
        <p class="compass-context-hint micro-copy">Bu mahal icin AI analiz ve degerlendirmelerinde kullanilan proje kimligi ozeti. Dolu alanlar AI ciktilarinin kalitesini arttirir.</p>
        <div class="project-identity-compass-section">
          <span class="project-identity-compass-label">Musteri / Aidiyet</span>
          <p>${escapeHtml(context.client || "Belirtilmedi")}</p>
        </div>
        <div class="project-identity-compass-section">
          <span class="project-identity-compass-label">Kimlik Notu</span>
          <p>${escapeHtml(context.notes || "Bu proje icin ek kimlik notu girilmedi.")}</p>
        </div>
        <div class="project-identity-compass-section">
          <div class="project-identity-compass-inline">
            <span class="project-identity-compass-label">Global Palet</span>
            <span class="badge neutral">${escapeHtml(context.paletteModeLabel || "Kapali")}</span>
          </div>
          <div class="project-identity-compass-swatches">
            ${paletteColors.length
              ? paletteColors.map((hex) => `<span class="project-identity-compass-swatch" style="--swatch:${escapeHtml(hex)}" title="${escapeHtml(hex)}"></span>`).join("")
              : '<span class="micro-copy">Global palet rengi tanimlanmadi.</span>'}
          </div>
        </div>
        <div class="project-identity-compass-section">
          <span class="project-identity-compass-label">Secili Proje Presetleri</span>
          ${selectedPresets.length
            ? `<div class="project-identity-compass-chip-row">${selectedPresets.map((preset) => `<span class="badge neutral">${escapeHtml(preset.name || "Preset")}</span>`).join("")}</div>`
            : '<p>Bu mahal henuz proje presetlerinden secim yapmiyor.</p>'}
        </div>
        ${context.designProfileConfigured ? `
        <div class="project-identity-compass-section">
          <div class="project-identity-compass-inline">
            <span class="project-identity-compass-label">Tasarim Profili</span>
            <span class="badge success">${escapeHtml(context.designProfileLabel || "Aktif")}</span>
          </div>
          ${context.designProfile?.budgetTone ? `<p class="micro-copy">Butce: ${escapeHtml(context.designProfile.budgetTone)}${context.designProfile.interventionLevel ? ` · Mudahale: ${escapeHtml(context.designProfile.interventionLevel)}` : ""}</p>` : ""}
          ${context.designProfile?.materialApproach?.preferredMaterials?.length ? `
          <div class="project-identity-compass-chip-row">
            ${context.designProfile.materialApproach.preferredMaterials.slice(0, 4).map((m) => `<span class="badge neutral">${escapeHtml(m)}</span>`).join("")}
          </div>` : ""}
        </div>
        ` : `
        <div class="project-identity-compass-section">
          <div class="project-identity-compass-inline">
            <span class="project-identity-compass-label">Tasarim Profili</span>
            <span class="badge warning">Tanimlanmadi</span>
          </div>
          <p class="micro-copy">Proje ayarlarindan bir tasarim profili secin; AI degerlendirmeleri bu profile gore yapilsin.</p>
        </div>
        `}
        <div class="project-identity-compass-actions">
          <button type="button" class="secondary-button" data-header-action="edit-project-identity">Proje Kimligini Duzenle</button>
        </div>
      </div>
    </div>
  `;
}

function openProjectIdentityCompass() {
  if (!shouldShowProjectIdentityCompass()) return;
  projectIdentityCompassOpen = true;
  renderHeaderStepActions();
}

function closeProjectIdentityCompass() {
  if (!projectIdentityCompassOpen) return;
  projectIdentityCompassOpen = false;
  renderHeaderStepActions();
}

function renderHeaderStepActions() {
  if (!ui.headerStepActionLeft || !ui.headerStepActionRight) return;
  const { left, right } = getHeaderStepActions(appState.currentStep);
  ui.headerStepActionLeft.innerHTML = left ? createHeaderStepActionMarkup(left) : "";
  const rightFragments = [renderProjectIdentityCompass(), right ? createHeaderStepActionMarkup(right) : ""].filter(Boolean);
  ui.headerStepActionRight.innerHTML = rightFragments.length ? `<div class="header-step-action-stack">${rightFragments.join("")}</div>` : "";
  syncHubOriginalPeekPlacement();

  [ui.headerStepActionLeft, ui.headerStepActionRight].forEach((slot) => {
    slot.querySelectorAll("[data-header-nav-step]").forEach((button) => {
      button.addEventListener("click", () => showStep(Number(button.dataset.headerNavStep)));
    });
    slot.querySelectorAll("[data-header-nav-page]").forEach((button) => {
      button.addEventListener("click", () => showPage(button.dataset.headerNavPage));
    });
    slot.querySelectorAll("[data-header-action]").forEach((button) => {
      button.addEventListener("click", () => {
        if (button.dataset.headerAction === "analyze") handleAnalyze();
        if (button.dataset.headerAction === "open-hub-selector") openHubSelectionModal(getFirstHubStep());
        if (button.dataset.headerAction === "generate-alternatives") handleGenerateAlternatives();
        if (button.dataset.headerAction === "generate-visuals") handleGenerateVisuals();
        if (button.dataset.headerAction === "export-report") exportReport();
        if (button.dataset.headerAction === "toggle-identity-compass") {
          if (projectIdentityCompassOpen) closeProjectIdentityCompass();
          else openProjectIdentityCompass();
        }
        if (button.dataset.headerAction === "edit-project-identity") {
          closeProjectIdentityCompass();
          if (currentProject?.id) {
            void goTo({ view: "project", projectId: currentProject.id, tab: "identity" });
          } else {
            void goTo({ view: "projects" });
          }
        }
        if (button.dataset.headerAction === "open-project-detail") {
          closeProjectIdentityCompass();
          if (currentProject?.id) {
            void goTo({ view: "project", projectId: currentProject.id, tab: "spaces" });
          } else {
            void goTo({ view: "projects" });
          }
        }
        if (button.dataset.headerAction === "open-dashboard") {
          closeProjectIdentityCompass();
          void goTo({ view: "projects" });
        }
        if (button.dataset.headerAction === "go-all-projects") {
          closeProjectIdentityCompass();
          void goTo({ view: "projects" });
        }
        if (button.dataset.headerAction === "go-breadcrumb-project") {
          closeProjectIdentityCompass();
          const projectId = button.dataset.projectId || currentProject?.id || "";
          if (projectId) void goTo({ view: "project", projectId, tab: "identity" });
          else void goTo({ view: "projects" });
        }
      });
    });
    sanitizeStaticUiText(slot);
  });
}

function createHeaderStepActionMarkup(config) {
  const className = `header-step-action ${config.variant === "primary" ? "primary" : "secondary"}`;
  const disabledAttr = config.disabled ? "disabled" : "";
  if (config.mode === "nav") {
    return `<button type="button" class="${className}" data-header-nav-step="${config.step}">${escapeHtml(config.label)}</button>`;
  }
  if (config.mode === "page") {
    return `<button type="button" class="${className}" data-header-nav-page="${escapeHtml(config.page)}">${escapeHtml(config.label)}</button>`;
  }
  return `<button type="button" class="${className}" data-header-action="${config.action}" ${disabledAttr}>${escapeHtml(config.label)}</button>`;
}

function renderHubSelectionModal() {
  if (!ui.hubSelectionOptions) return;
  const activeKeys = getActiveHubKeys();
  ui.hubSelectionOptions.innerHTML = HUB_DEFINITIONS.map((hub) => `
    <label class="hub-selection-option">
      <input type="checkbox" data-hub-selection-option="${escapeHtml(hub.key)}" ${activeKeys.includes(hub.key) ? "checked" : ""} ${REQUIRED_HUB_KEYS.includes(hub.key) ? "checked disabled" : ""}>
      <span>
        <strong>${escapeHtml(hub.label)}</strong>
        <small>Step ${hub.step}${REQUIRED_HUB_KEYS.includes(hub.key) ? " • Zorunlu" : ""}</small>
      </span>
    </label>
  `).join("");
  handleHubSelectionOptionChange();
}

function openHubSelectionModal(targetStep = 0) {
  pendingHubEntryStep = Number(targetStep || 0);
  renderHubSelectionModal();
  ui.hubSelectionModal?.classList.remove("hidden");
  ui.hubSelectionModal?.setAttribute("aria-hidden", "false");
}

function closeHubSelectionModal() {
  pendingHubEntryStep = 0;
  ui.hubSelectionModal?.classList.add("hidden");
  ui.hubSelectionModal?.setAttribute("aria-hidden", "true");
}

function handleHubSelectionOptionChange() {
  if (!ui.confirmHubSelectionButton || !ui.hubSelectionOptions) return;
  const checkedCount = ui.hubSelectionOptions.querySelectorAll("[data-hub-selection-option]:checked").length;
  ui.confirmHubSelectionButton.disabled = checkedCount === 0;
}

async function applyHubSelectionAndContinue() {
  if (!ui.hubSelectionOptions) return;
  const selectedKeys = Array.from(new Set([
    ...REQUIRED_HUB_KEYS,
    ...Array.from(ui.hubSelectionOptions.querySelectorAll("[data-hub-selection-option]:checked"))
      .map((input) => input.dataset.hubSelectionOption)
      .filter(Boolean),
  ]));
  if (!selectedKeys.length) {
    showAlert("Devam etmek icin en az bir hub secmelisiniz.", "warning");
    return;
  }
  appState.hubPreferences = {
    configured: true,
    activeKeys: selectedKeys,
  };
  const requestedHubStep = pendingHubEntryStep && isHubStep(pendingHubEntryStep) ? pendingHubEntryStep : getFirstHubStep();
  const targetStep = getActiveHubSteps().includes(requestedHubStep) ? requestedHubStep : getFirstHubStep();
  closeHubSelectionModal();
  saveState();
  renderTopNav();
  renderHeaderStepActions();
  renderHubPanels();
  renderAllHubOverlays();
  if (isHubStep(targetStep) && hubRequiresSegmentation(getHubDefinitionByStep(targetStep)?.key)) {
    void ensureSegmentationReady({ background: true, reason: "hub-selection" });
  }
  showStep(targetStep, { skipGuard: false });
  showAlert(`${selectedKeys.length} hub aktif edildi. Akis seciminize gore guncellendi.`, "success");
}

function getWorkflowStepState(stepNumber) {
  const hasUploads = !!appState.uploadedRenders.length && !!appState.uploadedPlan;
  const hasAnalysis = !!appState.quantityTakeoff.length;
  const hasPrompt = !!buildUnifiedDesignPrompt().trim();
  const hasAlternatives = !!appState.alternatives.length;
  const hasAlternativeResources = !!(appState.alternativeResourcePool?.materials?.length || appState.alternativeResourcePool?.colorNotes?.length || appState.alternativeResourcePool?.lightingSuggestions?.length);
  const hasReference = !!getSelectedReferenceRender();
  const hasVisuals = Object.keys(appState.generatedVisuals || {}).length > 0;
  const hasReportCandidates = buildReportSourceEntries().length > 0;
  const hasPendingTakeoffApprovals = getPendingTakeoffCostApprovals().length > 0;
  const uploadGateHint = "Ilerlemeden once en az 1 render ve 1 kat plani yukleyin.";
  const takeoffCostGateHint = "Metrajdaki AI maliyet onerilerini veritabanina eklemeden devam edemezsiniz.";

  const hasSegmentation = appState.segmentation && appState.segmentation.status === 'ready';

  const states = {
    1: { locked: false, completed: hasUploads && hasAnalysis, hint: "Projeyi kurup analiz baslatabilirsiniz." },
    2: { locked: !hasUploads || (!hasAnalysis && !appState.loading.analysis), completed: hasAnalysis, hint: !hasUploads ? uploadGateHint : "Step 2'ye gecmek icin once Step 1'de analiz calistirin." },
    3: { locked: !hasUploads || (!hasAnalysis && !appState.loading.analysis) || hasPendingTakeoffApprovals, completed: hasPrompt || hasAlternativeResources, hint: !hasUploads ? uploadGateHint : hasPendingTakeoffApprovals ? takeoffCostGateHint : "Tasarim briefi icin once metraj ve hub kararlarini olusturun." },
    4: { locked: !isHubKeyActive("color") || !hasUploads || !hasAnalysis, completed: hasSegmentation, hint: !isHubKeyActive("color") ? "Bu akista Renk Hub secili degil." : !hasUploads ? uploadGateHint : hasSegmentation ? "Renk hub'inda bolgelere renk kararlari verin." : "Renk hub acilir; bolge bazli araclar segmentasyon tamamlaninca etkinlesir." },
    5: { locked: !isHubKeyActive("material") || !hasUploads || !hasAnalysis, completed: hasSegmentation, hint: !isHubKeyActive("material") ? "Bu akista Malzeme Hub secili degil." : !hasUploads ? uploadGateHint : hasSegmentation ? "Malzeme hub'inda bolgelere malzeme secin." : "Malzeme hub acilir; bolge bazli araclar segmentasyon tamamlaninca etkinlesir." },
    6: { locked: !isHubKeyActive("lighting") || !hasUploads || !hasAnalysis, completed: false, hint: !isHubKeyActive("lighting") ? "Bu akista Aydinlatma Hub secili degil." : !hasUploads ? uploadGateHint : "Aydinlatma hub'inda isik katmanlarini tanimlayin." },
    7: { locked: !isHubKeyActive("plan") || !hasUploads || !hasAnalysis, completed: false, hint: !isHubKeyActive("plan") ? "Bu akista Plan Degerlendirme Hub secili degil." : !hasUploads ? uploadGateHint : "Plan hub'inda yerlesim ve akis kararlarini degerlendirin." },
    8: { locked: !isHubKeyActive("furniture") || !hasUploads || !hasAnalysis, completed: false, hint: !isHubKeyActive("furniture") ? "Bu akista Mobilya Hub secili degil." : !hasUploads ? uploadGateHint : "Mobilya hub'inda oturum ve ergonomi kararlarini degerlendirin." },
    9: { locked: !isHubKeyActive("acoustics") || !hasUploads || !hasAnalysis, completed: false, hint: !isHubKeyActive("acoustics") ? "Bu akista Akustik Hub secili degil." : !hasUploads ? uploadGateHint : "Akustik performansi degerlendir." },
    10: { locked: !hasUploads || hasPendingTakeoffApprovals, completed: hasAlternatives || hasAlternativeResources, hint: !hasUploads ? uploadGateHint : hasPendingTakeoffApprovals ? takeoffCostGateHint : "Alternatif Explorer hazir." },
    11: { locked: !hasUploads || !hasAlternatives || !hasReference || hasPendingTakeoffApprovals, completed: hasVisuals, hint: !hasUploads ? uploadGateHint : hasPendingTakeoffApprovals ? takeoffCostGateHint : !hasAlternatives ? "Render adimindan once alternatif uretin." : "Render adimindan once bir referans render secin." },
    12: { locked: !hasUploads || !hasAnalysis, completed: hasAnalysis && appState.unknownMaterials.length === 0, hint: !hasUploads ? uploadGateHint : "Maliyet veritabanini kullanmak icin once analiz verisi olusmali." },
    13: { locked: !hasUploads || !hasReportCandidates || hasPendingTakeoffApprovals, completed: !!appState.reportData?.refinedPackets?.length, hint: !hasUploads ? uploadGateHint : hasPendingTakeoffApprovals ? takeoffCostGateHint : "Rapor havuzu icin once render uretin veya disardan render ekleyin." },
  };

  return states[stepNumber] || { locked: false, completed: false, hint: "" };
}

function renderProjectSummary() {
  if (!ui.projectSummary) return;
  const stepInfo = STEP_BAND_CONTENT[appState.currentStep] || STEP_BAND_CONTENT[1];
  const projectName = currentProject?.name || "Proje";
  const spaceName = appState.name || "Mahal";
  const selectedPresetIds = appState.identityBindings?.selectedPresetIds || [];
  const selectedPresets = getSelectedProjectPresetsForSpace();
  const aiProfile = getCurrentProjectAiProfile();
  ui.projectSummary.innerHTML = `
    <div class="header-context-card">
      <div>
        <p class="section-kicker">${stepInfo.kicker}</p>
        <strong>${escapeHtml(projectName)} / ${escapeHtml(spaceName)}</strong>
      </div>
      <p>${escapeHtml(stepInfo.copy)}</p>
      <div class="project-card-stats">
        <span class="project-card-stat">${escapeHtml(getGlobalPaletteModeLabel(getGlobalColorPaletteState().mode))}</span>
        <span class="project-card-stat">${escapeHtml(getAiProfileKeyForModels(aiProfile) || "ozel AI profili")}</span>
      </div>
      ${(currentProject?.moodboardPresets || []).length ? `
        <div class="project-summary-preset-row">
          ${(currentProject.moodboardPresets || []).map((preset) => `
            <button type="button" class="ghost-button small-button${selectedPresetIds.includes(preset.id) ? " is-active" : ""}" data-project-summary-preset="${preset.id}">
              ${escapeHtml(preset.name)}
            </button>
          `).join("")}
        </div>
      ` : '<p class="micro-copy">Bu projede henuz preset yok. Proje detayindaki Kimlik sekmesinden ekleyebilirsiniz.</p>'}
      ${selectedPresets.length ? `<p class="micro-copy">Bu mahal su an ${escapeHtml(selectedPresets.map((preset) => preset.name).join(", "))} presetlerini referans aliyor.</p>` : '<p class="micro-copy">Bu mahal henuz proje presetlerinden secim yapmiyor.</p>'}
    </div>
  `;
  sanitizeStaticUiText(ui.projectSummary);
}

function getSelectedProjectPresetsForSpace(state = appState, project = currentProject) {
  const selectedPresetIds = Array.isArray(state?.identityBindings?.selectedPresetIds)
    ? state.identityBindings.selectedPresetIds
    : [];
  const presetPool = Array.isArray(project?.moodboardPresets) ? project.moodboardPresets : [];
  if (!selectedPresetIds.length || !presetPool.length) return [];
  return presetPool.filter((preset) => selectedPresetIds.includes(preset.id));
}

function summarizeProjectPresetForPrompt(preset = {}) {
  const parts = [String(preset.name || "").trim()].filter(Boolean);
  if (preset.description) parts.push(String(preset.description).trim());
  if (Array.isArray(preset.materials) && preset.materials.length) parts.push(`malzemeler: ${preset.materials.slice(0, 4).join(", ")}`);
  if (Array.isArray(preset.colors) && preset.colors.length) parts.push(`renkler: ${preset.colors.slice(0, 4).join(", ")}`);
  if (Array.isArray(preset.keywords) && preset.keywords.length) parts.push(`sifatlar: ${preset.keywords.slice(0, 3).join(", ")}`);
  return parts.join(" | ");
}

function buildProjectIdentityPromptSummary(state = appState, project = currentProject) {
  const segments = [];
  if (String(project?.notes || "").trim()) {
    segments.push(`proje kimligi notu: ${String(project.notes).trim()}`);
  }
  const selectedPresets = getSelectedProjectPresetsForSpace(state, project);
  if (selectedPresets.length) {
    segments.push(`secili proje presetleri: ${selectedPresets.map((preset) => summarizeProjectPresetForPrompt(preset)).join(" || ")}`);
  }
  return segments.join(" ");
}

function buildProjectContextPayload(project = currentProject, space = appState) {
  if (!project?.id) return null;
  const safeProject = createDefaultProjectRecord(project);
  const safeSpace = space || {};
  const selectedPresetIds = Array.isArray(safeSpace?.identityBindings?.selectedPresetIds)
    ? safeSpace.identityBindings.selectedPresetIds
    : [];
  const selectedPresets = getSelectedProjectPresetsForSpace(safeSpace, safeProject).map((preset) => ({
    name: String(preset.name || "").trim(),
    description: String(preset.description || "").trim(),
    materials: Array.isArray(preset.materials) ? preset.materials.filter(Boolean).slice(0, 6) : [],
    colors: Array.isArray(preset.colors) ? preset.colors.filter(Boolean).slice(0, 5) : [],
    keywords: Array.isArray(preset.keywords) ? preset.keywords.filter(Boolean).slice(0, 4) : [],
  }));
  return {
    projectName: String(safeProject.name || "").trim(),
    client: String(safeProject.client || "").trim(),
    notes: String(safeProject.notes || "").trim(),
    globalPalette: {
      mode: String(safeProject.globalPalette?.mode || "off").trim(),
      harmony: String(safeProject.globalPalette?.harmony || "analogous").trim(),
      colors: Array.isArray(safeProject.globalPalette?.colors) ? safeProject.globalPalette.colors.filter(Boolean).slice(0, 6) : [],
    },
    aiProfile: getCurrentProjectAiProfile(safeProject),
    selectedPresetIds,
    selectedPresets,
    spaceName: String(safeSpace?.name || "").trim(),
    designProfile: safeProject.designProfile || null,
  };
}

function buildProjectContextDirective(projectContext = buildProjectContextPayload(), intent = "") {
  if (!projectContext?.projectName && !projectContext?.notes && !projectContext?.selectedPresets?.length && !isDesignProfileConfigured(projectContext?.designProfile)) return "";
  const paletteColors = Array.isArray(projectContext?.globalPalette?.colors) && projectContext.globalPalette.colors.length
    ? projectContext.globalPalette.colors.join(", ")
    : "yok";
  const selectedPresetSummary = Array.isArray(projectContext?.selectedPresets) && projectContext.selectedPresets.length
    ? projectContext.selectedPresets
      .map((preset) => [preset.name, preset.description, preset.materials?.length ? `malzemeler: ${preset.materials.join(", ")}` : "", preset.colors?.length ? `renkler: ${preset.colors.join(", ")}` : "", preset.keywords?.length ? `sifatlar: ${preset.keywords.join(", ")}` : ""].filter(Boolean).join(" | "))
      .join(" || ")
    : "yok";
  const profileSummary = summarizeDesignProfileForPrompt(projectContext?.designProfile);
  const lines = [
    `[UST PROJE BAGLAMI: Bu mekan "${projectContext.projectName || "Adsiz Proje"}" projesi altindadir.`,
    `Mahal: "${projectContext.spaceName || "Adsiz Mahal"}".`,
    `Musteri / aidiyet: "${projectContext.client || "belirtilmedi"}".`,
    `Kimlik notu: "${projectContext.notes || "yok"}".`,
    `Global palet modu: "${projectContext.globalPalette?.mode || "off"}".`,
    `Global palet renkleri: "${paletteColors}".`,
    `Secili proje presetleri: "${selectedPresetSummary}".`,
  ];
  if (profileSummary) {
    lines.push(`TASARIM PROFILI (ANAYASA): ${profileSummary}`);
    lines.push(`Onerilerini bu profilin sinirlari icinde tut. Profille celisen kararlari acikca isaretle.`);
  }
  lines.push(`${intent ? `${intent} sirasinda` : "Analiz ve uretim kararlarinda"} bu baglami anayasa gibi temel al.]`);
  return lines.join(" ");
}

function getProjectIdentityCompassData() {
  const payload = buildProjectContextPayload();
  if (!payload) return null;
  const profile = payload.designProfile;
  const profileLabel = isDesignProfileConfigured(profile)
    ? (getDesignProfileTemplateLabel(profile.templateId) || profile.sector || "Ozel Profil")
    : "";
  return {
    ...payload,
    paletteModeLabel: getGlobalPaletteModeLabel(payload.globalPalette?.mode),
    aiProfileLabel: getAiProfileKeyForModels(payload.aiProfile) || "ozel AI profili",
    designProfileLabel: profileLabel,
    designProfileConfigured: isDesignProfileConfigured(profile),
  };
}

function resetWorkflowAfterUploadChange() {
  const initialState = createInitialState();
  appState.analysisSummary = null;
  appState.segmentation = { ...initialState.segmentation };
  appState.decisionLog = [];
  appState.designBrief = { ...initialState.designBrief };
  appState.colorTool = normalizeColorToolState(initialState.colorTool);
  appState.quantityTakeoff = [];
  appState.scopeSelections = { ...initialState.scopeSelections };
  appState.designPrompt = "";
  appState.promptSelections = { ...initialState.promptSelections };
  appState.promptSelectionSource = {};
  appState.promptOptionExpansion = { ...initialState.promptOptionExpansion };
  appState.promptBuilder = { ...initialState.promptBuilder };
  appState.alternatives = [];
  appState.unknownMaterials = [];
  appState.generatedVisuals = {};
  appState.materialAtlas = { ...initialState.materialAtlas };
  resetReportSelectionState({ clearApprovals: true });
}

function refreshWorkflowAfterUploadChange() {
  renderProjectSummary();
  renderUploadedFiles();
  renderAnalysisSummary();
  renderQuantityTable();
  renderPromptBuilder();
  renderReferencePanel();
  renderAlternatives();
  renderVisualPanels();
  renderReport();
  syncAllHubImages();
  renderHubPanels();
  renderAllHubOverlays();
  renderTopNav();
}

function resetWorkflowKeepingUploads() {
  const initialState = createInitialState();
  const preservedRenders = deepClone(appState.uploadedRenders || []);
  const preservedPlan = appState.uploadedPlan ? deepClone(appState.uploadedPlan) : null;
  const preservedApiSettings = { ...initialState.apiSettings, ...(appState.apiSettings || {}) };
  const preservedCostDatabase = Array.isArray(appState.costDatabase) && appState.costDatabase.length
    ? deepClone(appState.costDatabase)
    : deepClone(initialState.costDatabase);
  const preservedGlobalColorPalette = deepClone(getGlobalColorPaletteState());
  const preservedMoodboardPresets = deepClone(appState.moodboardPresets || []);
  const selectedReferenceRenderId = preservedRenders.some((file) => file.id === appState.selectedReferenceRenderId)
    ? appState.selectedReferenceRenderId
    : (preservedRenders[0]?.id || "");

  appState = {
    ...initialState,
    uploadedRenders: preservedRenders,
    uploadedPlan: preservedPlan,
    selectedReferenceRenderId,
    apiSettings: preservedApiSettings,
    costDatabase: preservedCostDatabase,
    globalColorPalette: preservedGlobalColorPalette,
    moodboardPresets: preservedMoodboardPresets,
  };
}

function resetWorkflowKeepingTakeoffAndSegmentation() {
  const initialState = createInitialState();
  const preservedRenders = deepClone(appState.uploadedRenders || []);
  const preservedPlan = appState.uploadedPlan ? deepClone(appState.uploadedPlan) : null;
  const preservedApiSettings = { ...initialState.apiSettings, ...(appState.apiSettings || {}) };
  const preservedCostDatabase = Array.isArray(appState.costDatabase) && appState.costDatabase.length
    ? deepClone(appState.costDatabase)
    : deepClone(initialState.costDatabase);
  const preservedGlobalColorPalette = deepClone(getGlobalColorPaletteState());
  const preservedMoodboardPresets = deepClone(appState.moodboardPresets || []);
  const preservedAnalysisSummary = appState.analysisSummary ? deepClone(appState.analysisSummary) : null;
  const preservedQuantityTakeoff = deepClone(appState.quantityTakeoff || []);
  const preservedScopeSelections = { ...initialState.scopeSelections, ...(appState.scopeSelections || {}) };
  const preservedSegmentation = { ...initialState.segmentation, ...(deepClone(appState.segmentation || {})) };
  const preservedHubPreferences = normalizeHubPreferences(appState.hubPreferences, appState.currentStep);
  const selectedReferenceRenderId = preservedRenders.some((file) => file.id === appState.selectedReferenceRenderId)
    ? appState.selectedReferenceRenderId
    : (preservedRenders[0]?.id || "");

  appState = {
    ...initialState,
    uploadedRenders: preservedRenders,
    uploadedPlan: preservedPlan,
    selectedReferenceRenderId,
    apiSettings: preservedApiSettings,
    costDatabase: preservedCostDatabase,
    globalColorPalette: preservedGlobalColorPalette,
    moodboardPresets: preservedMoodboardPresets,
    analysisSummary: preservedAnalysisSummary,
    quantityTakeoff: preservedQuantityTakeoff,
    scopeSelections: preservedScopeSelections,
    segmentation: preservedSegmentation,
    hubPreferences: preservedHubPreferences,
  };
}

function invalidateSegmentation(reason = "Metraj guncellendi. Segmentasyon yeniden hazirlanacak.") {
  appState.segmentation = { ...createInitialState().segmentation };
  appState.decisionLog = [];
  appState.colorTool = normalizeColorToolState(createInitialState().colorTool);
  saveState();
  renderAllHubOverlays();
  renderTopNav();
  if (reason) showAlert(reason, "info");
}

function handleRestartWorkflowFromSetup() {
  if (!appState.uploadedRenders.length && !appState.uploadedPlan) {
    showAlert("Yuklu dosya olmadigi icin sifirlanacak bir surec bulunamadi.", "info");
    return;
  }
  resetWorkflowKeepingUploads();
  saveState();
  showStep(1, { skipGuard: true });
  refreshWorkflowAfterUploadChange();
  renderHeaderStepActions();
  showAlert("Yuklu gorseller korunarak surec sifirdan baslatildi.", "success");
}

function handleRestartAfterMaterialId() {
  if (!appState.uploadedRenders.length && !appState.uploadedPlan) {
    showAlert("Yuklu dosya olmadigi icin test akisi sifirlanamadi.", "info");
    return;
  }
  if (!appState.quantityTakeoff.length) {
    showAlert("Bu akis icin mevcut metraj korunmali. Once analiz veya metraj adimini tamamlayin.", "warning");
    return;
  }
  if (appState.segmentation?.status !== "ready" || !(appState.segmentation?.regions || []).length) {
    showAlert("Bu akis icin mevcut Material-ID/segmentasyon gerekli. Once segmentasyonu hazirlayin.", "warning");
    return;
  }
  resetWorkflowKeepingTakeoffAndSegmentation();
  resetHubSelectionUi();
  saveState();
  showStep(4, { skipGuard: true });
  refreshWorkflowAfterUploadChange();
  renderHeaderStepActions();
  renderAllHubOverlays();
  showAlert("Mevcut Material-ID korunarak Renk Hub temiz baslangic modunda acildi.", "success");
}

function renderHeaderReferencePreview() {
  if (!ui.headerReferencePreview) return;
  const referenceRender = getSelectedReferenceRender();
  if (!referenceRender) {
    ui.headerReferencePreview.classList.add("is-empty");
    ui.headerReferencePreview.innerHTML = `
      <span class="header-reference-chip">Referans</span>
    `;
    sanitizeStaticUiText(ui.headerReferencePreview);
    return;
  }

  ui.headerReferencePreview.classList.remove("is-empty");
  ui.headerReferencePreview.innerHTML = `
    <span class="header-reference-chip">Referans</span>
    <img src="${referenceRender.preview}" alt="${escapeHtml(referenceRender.name)}">
  `;
  sanitizeStaticUiText(ui.headerReferencePreview);
}

function renderUploadedFiles() {
  appState.preserveGeometry = true;
  renderHeaderReferencePreview();
  ui.renderPreviewList.innerHTML = appState.uploadedRenders.length
    ? appState.uploadedRenders.map((file) => previewCardMarkup(file, "render")).join("")
    : emptyStateMarkup("HenÃ¼z render yÃ¼klenmedi.", "Step 1 iÃ§inde en az bir perspektif gÃ¶rsel yÃ¼kleyin.");
  ui.planPreviewList.innerHTML = appState.uploadedPlan
    ? previewCardMarkup(appState.uploadedPlan, "plan")
    : emptyStateMarkup("Kat planÄ± bekleniyor.", "PDF veya gÃ¶rsel bir plan dosyasÄ± ekleyin.");
  renderDebugPanels();
  sanitizeStaticUiText(ui.renderPreviewList.parentElement);
}

function previewCardMarkup(file, type) {
  const isReference = type === "render" && file.id === appState.selectedReferenceRenderId;
  return `
    <article class="preview-card ${isReference ? "is-reference" : ""}">
      <img class="preview-thumb" src="${file.preview}" alt="${file.name}">
      <div class="preview-body">
        <div class="preview-title-row">
          <h4 class="preview-title">${escapeHtml(file.name)}</h4>
          <button type="button" class="text-button" data-remove-upload="${file.id}" data-upload-type="${type}">Sil</button>
        </div>
        <div class="status-inline">
          <span class="badge neutral">${file.typeLabel}</span>
          <span class="badge info">${escapeHtml(file.mimeType || "image/*")}</span>
          ${file.optimized ? '<span class="badge warning">Optimize Edildi</span>' : ""}
          ${isReference ? '<span class="badge success">Referans Render</span>' : ""}
        </div>
        ${file.optimized ? `<p class="micro-copy">Yukleme sirasinda ${file.originalWidth || "?"}x${file.originalHeight || "?"} boyutundan ${file.width || "?"}x${file.height || "?"} boyutuna dusuruldu.</p>` : ""}
        ${type === "render" ? `<button type="button" class="ghost-button small-button" data-select-reference-render="${file.id}">${isReference ? "Secili Referans" : "Bunu Referans Al"}</button>` : ""}
      </div>
    </article>
  `;
}

// ── Collapsible Metraj Panel (Kurulum page) ──

function toggleMetrajPanel(forceOpen) {
  const panel = document.getElementById("kurulum-metraj-panel");
  if (!panel) return;
  const shouldOpen = typeof forceOpen === "boolean" ? forceOpen : panel.dataset.collapsed === "true";
  panel.dataset.collapsed = shouldOpen ? "false" : "true";
  appState.metrajPanelOpen = shouldOpen;
  const body = panel.querySelector(".collapsible-body");
  if (body) {
    if (shouldOpen) {
      body.style.maxHeight = body.scrollHeight + "px";
      setTimeout(() => { body.style.maxHeight = "none"; }, 320);
    } else {
      body.style.maxHeight = body.scrollHeight + "px";
      requestAnimationFrame(() => { body.style.maxHeight = "0"; });
    }
  }
  const arrow = panel.querySelector(".collapsible-arrow");
  if (arrow) arrow.style.transform = shouldOpen ? "rotate(90deg)" : "rotate(0deg)";
}

// ── Analiz Page Renderer ──

function renderAnalizPage() {
  renderAnalysisSummary();
  renderAnalizHubNav();
  renderAnalizHubContent();
}

function getMetricColor(score, isPercent = false) {
  const s = isPercent ? score / 10 : score;
  return s >= 8 ? "var(--green, #1e8e5c)" : s >= 6 ? "var(--amber, #c97918)" : "var(--red, #b53a2d)";
}

function toNumericScore(value, fallback = 0) {
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : fallback;
}

function pickCritiqueMetric(skorlar, keys, label) {
  for (const key of keys) {
    const entry = skorlar?.[key];
    if (entry && Number.isFinite(Number(entry.puan))) {
      return {
        label,
        value: Number(entry.puan),
      };
    }
  }
  return {
    label,
    value: 0,
  };
}

function buildLegacyEvalCategories(critique = {}) {
  const skorlar = critique.skorlar || {};
  const groups = [
    {
      label: "Islev & Kullanim",
      color: "#2667ff",
      metrics: [
        pickCritiqueMetric(skorlar, ["mekansalOrganizasyon", "planCozumu", "sirkulasyon"], "Mekansal Organizasyon"),
        pickCritiqueMetric(skorlar, ["ergonomiEsneklik", "ergonomi", "esneklik"], "Ergonomi"),
      ],
    },
    {
      label: "Atmosfer & Duyular",
      color: "#c97918",
      metrics: [
        pickCritiqueMetric(skorlar, ["isikPerformansi", "isikKalitesi"], "Isik Performansi"),
        pickCritiqueMetric(skorlar, ["malzemeDoku", "malzemeUyumu"], "Malzeme & Doku"),
      ],
    },
    {
      label: "Estetik & Kompozisyon",
      color: "#1e8e5c",
      metrics: [
        pickCritiqueMetric(skorlar, ["gorselKompozisyon", "oranOranti", "odakNoktasi"], "Gorsel Kompozisyon"),
        pickCritiqueMetric(skorlar, ["konseptUyumu", "butunselEtki"], "Konsept Uyumu"),
      ],
    },
    {
      label: "Gercekcilik & Maliyet",
      color: "#7a4ce0",
      metrics: [
        pickCritiqueMetric(skorlar, ["uretilebilirlik"], "Uretilebilirlik"),
        pickCritiqueMetric(skorlar, ["butceVerimliligi"], "Butce Verimliligi"),
      ],
    },
  ];
  return groups.map((group) => {
    const validScores = group.metrics.map((metric) => metric.value).filter((value) => value > 0);
    const score = validScores.length
      ? (validScores.reduce((sum, value) => sum + value, 0) / validScores.length).toFixed(1)
      : "—";
    return {
      label: group.label,
      color: group.color,
      score,
      metrics: group.metrics,
    };
  });
}

function renderAnalizEvalSummary() {
  const container = document.getElementById("analiz-eval-summary");
  if (!container) return;
  const summary = appState.analysisSummary;
  if (!summary) {
    container.innerHTML = `
      <div class="collapsible-toggle" id="analiz-eval-toggle">
        <span>Tasarim Degerlendirmesi</span>
        <span class="collapsible-arrow" style="transform:rotate(90deg)">&#9654;</span>
      </div>
      <div class="collapsible-body" style="max-height:none">
        <div class="analiz-eval-empty"><p>Henuz analiz yapilmadi. Kurulum sayfasindan analiz baslatin.</p></div>
      </div>
    `;
    return;
  }

  const critique = summary.designCritique || {};
  const categories = Array.isArray(critique.categories) && critique.categories.length
    ? critique.categories
    : buildLegacyEvalCategories(critique);
  const strengths = Array.isArray(critique.strengths)
    ? critique.strengths
    : (Array.isArray(critique.gucluYonler) ? critique.gucluYonler : []);
  const improvements = Array.isArray(critique.improvements)
    ? critique.improvements
    : (Array.isArray(critique.zayifYonler) ? critique.zayifYonler : []);
  const computedOverallScore = (() => {
    const categoryScores = categories
      .map((category) => toNumericScore(category.score, NaN))
      .filter((value) => Number.isFinite(value) && value > 0);
    if (categoryScores.length) {
      return (categoryScores.reduce((sum, value) => sum + value, 0) / categoryScores.length).toFixed(1);
    }
    return "—";
  })();
  const overallScore = critique.overallScore ?? critique.genelSkor ?? computedOverallScore;
  const critiqueSummary = critique.summary || critique.genelDegerlendirme || "";
  const confidence = calculateConfidenceMetrics();
  const confidenceLevels = summary.confidenceLevels || {
    Metraj: confidence.takeoff,
    Maliyet: confidence.cost,
    Gorsel: confidence.visual,
  };

  container.innerHTML = `
    <button type="button" class="collapsible-toggle" id="analiz-eval-toggle">
      <div>
        <h3>Tasarim Degerlendirmesi</h3>
        <p class="section-copy">Yuklenen renderlar uzerinden mimari kritik ve mekan analizi.</p>
      </div>
      <div style="display:flex;align-items:center;gap:8px">
        ${Object.entries(confidenceLevels).map(([key, val]) => `<span class="badge ${val === "Yuksek" ? "success" : val === "Dusuk" ? "warning" : "info"}">${escapeHtml(key)} ${escapeHtml(val)}</span>`).join("")}
        <span class="collapsible-arrow" style="transform:rotate(90deg)">&#9654;</span>
      </div>
    </button>
    <div class="collapsible-body" style="max-height:none">
      <div class="analiz-eval-grid">
        <div class="analiz-eval-score-panel">
          <div class="analiz-eval-score-badge">
            <span class="badge info">AI Kritik</span>
          </div>
          <div class="analiz-eval-score-number">
            <strong>${escapeHtml(String(overallScore))}</strong><span>/10</span>
          </div>
          <p class="analiz-eval-score-copy">${escapeHtml(critiqueSummary)}</p>
        </div>
        <div class="analiz-eval-findings">
          <div class="analiz-eval-section">
            <h4 class="analiz-eval-section-title">Guclu Yonler</h4>
            <ul>${strengths.map((s) => `<li>${escapeHtml(s)}</li>`).join("")}</ul>
          </div>
          <div class="analiz-eval-section">
            <h4 class="analiz-eval-section-title analiz-eval-section-title--warn">Gelistirilmesi Gerekenler</h4>
            <ul>${improvements.map((s) => `<li>${escapeHtml(s)}</li>`).join("")}</ul>
          </div>
        </div>
      </div>
      ${categories.length ? `
        <div class="analiz-eval-categories">
          ${categories.map((cat) => `
            <div class="analiz-eval-category-card">
              <div class="analiz-eval-category-head">
                <span class="analiz-eval-category-icon" style="background:${escapeHtml(cat.color || "#2667ff")}"></span>
                <strong>${escapeHtml(cat.label || "")}</strong>
                <span class="analiz-eval-category-score">${escapeHtml(String(cat.score ?? "—"))}</span>
              </div>
              ${Array.isArray(cat.metrics) ? cat.metrics.map((m) => `
                <div class="analiz-eval-metric">
                  <span>${escapeHtml(m.label || "")}</span>
                  <span>${escapeHtml(String(m.value ?? ""))}/10</span>
                </div>
              `).join("") : ""}
            </div>
          `).join("")}
        </div>
      ` : ""}
    </div>
  `;

  // Collapsible toggle
  const toggle = container.querySelector("#analiz-eval-toggle");
  if (toggle) {
    toggle.addEventListener("click", () => {
      const body = container.querySelector(".collapsible-body");
      const arrow = container.querySelector(".collapsible-arrow");
      const isOpen = body.style.maxHeight !== "0px" && body.style.maxHeight !== "0";
      if (isOpen) {
        body.style.maxHeight = body.scrollHeight + "px";
        requestAnimationFrame(() => { body.style.maxHeight = "0"; });
        if (arrow) arrow.style.transform = "rotate(0deg)";
      } else {
        body.style.maxHeight = body.scrollHeight + "px";
        setTimeout(() => { body.style.maxHeight = "none"; }, 320);
        if (arrow) arrow.style.transform = "rotate(90deg)";
      }
    });
  }
}

function renderAnalizHubNav() {
  const container = document.getElementById("analiz-hub-nav");
  if (!container) return;
  const questProgress = getRequiredHubPoolProgress();
  const visibleKeys = new Set(getVisibleHubDefinitions().map((hub) => hub.key));
  const renderHubButton = (hub) => {
    const isActive = appState.activeAnalizHub === hub.key;
    const cachedEval = appState.hubEvaluations?.[hub.key];
    const hasResult = !!cachedEval;
    const score = cachedEval?.score;
    const quest = questProgress[hub.key] || null;
    return `
      <button type="button"
        class="analiz-hub-pill ${isActive ? "is-active" : ""} ${hasResult ? "has-result" : ""} ${quest ? "is-mandatory" : ""} ${quest?.complete ? "is-complete" : ""}"
        data-hub-key="${hub.key}">
        <span>${escapeHtml(hub.navLabel)}</span>
        ${quest ? `<span class="analiz-hub-pill-meta">${quest.complete ? "Tamam" : `${quest.count}/${quest.target}`}</span>` : ""}
        ${score != null ? `<span class="analiz-hub-pill-score">${escapeHtml(String(score))}</span>` : ""}
      </button>
    `;
  };
  const activeKeys = getActiveHubKeys();
  const uretimHubs = activeKeys.map(k => HUB_BY_KEY[k]).filter(h => h && HUB_GROUPS.production.steps.includes(h.step));
  const degerlendirmeHubs = activeKeys.map(k => HUB_BY_KEY[k]).filter(h => h && HUB_GROUPS.evaluation.steps.includes(h.step));

  container.innerHTML = `
    <div class="analiz-hub-pill-row-group">
      <div class="analiz-hub-pill-row" style="display:flex; align-items:center; gap:16px; flex-wrap:wrap; justify-content:center;">
        ${uretimHubs.length ? `
        <div style="display:flex; align-items:center; gap:8px;">
          <span style="font-size:12px; font-weight:600; color:var(--muted); text-transform:uppercase; letter-spacing:0.04em;">Yuzeyler:</span>
          ${uretimHubs.map((hub) => renderHubButton(hub)).join("")}
        </div>` : ''}
        ${degerlendirmeHubs.length ? `
        <div style="display:flex; align-items:center; gap:8px;">
          <span style="font-size:12px; font-weight:600; color:var(--muted); text-transform:uppercase; letter-spacing:0.04em; margin-left:8px;">Degerlendirme:</span>
          ${degerlendirmeHubs.map((hub) => renderHubButton(hub)).join("")}
        </div>` : ''}
      </div>
    </div>
  `;

  container.querySelectorAll("[data-hub-key]").forEach((btn) => {
    btn.addEventListener("click", () => {
      const hubKey = btn.dataset.hubKey;
      const hub = HUB_BY_KEY[hubKey];
      if (!hub) return;
      appState.activeAnalizHub = hubKey;
      // Lazy AI: trigger evaluation only on click
      if (!appState.hubEvaluations?.[hubKey]) {
        triggerHubEvaluation(hubKey);
      }
      // Keep guard path active so hub-specific prerequisites (e.g. segmentation) can auto-trigger.
      showStep(hub.step, { skipGuard: false });
    });
  });
}

function renderAnalizHubContent() {
  if (!ui.unifiedHubShell) return;
  const hubKey = appState.activeAnalizHub;
  const parent = ui.unifiedHubShell.parentElement;
  
  if (!hubKey) {
    ui.unifiedHubShell.style.display = "none";
    let onboarding = parent.querySelector(".hub-onboarding-card");
    if (!onboarding) {
      onboarding = document.createElement("div");
      onboarding.className = "hub-onboarding-card empty-state summary-card";
      onboarding.innerHTML = `<p style="margin:0;font-size:14px;color:var(--text);">Yukariya tiklayarak hub araclarini acin.</p>`;
      parent.appendChild(onboarding);
    }
    onboarding.style.display = "block";
    resetHubDomBindings();
    return;
  }
  
  const onboarding = parent.querySelector(".hub-onboarding-card");
  if (onboarding) onboarding.style.display = "none";

  ui.unifiedHubShell.style.display = "";
  updateUnifiedHubFrame(hubKey);
  renderHubPanelForKey(hubKey);
  renderUnifiedHubSelectionInfo();
  renderUnifiedHubOverlay();
}

function toggleCritiquePanel() {
  const panel = document.getElementById("critique-collapsible-panel");
  if (!panel) return;
  const isCollapsed = panel.dataset.collapsed === "true";
  const body = panel.querySelector(".collapsible-body");
  const arrow = panel.querySelector(".collapsible-arrow");
  if (isCollapsed) {
    panel.dataset.collapsed = "false";
    body.style.maxHeight = body.scrollHeight + "px";
    setTimeout(() => { if (panel.dataset.collapsed === "false") body.style.maxHeight = "none"; }, 320);
    if (arrow) arrow.style.transform = "rotate(90deg)";
  } else {
    panel.dataset.collapsed = "true";
    body.style.maxHeight = body.scrollHeight + "px";
    void body.offsetHeight; // force reflow
    body.style.maxHeight = "0";
    if (arrow) arrow.style.transform = "rotate(0deg)";
  }
}

function renderAnalysisSummary() {
  if (appState.loading.analysis) {
    ui.analysisSummary.classList.remove("decision-mode");
    if (ui.analysisConfidenceStrip) ui.analysisConfidenceStrip.innerHTML = "";
    ui.analysisSummary.innerHTML = renderSkeletonGrid(4, "AI plani okuyor ve tasarim degerlendirmesi hazirlaniyor...");
    renderDebugPanels();
    return;
  }
  const summary = appState.analysisSummary;
  if (!summary) {
    ui.analysisSummary.classList.remove("decision-mode");
    if (ui.analysisConfidenceStrip) ui.analysisConfidenceStrip.innerHTML = "";
    ui.analysisSummary.innerHTML = emptyStateMarkup("Degerlendirme henuz uretilmedi.", "Step 1 uzerinden render ve plan yukleyip Analiz Et butonuna basin.");
    renderDebugPanels();
    return;
  }
  const pendingTakeoffApprovals = getPendingTakeoffCostApprovals().length;
  if (pendingTakeoffApprovals > 0) {
    ui.analysisSummary.classList.remove("decision-mode");
    if (ui.analysisConfidenceStrip) ui.analysisConfidenceStrip.innerHTML = "";
    ui.analysisSummary.innerHTML = emptyStateMarkup(
      "Tasarim degerlendirmesi hazir ama simdilik gizli.",
      pendingTakeoffApprovals === 1
        ? "Metrajdaki son AI maliyet onerisi sisteme eklendiginde bu bolum otomatik acilacak. AI hesabi tamamlandi; sonuc, tum kalemler sisteme alinana kadar saklaniyor."
        : `${pendingTakeoffApprovals} kalem daha sisteme eklenmeli. AI hesabi tamamlandi; tasarim degerlendirmesi tum kalemler sisteme alindiginda otomatik gosterilecek.`
    );
    renderDebugPanels();
    sanitizeStaticUiText(ui.analysisSummary);
    return;
  }
  const confidence = calculateConfidenceMetrics();
  const takeoffConfidence = getConfidenceProfile(confidence.takeoff);
  const costConfidence = getConfidenceProfile(confidence.cost);
  const visualConfidence = getConfidenceProfile(confidence.visual);
  ui.analysisSummary.classList.add("decision-mode");
  if (ui.analysisConfidenceStrip) {
    ui.analysisConfidenceStrip.innerHTML = `
      <span class="analysis-confidence-label">Guven Seviyeleri</span>
      <div class="status-inline">
        <span class="badge ${takeoffConfidence.badge}">Metraj ${takeoffConfidence.label}</span>
        <span class="badge ${costConfidence.badge}">Maliyet ${costConfidence.label}</span>
        <span class="badge ${visualConfidence.badge}">Gorsel ${visualConfidence.label}</span>
      </div>
    `;
  }
  renderDebugPanels();
  const critique = summary.designCritique;
  // Migrate old 10-criteria keys to new 8-criteria grouped keys
  if (critique && critique.skorlar) {
    const s = critique.skorlar;
    const isLegacyPlaceholderComment = (text) => /eski analiz formatinda|varsayilan deger atandi/i.test(String(text || ""));
    if (s.planCozumu && !s.mekansalOrganizasyon) {
      const avg = (a, b) => ({ puan: Math.round(((a?.puan || 0) + (b?.puan || 0)) / 2), yorum: [a?.yorum, b?.yorum].filter(Boolean).join(" ") });
      s.mekansalOrganizasyon = avg(s.planCozumu, s.sirkulasyon);
      if (s.esikDeneyimi && s.mekansalOrganizasyon) {
        s.mekansalOrganizasyon.yorum = [s.mekansalOrganizasyon.yorum, s.esikDeneyimi?.yorum].filter(Boolean).join(" ");
      }
      s.ergonomiEsneklik = avg(s.ergonomi, s.esneklik);
      s.isikPerformansi = s.isikKalitesi || { puan: 0, yorum: "" };
      s.malzemeDoku = s.malzemeUyumu || { puan: 0, yorum: "" };
      s.gorselKompozisyon = avg(s.oranOranti, s.odakNoktasi);
      s.konseptUyumu = s.butunselEtki || { puan: 0, yorum: "" };
      // Clean up old keys
      delete s.planCozumu; delete s.sirkulasyon; delete s.esikDeneyimi;
      delete s.isikKalitesi; delete s.malzemeUyumu; delete s.oranOranti;
      delete s.odakNoktasi; delete s.ergonomi; delete s.esneklik; delete s.butunselEtki;
    }
    // Derive or refresh feasibility comments from current grouped signals
    if (!s.uretilebilirlik || isLegacyPlaceholderComment(s.uretilebilirlik?.yorum)) {
      const matPuan = s.malzemeDoku?.puan || 6;
      const orgPuan = s.mekansalOrganizasyon?.puan || 6;
      const derivedPuan = Math.min(10, Math.round((matPuan + orgPuan) / 2 + 1));
      const malYorum = String(s.malzemeDoku?.yorum || "").toLowerCase();
      const hasComplexHint = malYorum.includes("karmasik") || malYorum.includes("ozel");
      s.uretilebilirlik = {
        puan: hasComplexHint ? Math.max(4, derivedPuan - 2) : derivedPuan,
        yorum: hasComplexHint
          ? "Cozum ozel detay ve koordinasyon gerektiriyor. Standart uygulama akisi korunabilir ancak kritik birlesimlerin shop drawing ile netlestirilmesi gerekir."
          : "Secilen sistemler standart uygulama mantigina yakin gorunuyor. Uretim ve montaj tarafinda buyuk bir risk beklenmez, ancak detay birlesimleri sahada dogrulanmalidir.",
      };
    }
    if (!s.butceVerimliligi || isLegacyPlaceholderComment(s.butceVerimliligi?.yorum)) {
      const allPuans = [s.mekansalOrganizasyon, s.ergonomiEsneklik, s.isikPerformansi, s.malzemeDoku, s.gorselKompozisyon, s.konseptUyumu].map((c) => c?.puan || 0);
      const avgScore = allPuans.reduce((a, b) => a + b, 0) / Math.max(1, allPuans.length);
      const derivedPuan = Math.round(Math.min(10, Math.max(3, avgScore - 0.5)));
      s.butceVerimliligi = {
        puan: derivedPuan,
        yorum: avgScore >= 7
          ? "Tasarim etkisi ile kaynak kullanimi arasinda olumlu bir denge var. Maliyet artisi, elde edilen mekansal kaliteyi destekliyor."
          : avgScore >= 5
            ? "Butce genel olarak dengeli kullaniliyor ancak etkiyi daha odakli alanlara toplamak verimliligi artirabilir."
            : "Maliyet etkisi tasarim kalitesine gore zayif kaliyor. Butcenin daha belirgin mekansal etki yaratan kalemlere yonlendirilmesi gerekir.",
      };
    }
  }
  const changeableItems = (summary.changeableItems || []).map(formatAnalysisListItem).filter(Boolean);
  const detectedSurfaces = (summary.detectedSurfaces || []).map(formatAnalysisListItem).filter(Boolean);
  const decisionPanel = buildAnalysisDecisionPanel(summary, changeableItems, detectedSurfaces);
  const verificationItems = deriveCompactVerificationItems(summary, appState.quantityTakeoff);
  const opportunityItems = decisionPanel.quickWins.slice(0, 3);
  if (critique && critique.skorlar) {
    const critiqueGroups = [
      {
        key: "islev",
        title: "Islev & Kullanim",
        subtitle: "The Logic",
        color: "#2667ff",
        icon: "&#9632;",
        criteria: [
          { key: "mekansalOrganizasyon", label: "Mekansal Organizasyon & Akis" },
          { key: "ergonomiEsneklik", label: "Ergonomi & Esneklik" },
        ],
      },
      {
        key: "atmosfer",
        title: "Atmosfer & Duyular",
        subtitle: "The Feel",
        color: "#c97918",
        icon: "&#9650;",
        criteria: [
          { key: "isikPerformansi", label: "Isik Performansi" },
          { key: "malzemeDoku", label: "Malzeme & Doku Uyumu" },
        ],
      },
      {
        key: "estetik",
        title: "Estetik & Kompozisyon",
        subtitle: "The Look",
        color: "#1e8e5c",
        icon: "&#9679;",
        criteria: [
          { key: "gorselKompozisyon", label: "Gorsel Kompozisyon & Hiyerarsi" },
          { key: "konseptUyumu", label: "Konsept & Baglam Uyumu" },
        ],
      },
      {
        key: "fizibilite",
        title: "Gerceklik & Maliyet",
        subtitle: "The Feasibility",
        color: "#69717b",
        icon: "&#9670;",
        criteria: [
          { key: "uretilebilirlik", label: "Uretilebilirlik" },
          { key: "butceVerimliligi", label: "Butce Verimliligi" },
        ],
      },
    ];

    // Calculate scores
    const allScores = critiqueGroups.flatMap((g) => g.criteria.map((c) => critique.skorlar[c.key]?.puan || 0));
    const avgScore = allScores.length ? (allScores.reduce((a, b) => a + b, 0) / allScores.length).toFixed(1) : "—";
    const avgNum = parseFloat(avgScore) || 0;
    const healthColor = getMetricColor(avgNum);

    // Build SVG radar chart
    const radarSize = 280;
    const radarCenter = radarSize / 2;
    const radarRadius = 110;
    const radarKeys = critiqueGroups.flatMap((g) => g.criteria.map((c) => ({ key: c.key, label: c.label, color: g.color })));
    const radarPointCount = radarKeys.length;
    const radarAngleStep = (2 * Math.PI) / radarPointCount;
    const radarStartAngle = -Math.PI / 2;

    function polarToXY(index, value) {
      const angle = radarStartAngle + index * radarAngleStep;
      const r = (value / 10) * radarRadius;
      return { x: radarCenter + r * Math.cos(angle), y: radarCenter + r * Math.sin(angle) };
    }

    // Grid rings
    const gridRings = [2, 4, 6, 8, 10].map((level) => {
      const r = (level / 10) * radarRadius;
      return `<circle cx="${radarCenter}" cy="${radarCenter}" r="${r}" fill="none" stroke="rgba(18,20,22,0.08)" stroke-width="1"/>`;
    }).join("");

    // Grid spokes + labels
    const spokes = radarKeys.map((rk, i) => {
      const ep = polarToXY(i, 10);
      const lp = polarToXY(i, 12.2);
      const puan = critique.skorlar[rk.key]?.puan || 0;
      const textAnchor = lp.x < radarCenter - 10 ? "end" : lp.x > radarCenter + 10 ? "start" : "middle";
      const shortLabel = rk.label.length > 18 ? rk.label.slice(0, 16) + "..." : rk.label;
      return `
        <line x1="${radarCenter}" y1="${radarCenter}" x2="${ep.x}" y2="${ep.y}" stroke="rgba(18,20,22,0.06)" stroke-width="1"/>
        <text x="${lp.x}" y="${lp.y}" text-anchor="${textAnchor}" dominant-baseline="central" font-size="9" font-weight="600" fill="${rk.color}" font-family="Segoe UI, Arial, sans-serif">${escapeHtml(shortLabel)}</text>
        <text x="${lp.x}" y="${lp.y + 12}" text-anchor="${textAnchor}" dominant-baseline="central" font-size="10" font-weight="800" fill="${rk.color}" font-family="Segoe UI, Arial, sans-serif">${puan}</text>
      `;
    }).join("");

    // Data polygon
    const dataPoints = radarKeys.map((rk, i) => {
      const puan = critique.skorlar[rk.key]?.puan || 0;
      const p = polarToXY(i, puan);
      return `${p.x},${p.y}`;
    }).join(" ");

    // Data dots
    const dataDots = radarKeys.map((rk, i) => {
      const puan = critique.skorlar[rk.key]?.puan || 0;
      const p = polarToXY(i, puan);
      return `<circle cx="${p.x}" cy="${p.y}" r="4" fill="${rk.color}" stroke="#fff" stroke-width="1.5"/>`;
    }).join("");

    const radarSvg = `
      <svg viewBox="0 0 ${radarSize} ${radarSize}" class="critique-radar-svg" xmlns="http://www.w3.org/2000/svg">
        ${gridRings}
        ${spokes}
        <polygon points="${dataPoints}" fill="rgba(38,103,255,0.10)" stroke="rgba(38,103,255,0.5)" stroke-width="1.5" stroke-linejoin="round"/>
        ${dataDots}
      </svg>
    `;

    // Group cards with score bars
    const groupCards = critiqueGroups.map((group) => {
      const groupScores = group.criteria.map((c) => critique.skorlar[c.key]?.puan || 0);
      const groupAvg = (groupScores.reduce((a, b) => a + b, 0) / groupScores.length).toFixed(1);
      const criteriaHtml = group.criteria.map((c) => {
        const puan = critique.skorlar[c.key]?.puan || 0;
        const yorum = critique.skorlar[c.key]?.yorum || "";
        const barColor = getMetricColor(puan);
        return `
          <div class="critique-score-row">
            <div class="critique-score-header">
              <span class="critique-score-label">${escapeHtml(c.label)}</span>
              <span class="critique-score-value">${puan}/10</span>
            </div>
            <div class="critique-score-bar-track">
              <div class="critique-score-bar-fill" style="width: ${puan * 10}%; background: ${barColor};"></div>
            </div>
            <p class="critique-score-comment">${escapeHtml(yorum)}</p>
          </div>
        `;
      }).join("");
      return `
        <article class="summary-card critique-group-card" style="--group-color: ${group.color};">
          <div class="critique-group-header">
            <div class="critique-group-title-row">
              <span class="critique-group-icon" style="color: ${group.color};">${group.icon}</span>
              <div>
                <span class="critique-group-title">${escapeHtml(group.title)}</span>
                <span class="critique-group-subtitle">${escapeHtml(group.subtitle)}</span>
              </div>
            </div>
            <span class="critique-group-avg" style="color: ${group.color};">${groupAvg}</span>
          </div>
          <div class="critique-scores-list">
            ${criteriaHtml}
          </div>
        </article>
      `;
    }).join("");

    // Acoustic warning
    const akustikHtml = critique.akustikUyari ? `
      <article class="summary-card critique-acoustic-warning">
        <div class="critique-acoustic-header">
          <span class="critique-acoustic-icon">&#9888;</span>
          <span class="analysis-eyebrow critique-eyebrow-orange">Akustik Uyari</span>
        </div>
        <p class="critique-acoustic-text">${escapeHtml(critique.akustikUyari)}</p>
      </article>
    ` : "";

    const skorLabel = document.getElementById("critique-collapsed-score");
    if (skorLabel) {
      skorLabel.innerHTML = `<span style="color:${healthColor}; font-weight:800">${avgScore}</span> <span style="font-size:12px;color:var(--muted)">/10</span>`;
    }

    const gucluItems = (critique.gucluYonler || []).map((item) => `<li>${escapeHtml(item)}</li>`).join("");
    const zayifItems = (critique.zayifYonler || []).map((item) => `<li>${escapeHtml(item)}</li>`).join("");
    ui.analysisSummary.innerHTML = `
      <div class="critique-dashboard">
        <div class="critique-dashboard-top">
          <article class="summary-card critique-overview-card">
            <div class="critique-overview-header">
              <div>
                <span class="analysis-eyebrow">Genel Tasarim Skoru</span>
                <div class="critique-avg-score">
                  <span class="critique-avg-number" style="color: ${healthColor};">${avgScore}</span>
                  <span class="critique-avg-label">/ 10</span>
                </div>
              </div>
              <div class="critique-mode-badge">
                <span class="badge success">AI Kritik</span>
              </div>
            </div>
            <p class="critique-general-text">${escapeHtml(critique.genelDegerlendirme || "")}</p>
          </article>
          <div class="critique-top-stack">
            <article class="summary-card critique-strengths-card">
              <span class="analysis-eyebrow critique-eyebrow-green">Guclu Yonler</span>
              <ul class="critique-list critique-list-green">${gucluItems}</ul>
            </article>
            <article class="summary-card critique-weaknesses-card">
              <span class="analysis-eyebrow critique-eyebrow-red">Gelistirilmesi Gerekenler</span>
              <ul class="critique-list critique-list-red">${zayifItems}</ul>
            </article>
          </div>
        </div>
        <div class="critique-groups-grid">
          ${groupCards}
        </div>
        ${akustikHtml}
      </div>
    `;
  } else {
    const strategyBadges = [
      `Guven: ${takeoffConfidence.label}`,
      `Revize alani: ${opportunityItems.length}`,
      `Maliyet riski: ${(deriveCostSensitiveItems(appState.quantityTakeoff)[0] || "Dengeli")}`,
    ];
    const compactDecisionLines = [
      `Baslangic: ${decisionPanel.strategyTitle}`,
      `Hizli firsatlar: ${opportunityItems.join(" / ") || "Belirgin firsat bulunmadi"}`,
      `Dogrulanacaklar: ${verificationItems.join(" / ") || "Ek saha teyidi gerekmez"}`,
    ];
    ui.analysisSummary.innerHTML = `
      <div class="analysis-compact-grid">
        <article class="summary-card analysis-compact-hero">
          <span class="analysis-eyebrow">Baslangic Stratejisi</span>
          <h4>${escapeHtml(decisionPanel.strategyTitle)}</h4>
          <div class="analysis-token-row">
            ${strategyBadges.map((tag) => `<span class="analysis-token">${escapeHtml(tag)}</span>`).join("")}
          </div>
        </article>
        <article class="summary-card analysis-compact-lines">
          <span class="analysis-eyebrow">Karar Satirlari</span>
          <div class="analysis-line-list">
            ${compactDecisionLines.map((line) => `<p class="analysis-line-item">${escapeHtml(line)}</p>`).join("")}
          </div>
        </article>
      </div>
    `;
  }
  sanitizeStaticUiText(ui.analysisConfidenceStrip?.closest(".panel") || ui.analysisSummary);
  sanitizeStaticUiText(ui.analysisSummary);
  maybePrimeAnalysisReviewFlow();
}

function deriveCompactVerificationItems(summary, takeoff) {
  const items = [
    ...deriveMeasurementCriticalItems(summary, takeoff),
    ...deriveUserChecks(summary),
    ...deriveAnalysisConstraints((summary.detectedSurfaces || []).map(formatAnalysisListItem).filter(Boolean), summary.userReviewRecommendation),
  ];
  return [...new Set(items)].slice(0, 3);
}

function buildAnalysisDecisionPanel(summary, changeableItems, detectedSurfaces) {
  const quickWins = (changeableItems.length ? changeableItems : ["Duvar yuzeyleri", "Tavan katmani", "Aydinlatma omurgasi"]).slice(0, 4);
  const constraints = deriveAnalysisConstraints(detectedSurfaces, summary.userReviewRecommendation);
  const userChecks = deriveUserChecks(summary);
  const leadFocus = quickWins.slice(0, 2).join(" + ");
  const strategyTitle = leadFocus ? `${leadFocus} ile hizli etki` : "Hizli etki icin kontrollu yenileme";
  const strategyCopy = `Ilk fazda ${leadFocus || "yuzey ve isik katmanlarina"} odaklanip maliyeti dagitmadan mekan karakterini belirginlestirin. Sonraki kararlarin ekseni bu cekirdege gore kurulabilir.`;
  const priorityTags = [
    `Revize alani ${quickWins.length}`,
    detectedSurfaces[0] || "Mevcut zemin okunuyor",
    constraints[0] || "Sabit geometri korunmali",
  ].filter(Boolean);
  return { quickWins, constraints, userChecks, strategyTitle, strategyCopy, priorityTags };
}

function applyVisionConfidenceGating(quantityTakeoff = []) {
  return sanitizeVisionTakeoffItems(quantityTakeoff).map((rawItem) => {
    const item = { ...rawItem };
    const confidence = getVisionConfidenceProfile(item.visionConfidence ?? item.confidence);
    const baseNote = String(item.note || "").trim();
    item.visionConfidence = confidence.score;
    if (confidence.score >= VISION_CONFIDENCE_THRESHOLDS.high) {
      item.inScope = typeof item.inScope === "boolean" ? item.inScope : true;
      item.designAction = item.designAction || inferDesignAction(item.inScope);
    } else if (confidence.score >= VISION_CONFIDENCE_THRESHOLDS.medium) {
      item.inScope = true;
      item.designAction = item.designAction || "ai";
    } else {
      item.inScope = false;
      item.designAction = "preserve";
      item.formDNA = item.formDNA || "koru";
      item.materialDNA = item.materialDNA || "koru";
      item.colorDNA = item.colorDNA || "koru";
    }
    item.note = [baseNote, `Vision guveni: ${confidence.label}. ${confidence.note}`].filter(Boolean).join(" ");
    return item;
  });
}

function sanitizeVisionTakeoffItems(quantityTakeoff = []) {
  const items = Array.isArray(quantityTakeoff) ? quantityTakeoff : [];
  const deduped = new Map();
  items.forEach((rawItem) => {
    const item = { ...(rawItem || {}) };
    const cleaned = sanitizeVisionTakeoffElementName(item.element);
    const normalizedElement = normalizeName(cleaned.name);
    const normalizedUnit = normalizeName(item.unit);
    const confidence = normalizeVisionConfidence(item.visionConfidence ?? item.confidence);
    const quantity = Number(item.quantity || 0);
    const isDecorative = VISION_TAKEOFF_DECORATIVE_PATTERN.test(normalizedElement);

    if (!normalizedElement || !Number.isFinite(quantity) || quantity <= 0) return;
    if (isDecorative) return;

    item.element = cleaned.name;
    item.location = String(item.location || "").trim();
    item.visibleInRenderIndices = Array.isArray(item.visibleInRenderIndices)
      ? item.visibleInRenderIndices.map((value) => Number(value)).filter(Number.isInteger)
      : [];
    if (cleaned.changed && !/sadelestir/i.test(item.note || "")) {
      item.note = [String(item.note || "").trim(), "Kalem adi gorsel tipolojiye gore sadelestirildi."].filter(Boolean).join(" ");
    }

    const key = `${normalizedElement}|${normalizedUnit || "adet"}`;
    const existing = deduped.get(key);
    if (!existing) {
      deduped.set(key, item);
      return;
    }

    const existingConfidence = normalizeVisionConfidence(existing.visionConfidence ?? existing.confidence);
    if (confidence > existingConfidence || (confidence === existingConfidence && quantity > Number(existing.quantity || 0))) {
      deduped.set(key, item);
    }
  });
  return Array.from(deduped.values());
}

function sanitizeVisionTakeoffElementName(value = "") {
  const original = String(value || "").trim();
  let cleaned = original
    .replace(/\((sofa|couch|table|chair|armchair|desk|coffee table)\)/gi, "")
    .replace(/\s+/g, " ")
    .trim();
  const tokens = cleaned.split(" ").filter(Boolean);
  let changed = cleaned !== original;
  let strippedStyle = false;
  while (tokens.length > 1 && VISION_TAKEOFF_STYLE_PREFIXES.includes(normalizeName(tokens[0]))) {
    tokens.shift();
    strippedStyle = true;
    changed = true;
  }
  cleaned = tokens.join(" ").replace(/\s+/g, " ").trim();
  return {
    name: cleaned || original,
    changed,
    strippedStyle,
  };
}

function buildScopeAlignmentPanel(summary) {
  const takeoff = Array.isArray(appState.quantityTakeoff) ? appState.quantityTakeoff : [];
  const preserved = takeoff
    .filter((item) => !item.inScope || (item.designAction || inferDesignAction(item.inScope)) === "preserve")
    .map((item) => item.element)
    .filter(Boolean);
  const revised = takeoff
    .filter((item) => item.inScope)
    .map((item) => item.element)
    .filter(Boolean);
  const measurement = deriveMeasurementCriticalItems(summary, takeoff);
  const costSensitive = deriveCostSensitiveItems(takeoff);
  return {
    preserved: preserved.length ? preserved.slice(0, 5) : ["Mevcut plan konturu ve sabit geometri korunmali."],
    revised: revised.length ? revised.slice(0, 5) : ["Revize kapsam Step 2 tablosunda netlestirilecek."],
    measurement: measurement.length ? measurement.slice(0, 5) : ["Tavan yuksekligi ve sabit eleman olculeri sahada teyit edilmeli."],
    costSensitive: costSensitive.length ? costSensitive.slice(0, 5) : ["Tavan, zemin ve sabit mobilya kalemleri maliyeti en fazla oynatir."],
  };
}

function deriveMeasurementCriticalItems(summary, takeoff) {
  const items = [];
  if ((summary.userReviewRecommendation || "").match(/kolon|kose|birlesim|mobilya/i)) {
    items.push("Kose birlesimleri ve kolon cikintilari net olculenmeli.");
    items.push("Sabit mobilya adetleri ve net yerleri teyit edilmeli.");
  }
  if (takeoff.some((item) => /tavan|aydinlatma/i.test(item.element || ""))) {
    items.push("Tavan yuksekligi ve aydinlatma akslari netlestirilmeli.");
  }
  if (takeoff.some((item) => /zemin|duvar/i.test(item.element || ""))) {
    items.push("Duvar boylari ve zemin sinirlari kesin olcu ile dogrulanmali.");
  }
  return [...new Set(items)];
}

function deriveCostSensitiveItems(takeoff) {
  const weighted = takeoff
    .map((item) => ({
      element: item.element,
      score: Number(item.quantity || 0) * ((item.designAction || inferDesignAction(item.inScope)) === "redesign" ? 3 : (item.inScope ? 2 : 1)),
    }))
    .filter((item) => item.element)
    .sort((a, b) => b.score - a.score)
    .map((item) => item.element);
  return [...new Set(weighted)].slice(0, 5);
}

function deriveAnalysisConstraints(detectedSurfaces, userReviewRecommendation) {
  const constraints = [];
  if (detectedSurfaces.some((item) => /zemin|parke|seramik/i.test(item))) constraints.push("Zemin karakteri referans olarak korunmali.");
  if (detectedSurfaces.some((item) => /tavan|aksi|lineer/i.test(item))) constraints.push("Tavan akslari ve mevcut ritim bozulmadan yorumlanmali.");
  if (/sabit mobilya/i.test(userReviewRecommendation || "")) constraints.push("Sabit mobilya yerleri saha teyidi olmadan tasinmamis kabul edilmeli.");
  if (!constraints.length) constraints.push("Tasiyici geometri ve plan konturu sabit kabul edilmeli.");
  return constraints.slice(0, 3);
}

function deriveUserChecks(summary) {
  const userChecks = splitSentences(summary.userReviewRecommendation || "").concat(splitSentences(summary.analysisNotes || ""));
  const normalized = userChecks
    .map((item) => item.replace(/^Analiz Notu:\s*/i, "").trim())
    .filter(Boolean);
  return (normalized.length ? normalized : ["Kritik koseler, cikintilar ve sabit eleman adetleri sahada teyit edilmeli."]).slice(0, 4);
}

function splitSentences(text) {
  return String(text || "")
    .split(/[.!?]\s+|\n+/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function inferSceneProgramContext() {
  const takeoffText = (appState.quantityTakeoff || [])
    .map((item) => `${item.element || ""} ${item.note || ""}`)
    .join(" ");
  const regionText = (appState.segmentation?.regions || [])
    .map((region) => `${region.label || ""} ${region.category || ""} ${region.detectedMaterial || ""}`)
    .join(" ");
  const summaryText = [
    appState.analysisSummary?.confidenceNote,
    appState.analysisSummary?.analysisNotes,
    appState.analysisSummary?.designCritique?.genelDegerlendirme,
    appState.analysisSummary?.designCritique?.skorlar?.mekansalOrganizasyon?.yorum,
  ].filter(Boolean).join(" ");
  const haystack = `${takeoffText} ${regionText} ${summaryText}`.toLowerCase();
  const score = {
    konferans: 0,
    toplanti: 0,
    egitim: 0,
    yemekhane: 0,
    cafeterya: 0,
    lounge: 0,
    resepsiyon: 0,
    bekleme: 0,
    ofis: 0,
    cok_amacli: 0,
  };
  const bump = function (key, value) {
    if (score[key] !== undefined) score[key] += value;
  };

  if (/(konferans|auditorium|konferans salonu|konfernas)/.test(haystack)) bump("konferans", 8);
  if (/(toplanti|meeting|boardroom|sunum|presentation)/.test(haystack)) bump("toplanti", 6);
  if (/(egitim|sinif|ders|ogrenci|tahta|egitim alani|seminer)/.test(haystack)) bump("egitim", 7);
  if (/(yemekhane|yemek alan|yemekhane\/toplanti|servis|oglen yemegi)/.test(haystack)) bump("yemekhane", 8);
  if (/(kafeterya|cafeteria|cafe|caf[eé]tery)/.test(haystack)) bump("cafeterya", 8);
  if (/(lounge|dinlenme|sosyal alan|hospitality|relax)/.test(haystack)) bump("lounge", 7);
  if (/(resepsiyon|karşilama|karsilama|lobi|lobby)/.test(haystack)) bump("resepsiyon", 7);
  if (/(bekleme|waiting|bekleme alan)/.test(haystack)) bump("bekleme", 7);
  if (/(ofis|workstation|calisma|çalisma|desk)/.test(haystack)) bump("ofis", 6);
  if (/(cok amacli|multi purpose|multi-purpose|esnek kullanim)/.test(haystack)) bump("cok_amacli", 7);

  const chairCount = ((haystack.match(/sandalye|koltuk/g) || []).length);
  const tableCount = ((haystack.match(/masa/g) || []).length);
  const screenLike = /(ekran|projeksiyon|sunum duvari|odak duvari)/.test(haystack);
  if (chairCount >= 2 && tableCount >= 1) {
    bump("toplanti", 2);
    bump("yemekhane", 2);
    bump("cafeterya", 1);
  }
  if (screenLike && chairCount >= 2) {
    bump("konferans", 2);
    bump("egitim", 2);
    bump("toplanti", 2);
  }

  const ranked = Object.entries(score).sort((a, b) => b[1] - a[1]);
  const primaryType = ranked[0]?.[1] > 0 ? ranked[0][0] : "cok_amacli";
  const secondaryType = ranked[1]?.[1] > 2 ? ranked[1][0] : "";

  const labels = {
    konferans: "konferans salonu",
    toplanti: "toplanti alani",
    egitim: "egitim / seminer alani",
    yemekhane: "yemekhane",
    cafeterya: "kafeterya",
    lounge: "lounge / sosyal alan",
    resepsiyon: "resepsiyon / lobi",
    bekleme: "bekleme alani",
    ofis: "ofis",
    cok_amacli: "cok amacli alan",
  };
  const acousticTargetsByType = {
    konferans: { rt60Min: 0.55, rt60Max: 0.8, stiMin: 0.68 },
    toplanti: { rt60Min: 0.6, rt60Max: 0.85, stiMin: 0.65 },
    egitim: { rt60Min: 0.55, rt60Max: 0.8, stiMin: 0.65 },
    yemekhane: { rt60Min: 0.9, rt60Max: 1.3, stiMin: 0.45 },
    cafeterya: { rt60Min: 0.9, rt60Max: 1.25, stiMin: 0.48 },
    lounge: { rt60Min: 0.8, rt60Max: 1.15, stiMin: 0.45 },
    resepsiyon: { rt60Min: 0.8, rt60Max: 1.15, stiMin: 0.5 },
    bekleme: { rt60Min: 0.85, rt60Max: 1.2, stiMin: 0.5 },
    ofis: { rt60Min: 0.75, rt60Max: 1.0, stiMin: 0.58 },
    cok_amacli: { rt60Min: 0.7, rt60Max: 1.0, stiMin: 0.6 },
  };
  const planFocusByType = {
    konferans: "gorus hatti, odak duvari, giris-cikis hizi ve toplu oturum okunurlugu",
    toplanti: "gorus hatti, masa etrafi dolasim, toplu kullanim akisi ve odak hiyerarsisi",
    egitim: "ogrenme odagi, ekran/tahta gorusu, gecis rahatligi ve tekrarli oturum duzeni",
    yemekhane: "servis akisi, masa araliklari, toplu oturum konforu ve giris-cikis rahatligi",
    cafeterya: "servis-bekleme akisi, masa yogunlugu ve oturum ceplerinin rahatligi",
    lounge: "serbest dolasim, rahatlama cepleri ve yumusak zonlama",
    resepsiyon: "karsilama akisi, bekleme cepleri ve yonlendirme netligi",
    bekleme: "sakin dolasim, bekleme cepleri ve oturum yogunlugu dengesi",
    ofis: "gunluk kullanim akisi, gorev odakli zonlama ve ekip dolasimi",
    cok_amacli: "farkli kurguya uyum, yeniden yerlesim kolayligi ve ana akis netligi",
  };
  const furnitureFocusByType = {
    konferans: "uzun oturum konforu, siralama ritmi, gorus hatti engellememe ve dayanim",
    toplanti: "oturum suresi, masa-sandalye orani, grup etkilesimi ve konfor",
    egitim: "uzun sureli kullanim, yazma/izleme ergonomisi ve tekrarli duzende rahatlik",
    yemekhane: "masa ustu rahatligi, hizli temizlik, kullanim yogunlugu ve davetkarlik",
    cafeterya: "devir hizina uygun dayanim, rahat ama hizli kullanim ergonomisi",
    lounge: "rahatlama, yumusak oturum, bekleme suresi ve sosyal kullanima uyum",
    resepsiyon: "kisa sureli bekleme konforu, temsil dili ve duzenli gorunum",
    bekleme: "kisa-orta sureli rahatlik, kullanim yogunlugu ve temiz okunurluk",
    ofis: "gun boyu ergonomi, dayanim ve ekip kullanimi",
    cok_amacli: "tasinabilirlik, yeniden dizilim ve farkli kullanima uyum",
  };
  const acousticFocusByType = {
    konferans: "konusma anlasirligi, odakli dinleme ve yankinin kontrolu",
    toplanti: "konusma netligi, yakin masa yansimalari ve uzun oturum rahatligi",
    egitim: "ogretici sesin netligi, arka siralarda anlasilabilirlik ve dagilim",
    yemekhane: "gurultu yogunlugunun kontrolu, masa sohbetlerinin birbirini bastirmamasi ve genel konfor",
    cafeterya: "servis gurultusu ile sohbet sesinin dengelenmesi ve genel ses yumusakligi",
    lounge: "yumusak arka plan seviyesi ve rahat sohbet konforu",
    resepsiyon: "karsilama netligi ve yogun saatlerde ses karmasasinin azaltilmasi",
    bekleme: "rahatsiz etmeyen arka plan seviyesi ve yumusak yankilanma",
    ofis: "yansimalarin kontrolu ve konusma gizliligi/okunurluk dengesi",
    cok_amacli: "farkli kullanimlara uyacak orta sertlikte kontrollu bir akustik denge",
  };

  return {
    primaryType,
    secondaryType,
    primaryLabel: labels[primaryType] || labels.cok_amacli,
    secondaryLabel: secondaryType ? (labels[secondaryType] || "") : "",
    summary: secondaryType
      ? `Mekan en yakin ${labels[primaryType]} olarak okunuyor; ikincil olarak ${labels[secondaryType]} karakteri de tasiyor.`
      : `Mekan en yakin ${labels[primaryType]} olarak okunuyor.`,
    planFocus: planFocusByType[primaryType] || planFocusByType.cok_amacli,
    furnitureFocus: furnitureFocusByType[primaryType] || furnitureFocusByType.cok_amacli,
    acousticFocus: acousticFocusByType[primaryType] || acousticFocusByType.cok_amacli,
    acousticTargets: acousticTargetsByType[primaryType] || acousticTargetsByType.cok_amacli,
  };
}

function getCombinedHubAnalysisContext() {
  return [
    appState.analysisSummary?.confidenceNote,
    appState.analysisSummary?.analysisNotes,
  ].filter(Boolean).join(" ");
}

function getHubMetricRows(evalData, fallbackRows) {
  const rows = evalData?.cards?.flatMap((card) => card.rows || []);
  return Array.isArray(rows) && rows.length ? rows : fallbackRows;
}

function describeAcousticTargets(targets, programLabel) {
  return `Hedef: ${targets.rt60Min.toFixed(2)}-${targets.rt60Max.toFixed(2)} sn (${programLabel}), STI \u2265 ${targets.stiMin.toFixed(2)}`;
}

function estimateProgramAwareAcousticScore(rt60, sti, targets) {
  const rtCenter = (targets.rt60Min + targets.rt60Max) / 2;
  const rtTolerance = Math.max(0.18, (targets.rt60Max - targets.rt60Min) / 2);
  const rtPenalty = Math.min(1, Math.abs(rt60 - rtCenter) / (rtTolerance + 0.35));
  const rtScore = 1 - rtPenalty;
  const stiScore = clampNumber((sti - (targets.stiMin - 0.18)) / 0.28, 0, 1);
  return clampNumber(4 + ((rtScore * 0.55) + (stiScore * 0.45)) * 5, 3.8, 9.4);
}

function formatAnalysisListItem(item) {
  if (typeof item === "string" || typeof item === "number") return String(item);
  if (!item || typeof item !== "object") return "";
  return item.label
    || item.name
    || item.title
    || item.surface
    || item.element
    || item.description
    || item.text
    || Object.entries(item)
      .filter(([, value]) => value !== null && value !== undefined && value !== "")
      .slice(0, 3)
      .map(([key, value]) => `${key}: ${value}`)
      .join(", ");
}

function renderQuantityTable() {
  ui.designPrompt.value = appState.designPrompt;
  renderPromptBuilder();
  renderBudgetControl();
  renderAggressivenessControl();
  renderAlternativeCountControl();
  if (appState.loading.analysis) {
    ui.quantityTakeoffSummary.innerHTML = renderSkeletonGrid(4, "Metraj kalemleri hazirlaniyor...");
    ui.quantityTableBody.innerHTML = renderSkeletonTableRows(6, 9);
    return;
  }
  ui.quantityTakeoffSummary.innerHTML = renderTakeoffSummaryMarkup();
  if (!appState.quantityTakeoff.length) {
    if (ui.quantityCardGrid) ui.quantityCardGrid.innerHTML = `<div class="takeoff-empty-state">${emptyStateInline("Metraj tablosu analizden sonra dolacaktir.")}</div>`;
    return;
  }
  if (ui.quantityCardGrid) {
    const takeoff = appState.quantityTakeoff || [];
    const surfaces = takeoff.filter(item => {
      const el = normalizeName(item.element);
      return /duvar|zemin|tavan|panel|kaplama|nis|kolon|banko|dolap|pencere|kapi/i.test(el);
    });
    const objects = takeoff.filter(item => {
      const el = normalizeName(item.element);
      return !/duvar|zemin|tavan|panel|kaplama|nis|kolon|banko|dolap|pencere|kapi/i.test(el);
    });

    let html = "";
    if (surfaces.length) {
      html += `<div class="takeoff-group-header">Yuzeyler</div>`;
      html += surfaces.map(item => renderCompactTakeoffCard(item)).join("");
    }
    if (objects.length) {
      html += `<div class="takeoff-group-header">Mobilya & Objeler</div>`;
      html += objects.map(item => renderCompactTakeoffCard(item)).join("");
    }
    ui.quantityCardGrid.innerHTML = html || `<div class="takeoff-empty-state">${emptyStateInline("Metraj tablosu analizden sonra dolacaktir.")}</div>`;
  }
}

function renderCompactTakeoffCard(item) {
  const visionConfidence = getVisionConfidenceProfile(item.visionConfidence);
  const showVisionBadge = visionConfidence.label.toLowerCase() !== "yuksek";
  const costContext = getTakeoffCostContext(item);
  const pendingClass = costContext.requiresApproval ? "warning" : costContext.source.startsWith("db") ? "success" : "info";

  const approvalMarkup = costContext.requiresApproval ? `
    <div class="tkcard-cost-actions">
      <button type="button" class="primary-button small-button" data-add-takeoff-cost="${item.id}">Sisteme Ekle</button>
    </div>
  ` : "";

  const isSegmentationEligible = isSegmentationEligibleTakeoffItem(item);
  const segTitle = isSegmentationEligible
    ? "Segmentasyona dahil bilgisini goster"
    : "Segmentasyon disi nedenini goster";
  const segAriaLabel = isSegmentationEligible
    ? "Segmentasyona dahil bilgisi"
    : "Segmentasyon disi bilgisi";

  return `
    <article class="takeoff-card-item compact-card" data-takeoff-card="${item.id}">
      <div class="tkcard-head">
        <div class="tkcard-identity">
          <input class="tkcard-name" type="text" value="${escapeHtml(item.element)}" data-takeoff-id="${item.id}" data-takeoff-field="element">
          <div class="tkcard-meta">
            <input class="tkcard-qty" type="number" step="0.1" min="0" value="${item.quantity}" data-takeoff-id="${item.id}" data-takeoff-field="quantity">
            <input class="tkcard-unit" type="text" value="${escapeHtml(item.unit)}" data-takeoff-id="${item.id}" data-takeoff-field="unit">
          </div>
        </div>
        <div class="tkcard-head-right">
          <span class="tkcard-price-summary">${formatCurrency(costContext.total)}</span>
          <button
            type="button"
            class="tkcard-seg-indicator ${isSegmentationEligible ? "is-included" : "is-excluded"}"
            data-show-segmentation-info="${item.id}"
            title="${segTitle}"
            aria-label="${segAriaLabel}">
            <span class="tkcard-seg-indicator-box" aria-hidden="true"></span>
          </button>
          <button type="button" class="tkcard-delete" data-delete-takeoff="${item.id}" title="Sil">&times;</button>
        </div>
      </div>

      ${showVisionBadge ? `<span class="badge ${visionConfidence.badge} tkcard-vision-badge">Vision ${visionConfidence.label}</span>` : ""}

      <div class="tkcard-cost-block compact-cost">
        <div class="tkcard-cost-head-summary">
          <span class="badge ${pendingClass}">${escapeHtml(costContext.sourceLabel)}</span>
          <p class="tkcard-cost-values">${formatCurrency(costContext.unitPrice)} birim / ${formatCurrency(costContext.labor)} iscilik</p>
        </div>
        ${approvalMarkup}
      </div>
    </article>
  `;
}

function renderGlobalColorPaletteCard() {
  const palette = getGlobalColorPaletteState();
  const isActive = palette.mode !== "off";
  const helperText = palette.mode === "override"
    ? "Tum scoped kalemler varsayilan olarak bu paleti referans alir."
    : palette.mode === "hybrid"
      ? "Kart bazinda yerel veya global kaynak secilebilir."
      : "Global palet kapali. Mevcut yerel renk kararlariniz aynen korunur.";
  return `
    <article class="takeoff-card-item takeoff-color-card ${isActive ? "is-active" : ""}">
      <div class="tkcard-head">
        <div class="tkcard-identity">
          <strong class="takeoff-color-card-title">Global Renk Paleti</strong>
          <p class="micro-copy">${helperText}</p>
        </div>
      </div>
      <div class="tkcard-dna-row">
        <span class="tkcard-row-label">Mod</span>
        <div class="pill-toggle-group">
          ${renderGlobalPaletteModeButton("off", "Kapali", palette.mode)}
          ${renderGlobalPaletteModeButton("hybrid", "Hibrit", palette.mode)}
          ${renderGlobalPaletteModeButton("override", "Tumunu Override Et", palette.mode)}
        </div>
      </div>
      <div class="tkcard-dna-row">
        <span class="tkcard-row-label">Iliski</span>
        <select class="table-input takeoff-color-select" data-global-color-field="harmony">
          ${renderGlobalHarmonyOptions(palette.harmony)}
        </select>
        <button type="button" class="ghost-button small-button" data-generate-global-palette="true">Uyumlu Palet Oner</button>
      </div>
      <div class="takeoff-color-palette-grid">
        ${palette.colors.map((hex, index) => `
          <label class="takeoff-color-slot">
            <span>${["Ana", "Denge", "Vurgu"][index] || `Renk ${index + 1}`}</span>
            <input type="color" value="${escapeHtml(hex)}" data-global-color-field="hex" data-global-color-index="${index}">
            <input class="table-input takeoff-color-hex" type="text" value="${escapeHtml(hex)}" data-global-color-field="hexText" data-global-color-index="${index}" placeholder="#D8D0C5">
          </label>
        `).join("")}
      </div>
      <div class="takeoff-color-preview">
        ${palette.colors.map((hex) => `<span class="takeoff-color-preview-swatch" style="background:${escapeHtml(hex)}"></span>`).join("")}
      </div>
    </article>
  `;
}

function renderBudgetControl() {
  const range = getBudgetRangeState();
  const profile = getBudgetRangeProfile(range);
  if (ui.budgetSliderMin) ui.budgetSliderMin.value = String(range.min);
  if (ui.budgetSliderMax) ui.budgetSliderMax.value = String(range.max);
  if (ui.budgetRangeControl) {
    ui.budgetRangeControl.style.setProperty("--range-start", `${(range.min / 5) * 100}%`);
    ui.budgetRangeControl.style.setProperty("--range-end", `${(range.max / 5) * 100}%`);
  }
  ui.budgetValue.textContent = profile.shortLabel;
  ui.budgetLabel.textContent = profile.modeLabel;
  ui.budgetLabel.className = `badge ${profile.badge}`;
}

function renderAggressivenessControl() {
  const range = getAggressivenessRangeState();
  const profile = getAggressivenessRangeProfile(range);
  if (ui.aggressivenessSliderMin) ui.aggressivenessSliderMin.value = String(range.min);
  if (ui.aggressivenessSliderMax) ui.aggressivenessSliderMax.value = String(range.max);
  if (ui.aggressivenessRangeControl) {
    ui.aggressivenessRangeControl.style.setProperty("--range-start", `${((range.min - 1) / 4) * 100}%`);
    ui.aggressivenessRangeControl.style.setProperty("--range-end", `${((range.max - 1) / 4) * 100}%`);
  }
  ui.aggressivenessValue.textContent = profile.shortLabel;
  ui.aggressivenessLabel.textContent = profile.modeLabel;
  ui.aggressivenessLabel.className = `badge ${profile.badge}`;
}

function handleBudgetRangeInput() {
  const nextRange = normalizeBudgetRange({
    min: Number(ui.budgetSliderMin?.value ?? 0),
    max: Number(ui.budgetSliderMax?.value ?? 0),
  });
  appState.budgetRange = nextRange;
  appState.budgetPreference = getBudgetRepresentativeLevel(nextRange);
  renderBudgetControl();
  renderPromptBuilder();
  saveState();
}

