function handlePromptPaletteComposerClick(event) {
  const globalMode = event.target.closest("[data-global-color-mode]")?.dataset.globalColorMode;
  if (globalMode && isCustomPaletteSelected()) {
    appState.globalColorPalette = { ...getGlobalColorPaletteState(), mode: globalMode };
    appState.promptSelections.paletteCustom = summarizeGlobalColorPalette();
    renderPromptBuilder();
    saveState();
    return;
  }
  if (event.target.closest("[data-prompt-generate-global-palette]") && isCustomPaletteSelected()) {
    const palette = getGlobalColorPaletteState();
    appState.globalColorPalette = {
      ...palette,
      mode: palette.mode === "off" ? "hybrid" : palette.mode,
      colors: generateRelatedPalette(palette.colors[0], palette.harmony),
    };
    appState.promptSelections.paletteCustom = summarizeGlobalColorPalette();
    renderPromptBuilder();
    saveState();
  }
}

function handlePromptPaletteComposerInput(event) {
  const globalField = event.target.dataset.promptGlobalColorField;
  if (!globalField || !isCustomPaletteSelected()) return;
  const palette = getGlobalColorPaletteState();
  if (globalField === "harmony") palette.harmony = event.target.value;
  if (globalField === "hex" || globalField === "hexText") {
    const index = Number(event.target.dataset.globalColorIndex || 0);
    palette.colors[index] = normalizeHexColor(event.target.value);
  }
  appState.globalColorPalette = palette;
  appState.promptSelections.paletteCustom = summarizeGlobalColorPalette() || "ozel renk paleti";
  renderPromptBuilder();
  saveState();
}

function normalizePromptSelectionValues(value, fallback = []) {
  if (Array.isArray(value)) return [...new Set(value.filter(Boolean))];
  if (typeof value === "string" && value.trim()) return [value.trim()];
  return Array.isArray(fallback) ? [...fallback] : [];
}

function normalizeSinglePromptSelectionValue(value, fallback = "") {
  if (Array.isArray(value)) return String(value[0] || fallback || "").trim() || fallback;
  if (typeof value === "string" && value.trim()) return value.trim();
  return fallback;
}

