function getConfidenceProfile(label) {
  const map = {
    Yuksek: { badge: "success", label: "Yuksek" },
    Orta: { badge: "info", label: "Orta" },
    Dusuk: { badge: "warning", label: "Dusuk" },
  };
  return map[label] || map.Orta;
}

function normalizeVisionConfidence(value, fallback = 0.68) {
  const numeric = Number(value);
  if (Number.isFinite(numeric)) return Math.min(0.99, Math.max(0, numeric));
  return fallback;
}

function getVisionConfidenceProfile(value) {
  const score = normalizeVisionConfidence(value);
  if (score >= VISION_CONFIDENCE_THRESHOLDS.high) return { score, label: "Yuksek", badge: "success", note: "Otomatik olarak kapsama dahil edildi." };
  if (score >= VISION_CONFIDENCE_THRESHOLDS.medium) return { score, label: "Orta", badge: "info", note: "Kullanici karari icin acik birakildi." };
  return { score, label: "Dusuk", badge: "warning", note: "Varsayilan olarak kapsam disi tutuldu." };
}

function calculateConfidenceMetrics(alternative = null) {
  const manualRows = appState.quantityTakeoff.filter((item) => /kullanici/i.test(item.note || "")).length;
  const confidenceScores = appState.quantityTakeoff
    .map((item) => normalizeVisionConfidence(item.visionConfidence, NaN))
    .filter((score) => Number.isFinite(score));
  const averageVisionConfidence = confidenceScores.length
    ? confidenceScores.reduce((sum, score) => sum + score, 0) / confidenceScores.length
    : 0;
  const takeoff = averageVisionConfidence >= VISION_CONFIDENCE_THRESHOLDS.high && appState.uploadedPlan && appState.uploadedRenders.length >= 2 && manualRows <= 2
    ? "Yuksek"
    : averageVisionConfidence >= VISION_CONFIDENCE_THRESHOLDS.medium && appState.uploadedPlan
      ? "Orta"
      : "Dusuk";

  const takeoffSummary = calculateTakeoffCostSummary(appState.quantityTakeoff);
  const estimatedTakeoffRatio = takeoffSummary.lineItems.length
    ? takeoffSummary.lineItems.filter((item) => !String(item.source || "").startsWith("db")).length / takeoffSummary.lineItems.length
    : 1;
  const unknownRatio = alternative && alternative.materials?.length
    ? alternative.materials.filter((item) => item.status === "unknown").length / alternative.materials.length
    : appState.unknownMaterials.length ? Math.min(1, appState.unknownMaterials.length / 6) : 0;
  const cost = estimatedTakeoffRatio < 0.25 && unknownRatio < 0.2
    ? "Yuksek"
    : estimatedTakeoffRatio < 0.6 && unknownRatio < 0.5
      ? "Orta"
      : "Dusuk";

  const redesignCount = appState.quantityTakeoff.filter((item) => item.designAction === "redesign").length;
  const visual = getSelectedReferenceRender() && getAggressivenessRepresentativeLevel() <= 2 && redesignCount <= 2
    ? "Yuksek"
    : getSelectedReferenceRender()
      ? "Orta"
      : "Dusuk";

  return { takeoff, cost, visual };
}

function calculateAlternativeCharacterScore(alternative = {}) {
  const redesignCount = (alternative.changedItems || []).filter((item) => {
    const normalized = normalizeName(item);
    return /tavan|duvar|aydinlatma|mobilya|sandalye|koltuk|panel|zemin/.test(normalized);
  }).length;
  const paletteDepth = normalizeSuggestedColors(alternative.suggestedColors || []).length;
  const contrastSignal = /premium|karakter|vurgu|kontrast|belirgin|rafine/i.test(`${alternative.title || ""} ${alternative.concept || ""} ${alternative.colorDNA || ""}`) ? 2 : 0;
  return redesignCount * 2 + paletteDepth + contrastSignal;
}

function buildAlternativePriorityMap(alternatives = []) {
  const safeAlternatives = alternatives.filter(Boolean);
  if (!safeAlternatives.length) return new Map();
  const priorityMap = new Map();
  const sortedByCost = [...safeAlternatives].sort((left, right) => (left.costSummary?.total || 0) - (right.costSummary?.total || 0));
  const cheapest = sortedByCost[0];
  if (cheapest) {
    priorityMap.set(cheapest.id, { label: "En ekonomik", badge: "success" });
  }
  const sortedByCharacter = [...safeAlternatives].sort((left, right) => calculateAlternativeCharacterScore(right) - calculateAlternativeCharacterScore(left));
  const mostCharacterful = sortedByCharacter.find((item) => item.id !== cheapest?.id) || sortedByCharacter[0];
  if (mostCharacterful) {
    priorityMap.set(mostCharacterful.id, { label: "En karakterli", badge: "warning" });
  }
  const averageCost = safeAlternatives.reduce((sum, item) => sum + (item.costSummary?.total || 0), 0) / safeAlternatives.length;
  const mostBalanced = [...safeAlternatives]
    .sort((left, right) => Math.abs((left.costSummary?.total || 0) - averageCost) - Math.abs((right.costSummary?.total || 0) - averageCost))
    .find((item) => !priorityMap.has(item.id)) || safeAlternatives.find((item) => !priorityMap.has(item.id)) || safeAlternatives[0];
  if (mostBalanced) {
    priorityMap.set(mostBalanced.id, { label: "En dengeli", badge: "info" });
  }
  safeAlternatives.forEach((item) => {
    if (!priorityMap.has(item.id)) priorityMap.set(item.id, { label: "Degerlendiriliyor", badge: "neutral" });
  });
  return priorityMap;
}

function deriveAlternativeCostRisk(alternative = {}) {
  const total = alternative.costSummary?.total || 0;
  const delta = alternative.costSummary?.designDeltaTotal || 0;
  const unknownCount = Number(alternative.unknownMaterialCount || 0);
  const deltaRatio = total > 0 ? delta / total : 0;
  if (unknownCount >= 2 || deltaRatio >= 0.42) return "Yuksek";
  if (unknownCount >= 1 || deltaRatio >= 0.2) return "Orta";
  return "Dusuk";
}

function deriveAlternativeBuildability(alternative = {}) {
  const changedCount = (alternative.changedItems || []).length;
  const unknownCount = Number(alternative.unknownMaterialCount || 0);
  const characterScore = calculateAlternativeCharacterScore(alternative);
  if (unknownCount >= 2 || changedCount >= 4 || characterScore >= 10) return "Detay cozumu ister";
  if (unknownCount >= 1 || changedCount >= 3 || characterScore >= 7) return "Orta";
  return "Kolay";
}

function deriveAlternativeSiteImpact(alternative = {}) {
  const changedCount = (alternative.changedItems || []).length;
  const buildability = alternative.buildability || deriveAlternativeBuildability(alternative);
  const costRisk = alternative.costRisk || deriveAlternativeCostRisk(alternative);
  if (buildability === "Detay cozumu ister" || costRisk === "Yuksek" || changedCount >= 4) return "Yuksek koordinasyon ihtiyaci";
  if (buildability === "Orta" || costRisk === "Orta" || changedCount >= 3) return "Orta santiye yuku";
  return "Dusuk mudahale";
}

function summarizeAlternativeSelectionReason(alternative = {}) {
  const changed = (alternative.changedItems || []).slice(0, 2);
  const focus = changed.length ? changed.join(" ve ") : "secili kapsam";
  const priority = alternative.priorityLabel || "";
  const buildability = alternative.buildability || deriveAlternativeBuildability(alternative);
  const costRisk = alternative.costRisk || deriveAlternativeCostRisk(alternative);
  if (priority === "En ekonomik") {
    return `${focus} tarafinda iyilesme saglarken maliyet riskini daha kontrollu tutar.`;
  }
  if (priority === "En karakterli") {
    return `${focus} tarafinda mekana daha belirgin kimlik katar; sunum etkisi daha gucludur.`;
  }
  if (buildability === "Kolay" && costRisk !== "Yuksek") {
    return `${focus} tarafinda dengeli fark yaratir; uygulanabilirlik ve butce tarafinda guvenli bir yon sunar.`;
  }
  return `${focus} tarafinda belirgin iyilesme sunar; tasarim etkisi ile uygulama dengesi birlikte okunabilir.`;
}

function normalizeAlternativeState(alternative = {}) {
  const normalized = {
    reviewStatus: "draft",
    isBaseAlternative: false,
    reasonWhy: "",
    budgetImpact: "",
    differenceSummary: "",
    designIntentPrompt: "",
    colorDNA: "",
    suggestedColors: [],
    dnaDecisions: [],
    priorityLabel: "",
    priorityBadge: "neutral",
    costRisk: "",
    buildability: "",
    selectionReason: "",
    siteImpact: "",
    ...alternative,
  };
  normalized.dnaDecisions = normalizeAlternativeDNADecisions(normalized.dnaDecisions, normalized);
  normalized.suggestedColors = normalizeSuggestedColors(normalized.suggestedColors?.length ? normalized.suggestedColors : buildFallbackSuggestedColors(normalized));
  normalized.colorDNA = normalized.colorDNA || buildAlternativeColorDNALabel(normalized);
  normalized.differenceSummary = String(normalized.differenceSummary || "").trim() || summarizeAlternativeDifference(normalized);
  normalized.designIntentPrompt = String(normalized.designIntentPrompt || "").trim() || buildAlternativeTextDesignIntent(normalized);
  normalized.costRisk = normalized.costRisk || deriveAlternativeCostRisk(normalized);
  normalized.buildability = normalized.buildability || deriveAlternativeBuildability(normalized);
  normalized.siteImpact = normalized.siteImpact || deriveAlternativeSiteImpact(normalized);
  normalized.selectionReason = String(normalized.selectionReason || "").trim() || summarizeAlternativeSelectionReason(normalized);
  if (normalized.reviewStatus === "rejected") normalized.selected = false;
  return normalized;
}

function normalizeAlternativeResourcePool(pool = {}) {
  const normalizeProvenance = (provenance = {}, fallbackSource = "user") => ({
    source: ["ai", "user", "fallback"].includes(provenance?.source) ? provenance.source : fallbackSource,
    dataInputs: Array.isArray(provenance?.dataInputs) ? provenance.dataInputs.filter(Boolean) : [],
    affectedSurfaces: Array.isArray(provenance?.affectedSurfaces) ? provenance.affectedSurfaces.filter(Boolean) : [],
    alternativeImpact: String(provenance?.alternativeImpact || "").trim(),
  });
  const normalizeItem = (item, fallbackType) => ({
    id: item?.id || `pool_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
    type: item?.type || fallbackType,
    title: String(item?.title || "").trim(),
    summary: String(item?.summary || "").trim(),
    body: String(item?.body || "").trim(),
    sourceLabel: String(item?.sourceLabel || "").trim(),
    dbItemId: item?.dbItemId || "",
    areaM2: item?.areaM2 || 0,
    budgetImpact: item?.budgetImpact || null,
    meta: item?.meta && typeof item.meta === "object" ? item.meta : {},
    provenance: normalizeProvenance(item?.provenance, fallbackType === "lighting" ? "ai" : "user"),
    createdAt: item?.createdAt || new Date().toISOString(),
  });
  return {
    materials: Array.isArray(pool?.materials) ? pool.materials.map((item) => normalizeItem(item, "material")) : [],
    colorNotes: Array.isArray(pool?.colorNotes) ? pool.colorNotes.map((item) => normalizeItem(item, "color")) : [],
    lightingSuggestions: Array.isArray(pool?.lightingSuggestions) ? pool.lightingSuggestions.map((item) => normalizeItem(item, "lighting")) : [],
    strategyNotes: Array.isArray(pool?.strategyNotes) ? pool.strategyNotes.map((item) => normalizeItem(item, "strategy")) : [],
  };
}

function getPoolProvenanceLabel(provenance = {}) {
  if (provenance.source === "ai") return "AI analiz";
  if (provenance.source === "fallback") return "Fallback";
  return "Kullanici karari";
}

function formatPoolDataInputs(inputs = []) {
  if (!inputs.length) return "Veri belirtilmedi";
  const labels = { render: "render", plan: "plan", segmentation: "segmentasyon", analysis: "analiz" };
  return inputs.map((item) => labels[item] || item).join(" + ");
}

function renderPoolProvenanceMarkup(item) {
  const provenance = item?.provenance || {};
  const lines = [
    `Kaynak: ${getPoolProvenanceLabel(provenance)}`,
    `Veri: ${formatPoolDataInputs(provenance.dataInputs || [])}`,
  ];
  if (provenance.affectedSurfaces?.length) {
    lines.push(`Etki: ${provenance.affectedSurfaces.join(", ")}`);
  }
  if (provenance.alternativeImpact) {
    lines.push(`Alternatif etkisi: ${provenance.alternativeImpact}`);
  }
  return lines.map((line) => `<p class="resource-pool-meta">${escapeHtml(line)}</p>`).join("");
}

function normalizeAlternativeBoardState(board = {}) {
  const assignments = board?.assignments && typeof board.assignments === "object" ? board.assignments : {};
  return {
    assignments: Object.fromEntries(Object.entries(assignments).map(([key, value]) => [key, Array.isArray(value) ? value.filter(Boolean) : []])),
  };
}

function ensureAlternativeResourcePool() {
  appState.alternativeResourcePool = normalizeAlternativeResourcePool(appState.alternativeResourcePool);
  return appState.alternativeResourcePool;
}

function ensureAlternativeBoard() {
  appState.alternativeBoard = normalizeAlternativeBoardState(appState.alternativeBoard);
  return appState.alternativeBoard;
}

function getAlternativePoolItems() {
  const pool = ensureAlternativeResourcePool();
  return [
    ...pool.materials.map((item) => ({ ...item, poolType: "material", poolLabel: "Malzeme" })),
    ...pool.colorNotes.map((item) => ({ ...item, poolType: "color", poolLabel: "Renk" })),
    ...pool.lightingSuggestions.map((item) => ({ ...item, poolType: "lighting", poolLabel: "Isik" })),
    ...pool.strategyNotes.map((item) => ({ ...item, poolType: "strategy", poolLabel: "Strateji" })),
  ];
}

function getAlternativeBoardAssignedIds() {
  const board = ensureAlternativeBoard();
  return Object.values(board.assignments).flat().filter(Boolean);
}

function getAlternativeBoardPoolItems() {
  const assigned = new Set(getAlternativeBoardAssignedIds());
  return getAlternativePoolItems().filter((item) => !assigned.has(item.id));
}

function getAlternativeBoardItemsForAlternative(altId) {
  const board = ensureAlternativeBoard();
  const ids = board.assignments[altId] || [];
  const itemMap = new Map(getAlternativePoolItems().map((item) => [item.id, item]));
  return ids.map((id) => itemMap.get(id)).filter(Boolean);
}

function buildAlternativeBoardSummary(alternative) {
  const items = getAlternativeBoardItemsForAlternative(alternative.id);
  if (!items.length) return "";
  return items.map((item) => `${item.poolLabel}: ${item.title}`).join(" | ");
}

function moveAlternativeBoardItem(itemId, targetAltId = "pool") {
  const board = ensureAlternativeBoard();
  Object.keys(board.assignments).forEach((altId) => {
    board.assignments[altId] = (board.assignments[altId] || []).filter((id) => id !== itemId);
  });
  if (targetAltId !== "pool") {
    board.assignments[targetAltId] = board.assignments[targetAltId] || [];
    if (!board.assignments[targetAltId].includes(itemId)) {
      board.assignments[targetAltId].push(itemId);
    }
    appState.selectedAlternativeId = targetAltId;
  }
  saveState();
  renderAlternatives();
}

function getColorAdjustmentParts(grade = {}) {
  const normalized = normalizeColorGrade(grade);
  const labels = {
    s: "doygunluk",
    l: "aciklik",
    temperature: "sicaklik",
    contrast: "kontrast",
  };
  return COLOR_GRADE_FIELDS
    .filter((field) => Math.abs(Number(normalized[field] || 0)) > 0.25)
    .map((field) => `${labels[field]} ${normalized[field] > 0 ? "+" : ""}${Math.round(normalized[field])}`);
}

function buildColorDecisionPoolItem(scope = "global") {
  const pool = ensureAlternativeResourcePool();
  const colorTool = normalizeColorToolState(appState.colorTool);
  const selectedRegion = scope === "local" ? getActiveColorRegion() : null;
  const localGrade = selectedRegion ? getTargetColorGrade(selectedRegion.targetIndex) : createEmptyColorGrade();
  const localTargetDecision = selectedRegion ? getTargetColorDecision(selectedRegion.targetIndex) : createEmptyTargetColorDecision();
  const globalParts = getColorAdjustmentParts(colorTool.globalGrade);
  const localParts = getColorAdjustmentParts(localGrade);
  const changedSurfaces = getColorSurfaceStats().filter((item) => hasVisibleColorGrade(getTargetColorGrade(item.targetIndex)) || hasActiveTargetColorDecision(getTargetColorDecision(item.targetIndex)));
  if (scope === "local" && !selectedRegion) return null;
  if (scope === "global" && !globalParts.length && !changedSurfaces.length && !hasActiveTargetColorDecision(colorTool.globalTargetColor)) return null;
  if (scope === "local" && !localParts.length && !hasActiveTargetColorDecision(localTargetDecision)) return null;

  const title = scope === "local"
    ? `${selectedRegion.label} renk karari`
    : `Global renk karari ${pool.colorNotes.length + 1}`;
  const summary = scope === "local"
    ? `${selectedRegion.label} icin lokal renk duzenleme notu.`
    : `${changedSurfaces.length ? changedSurfaces.map((item) => item.label).slice(0, 4).join(", ") : "Tum mekan"} uzerindeki renk kararlarini yazar.`;
  const lines = [];
  if (scope === "global" && globalParts.length) {
    lines.push(`Global ince ayar: ${globalParts.join(", ")}.`);
  }
  if (scope === "global" && hasActiveTargetColorDecision(colorTool.globalTargetColor)) {
    lines.push(`Tum mekan hedef renk: ${colorTool.globalTargetColor.hex}, yogunluk %${Math.round(colorTool.globalTargetColor.strength * 100)}, aciklik ${Math.round(colorTool.globalTargetColor.lightness)}.`);
  }
  if (scope === "global" && changedSurfaces.length) {
    changedSurfaces.slice(0, 6).forEach((item) => {
      const targetParts = getColorAdjustmentParts(getTargetColorGrade(item.targetIndex));
      const targetDecision = getTargetColorDecision(item.targetIndex);
      const decisionBits = [];
      if (hasActiveTargetColorDecision(targetDecision)) {
        decisionBits.push(`hedef renk ${targetDecision.hex}`);
        decisionBits.push(`yogunluk %${Math.round(targetDecision.strength * 100)}`);
        if (targetDecision.lightness) decisionBits.push(`aciklik ${Math.round(targetDecision.lightness)}`);
      }
      if (targetParts.length) decisionBits.push(targetParts.join(", "));
      if (!decisionBits.length) return;
      lines.push(`${item.label}: ${decisionBits.join(", ")}. Yaklasik kod ${getApproxColorCode(item.previewHex)}.`);
    });
  }
  if (scope === "local" && selectedRegion) {
    const detailBits = [];
    if (hasActiveTargetColorDecision(localTargetDecision)) {
      detailBits.push(`hedef renk ${localTargetDecision.hex}`);
      detailBits.push(`yogunluk %${Math.round(localTargetDecision.strength * 100)}`);
      if (localTargetDecision.lightness) detailBits.push(`aciklik ${Math.round(localTargetDecision.lightness)}`);
    }
    if (localParts.length) detailBits.push(localParts.join(", "));
    lines.push(`${selectedRegion.label}: ${detailBits.join(", ")}.`);
    lines.push(`Yaklasik kod ${getApproxColorCode(getDecisionPreviewColorForTarget(selectedRegion.targetIndex))}, finish ${getFinishRecommendation(selectedRegion, getDecisionPreviewColorForTarget(selectedRegion.targetIndex))}.`);
    lines.push(`Komsu etki: ${getNeighborEffectNote(selectedRegion)}`);
  }
  return {
    id: `color_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
    type: "color",
    title,
    summary,
    body: lines.join(" "),
    sourceLabel: scope === "local" && selectedRegion ? selectedRegion.label : "Renk Studyosu",
    meta: {
      scope,
      affectedLabels: scope === "local" && selectedRegion ? [selectedRegion.label] : changedSurfaces.map((item) => item.label),
      activeAiAlternativeId: colorTool.activeAiAlternativeId || "",
    },
    provenance: {
      source: colorTool.activeAiAlternativeId ? "ai" : "user",
      dataInputs: ["render", "segmentation"],
      affectedSurfaces: scope === "local" && selectedRegion ? [selectedRegion.label] : changedSurfaces.map((item) => item.label),
      alternativeImpact: scope === "local" && selectedRegion
        ? `${selectedRegion.label} uzerinde daha belirgin bir renk dili kurar.`
        : "Alternatiflerin genel renk DNA'sini ve vurgu dengesini etkiler.",
    },
    createdAt: new Date().toISOString(),
  };
}

function showQuestCompletionReward(hubKey) {
  const pool = ensureAlternativeResourcePool();
  const descriptions = {
    color: pool.colorNotes.map((item) => item.title).slice(0, 3).join(", "),
    material: pool.materials.map((item) => item.title).slice(0, 3).join(", "),
    lighting: pool.lightingSuggestions.map((item) => item.title).slice(0, 3).join(", "),
  };
  const details = descriptions[hubKey] || "";
  showAlert(
    `${HUB_BY_KEY[hubKey]?.navLabel || "Hub"} gorevi tamamlandi. Alternatiflerde kullanilacak kararlar: ${details || "hazir"}.`,
    "success",
  );
}

function addColorDecisionToAlternativePool(scope = "global") {
  const item = buildColorDecisionPoolItem(scope);
  if (!item) {
    showAlert("Alternatiflere gonderilecek renk karari bulunamadi. Once renk ayari yapin.", "warning");
    return;
  }
  let pool = ensureAlternativeResourcePool();
  const exists = pool.colorNotes.some((entry) => normalizeName(entry.title) === normalizeName(item.title) && normalizeName(entry.body) === normalizeName(item.body));
  if (exists) {
    showAlert("Bu renk karari zaten Alternatifler modulu icine eklendi.", "warning");
    return;
  }
  const wasComplete = getRequiredHubPoolProgress().color.complete;
  pool = ensureAlternativeResourcePool();
  pool.colorNotes.unshift(item);
  saveState();
  renderHubPanels();
  renderAnalizHubNav();
  renderAlternatives();
  renderPromptBuilder();
  const progress = getRequiredHubPoolProgress().color;
  if (!wasComplete && progress.complete) showQuestCompletionReward("color");
  else showAlert(`Renk gorevi tamamlandi. Havuza ${progress.count} renk karari eklendi.`, "success");
}

async function recordProjectMaterialUsage(detail) {
  if (!currentProject?.id || !detail?.selectedDbItem?.id) return;
  currentProject = createDefaultProjectRecord({
    ...currentProject,
    materialUsage: Array.isArray(currentProject.materialUsage) ? currentProject.materialUsage : [],
  });
  const exists = currentProject.materialUsage.some((entry) => entry.spaceId === appState.id && entry.dbItemId === detail.selectedDbItem.id);
  if (!exists) {
    currentProject.materialUsage.push({
      dbItemId: detail.selectedDbItem.id,
      spaceId: appState.id,
      spaceName: appState.name,
      category: detail.selectedDbItem.category,
      addedAt: new Date().toISOString(),
    });
    await saveProject(currentProject);
  }
}

async function addMaterialSuggestionToAlternativePool(region, suggestion) {
  if (!region || !suggestion?.selectedDbItem) {
    showAlert("Havuza eklenecek gecerli bir malzeme onerisi bulunamadi.", "warning");
    return;
  }
  appState.activeAnalizHub = "material";
  let pool = ensureAlternativeResourcePool();
  const dbItem = suggestion.selectedDbItem;
  const budgetImpact = suggestion.budgetImpact || null;
  const title = String(dbItem.name || suggestion.material || suggestion.title || "Malzeme onerisi").trim();
  const body = String(dbItem.profile?.note || suggestion.reason || suggestion.body || "").trim();
  const key = `${normalizeName(region.label || "")}:${normalizeName(dbItem.id || title)}`;
  const exists = pool.materials.some((entry) => `${normalizeName(entry.sourceLabel || "")}:${normalizeName(entry.dbItemId || entry.title || "")}` === key);
  if (exists) {
    showAlert("Bu malzeme onerisi zaten kullanilabilecek malzemeler havuzunda var.", "warning");
    return;
  }
  const wasComplete = getRequiredHubPoolProgress().material.complete;
  // Re-fetch pool reference because getRequiredHubPoolProgress normalizes and replaces the state object!
  pool = ensureAlternativeResourcePool();
  pool.materials.unshift({
    id: `material_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
    type: "material",
    title,
    dbItemId: dbItem.id,
    summary: `${region.label || "Secili bolge"} icin secilen malzeme karari`,
    body,
    sourceLabel: region.label || "Malzeme Hub",
    areaM2: Number(suggestion.areaInfo?.areaM2 || 0),
    budgetImpact: budgetImpact ? {
      perUnit: Number(budgetImpact.perUnit || 0),
      total: Number(budgetImpact.total || 0),
      posture: budgetImpact.budgetPosture || "balanced",
    } : null,
    meta: {
      category: dbItem.category || region.category || "",
      detectedMaterial: region.detectedMaterial || "",
      selectedMaterialFamily: dbItem.profile?.materialFamily || "",
    },
    provenance: {
      source: suggestion.provenance?.source || "user",
      dataInputs: ["cost-database", "segmentation"],
      affectedSurfaces: [region.label || "Secili bolge"],
      alternativeImpact: `${region.label || "Secili bolge"} icin malzeme dili, butce etkisi ve render prompt'una gidecek doku tanimini etkiler.`,
    },
    createdAt: new Date().toISOString(),
  });
  await recordProjectMaterialUsage(suggestion);
  saveState();
  renderHubPanelForKey("material");
  renderUnifiedHubSelectionInfo();
  renderUnifiedHubOverlay();
  renderAnalizHubNav();
  renderAlternatives();
  renderPromptBuilder();
  const progress = getRequiredHubPoolProgress().material;
  if (!wasComplete && progress.complete) showQuestCompletionReward("material");
  else showAlert(`Malzeme gorevi ilerledi. Havuza ${progress.count} malzeme onerisi eklendi.`, "success");
}

function addLightingSuggestionToAlternativePool(index) {
  const cached = getValidHubCache("lighting", null);
  const suggestions = getLightingScenarioSuggestions(cached);
  const suggestion = suggestions?.[Number(index)];
  const selectedRegion = getSelectedSegmentationRegion();
  const affectedSurfaces = selectedRegion?.label
    ? [selectedRegion.label]
    : ["Genel aydinlatma", "Odak akslari"];
  if (!suggestion) {
    showAlert("Eklenebilecek AI isik onerisi bulunamadi.", "warning");
    return;
  }
  let pool = ensureAlternativeResourcePool();
  const key = normalizeName(suggestion.title || suggestion.summary || "");
  const exists = pool.lightingSuggestions.some((item) => normalizeName(item.title || "") === key);
  if (exists) {
    showAlert("Bu isik onerisi zaten Tasarim ve Alternatif havuzuna eklendi.", "warning");
    return;
  }
  const wasComplete = getRequiredHubPoolProgress().lighting.complete;
  pool = ensureAlternativeResourcePool();
  pool.lightingSuggestions.unshift({
    id: `lighting_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
    type: "lighting",
    title: suggestion.title || `Isik Onerisi ${pool.lightingSuggestions.length + 1}`,
    summary: suggestion.summary || "AI tarafindan uretilen aydinlatma yonu.",
    body: suggestion.rationale || suggestion.prompt || "",
    sourceLabel: "Isik Hub",
    meta: { prompt: suggestion.prompt || "" },
    provenance: {
      source: "ai",
      dataInputs: ["render", "analysis"],
      affectedSurfaces,
      alternativeImpact: suggestion.summary || "Alternatiflerin atmosferini ve odak hiyerarsisini etkiler.",
    },
    createdAt: new Date().toISOString(),
  });
  saveState();
  renderHubPanels();
  renderAnalizHubNav();
  renderAlternatives();
  renderPromptBuilder();
  const progress = getRequiredHubPoolProgress().lighting;
  if (!wasComplete && progress.complete) showQuestCompletionReward("lighting");
  else showAlert(`Isik gorevi ilerledi. Havuza ${progress.count} isik onerisi eklendi.`, "success");
}

