function buildAlternativeResourcePoolPromptSummary() {
  const pool = ensureAlternativeResourcePool();
  const parts = [];
  if (pool.materials.length) {
    parts.push(`Malzeme havuzu: ${pool.materials.slice(0, 6).map((item) => `${item.sourceLabel || "Bolge"} icin ${item.title}`).join("; ")}.`);
  }
  if (pool.colorNotes.length) {
    parts.push(`Renk karar notlari: ${pool.colorNotes.slice(0, 4).map((item) => item.body || item.summary).filter(Boolean).join(" ")}.`);
  }
  if (pool.lightingSuggestions.length) {
    parts.push(`Isik atmosfer yonu: ${pool.lightingSuggestions.slice(0, 4).map((item) => {
      const region = item.provenance?.affectedSurfaces?.[0] || "genel";
      const effect = getLightingScenarioEffectTag(item);
      return `${region} icin ${effect}: ${item.summary}`;
    }).join("; ")}.`);
  }
  if (pool.strategyNotes.length) {
    parts.push(`Strateji notlari: ${pool.strategyNotes.slice(0, 4).map((item) => {
      const hubKey = item.meta?.hubKey;
      if (hubKey === "acoustics") {
        return `Akustik yonu: ${item.title}. ${item.summary}. ${item.body}`;
      }
      if (hubKey === "furniture") {
        const region = item.provenance?.affectedSurfaces?.[0] || "secili mobilya";
        return `${region} icin mobilya yonu: ${item.title}. ${item.body}`;
      }
      if (hubKey === "plan") {
        return `Plan stratejisi: ${item.title}. ${item.body || item.summary}`;
      }
      return `${item.sourceLabel || "Hub"} icin ${item.title}`;
    }).join("; ")}.`);
  }
  const evaluationLines = ["plan", "furniture", "acoustics"]
    .map((key) => getValidHubCache(key, null)?.summary)
    .filter(Boolean)
    .slice(0, 3);
  if (evaluationLines.length) {
    parts.push(`Degerlendirme notlari: ${evaluationLines.join(" ")}`);
  }
  return parts.join(" ");
}

function getAlternativeReviewProfile(alternative) {
  if (alternative.reviewStatus === "rejected") return { label: "Elendi", badge: "warning" };
  if (alternative.isBaseAlternative) return { label: "Baz Alindi", badge: "info" };
  if (alternative.reviewStatus === "kept" || alternative.selected) return { label: "Saklandi", badge: "success" };
  return { label: "Taslak", badge: "neutral" };
}

