function renderLightingInsights() {
  const cached = getValidHubCache("lighting", null);
  const suggestions = getLightingScenarioSuggestions(cached);
  const selectedRegion = getSelectedSegmentationRegion();
  const selectedText = normalizeName(`${selectedRegion?.label || ""} ${selectedRegion?.category || ""}`);
  const showContextNote = !!selectedRegion && /tavan|duvar|ceiling|wall|panel/.test(selectedText);
  const contextMarkup = showContextNote
    ? renderHubPanelSection("Secili Yuzey Ipuclari", `
      <div class="hub-tech-note lighting-context-note">
        ${buildLightingRecommendations(selectedRegion).slice(0, 3).map((item) => `
          <div class="hub-tech-item">
            <span class="hub-tech-label">${escapeHtml(item.title || "Yuzey Notu")}</span>
            <span class="hub-tech-value">${escapeHtml(item.body || "")}</span>
          </div>
        `).join("")}
      </div>
    `, "lighting-context-section")
    : "";
  return renderHubPanelSection("AI Insight Kartlari", `
    <div class="hub-eval-recommendations">
      ${suggestions.map((item, index) => `
        <div class="hub-eval-rec-item lighting-scenario-card">
          <div class="hub-eval-rec-head">
            <strong>${escapeHtml(item.title || `Senaryo ${index + 1}`)}</strong>
            <span class="badge neutral">${escapeHtml(getLightingScenarioEffectTag(item))}</span>
          </div>
          <p>${escapeHtml(item.summary || item.prompt || "")}</p>
          <p class="resource-pool-meta">${escapeHtml(getLightingScenarioDeltaSummary(item))}</p>
          ${item.rationale ? `<p class="resource-pool-meta">${escapeHtml(item.rationale)}</p>` : ""}
          <div class="hub-tool-actions lighting-scenario-actions">
            <button type="button" class="ghost-button small-button" onclick="generateLightingScenarioFromSuggestion(${index})">Gorseli Uret</button>
            <button type="button" class="ghost-button small-button" onclick="addLightingSuggestionToAlternativePool(${index})">Havuza Ekle</button>
          </div>
        </div>
      `).join("")}
    </div>
  `) + contextMarkup;
}

function renderLightingScenarioGallery() {
  const scenarios = (appState.lightingScenarios || [])
    .map((scenario, index) => (scenario?.imageUrl ? { ...scenario, _sourceIndex: index } : null))
    .filter(Boolean);
  if (!scenarios.length) return "";
  return renderHubPanelSection("Uretilen Senaryolar", `
    <div class="lighting-gallery-grid">
      ${scenarios.map((scenario, index) => `
        <article class="lighting-gallery-thumb">
          <button type="button" class="lighting-gallery-preview" onclick="openLightingScenarioGallery(${scenario._sourceIndex})" aria-label="${escapeHtml((scenario.title || `Senaryo ${index + 1}`) + " buyuk goster")}">
            <img src="${escapeHtml(scenario.imageUrl)}" alt="${escapeHtml(scenario.title || `Isik Senaryosu ${index + 1}`)}" />
          </button>
          <div class="lighting-gallery-caption">
            <strong>${escapeHtml(scenario.title || `Senaryo ${index + 1}`)}</strong>
            <span>${escapeHtml(new Date(scenario.createdAt || Date.now()).toLocaleString("tr-TR", { hour: "2-digit", minute: "2-digit" }))}</span>
          </div>
          <div class="hub-tool-actions lighting-scenario-actions">
            <button type="button" class="ghost-button small-button" onclick="openLightingScenarioGallery(${scenario._sourceIndex})">Buyuk Ac</button>
            <button type="button" class="ghost-button small-button" onclick="downloadLightingScenario(${scenario._sourceIndex})">Indir</button>
          </div>
        </article>
      `).join("")}
    </div>
  `, "lighting-gallery-section");
}

