function getPlanInsightCards() {
  const context = inferSceneProgramContext();
  const type = context.primaryType;
  if (type === "konferans" || type === "egitim" || type === "toplanti") {
    return [
      { title: "Sahne ve odak aksini sabitleyin", body: "Oturum bloklari ile ekran/sunum duvari arasindaki gorus hattinin her sirada korunmasi, plan kararini belirleyen ana kalite unsurudur." },
      { title: "Projeksiyon ve gorus mesafesini dogrulayin", body: "Arka siralarda okunurlugu dusuren mesafeler ve fazla dik oturum acilari sunum performansini zayiflatabilir." },
      { title: "Cikis kapasitesi ve servis ceplerini koruyun", body: "Toplu kullanimli mekanlarda ana cikislar, yan gecisler ve servis nişleri oturum yogunlugundan bagimsiz rahat okunmali." },
    ];
  }
  if (type === "yemekhane" || type === "cafeterya") {
    return [
      { title: "Servis hattini daraltmayin", body: "Masa yogunlugu artarken servis-akis bandinin net ve takilmadan okunmasi tum mekan performansini belirler." },
      { title: "Mutfak veya hazirlik baglantisini temiz tutun", body: "Tasima rotalari ve masa cepleri birbiriyle carpisirsa hem hizmet hizi hem kullanici konforu duser." },
      { title: "Oturum yogunlugunu ritimle dengeleyin", body: "Her masayi maksimum doldurmak yerine nefes alan gecis cepleri ve farkli oturum cepleri kurmak daha saglikli olur." },
    ];
  }
  if (type === "ofis") {
    return [
      { title: "Is istasyonu araliklarini netlestirin", body: "Calisma bloklari arasindaki gecis genislikleri ve sandalye cekme mesafeleri verimli kullanimi belirler." },
      { title: "Toplanti erisimi ve sessiz alan dengesini kurun", body: "Odakli calisma ile hizli toplantilar ayni aks uzerinde carpisiyorsa plan performansi zayiflar." },
      { title: "Dogal isik dagilimini bloklamayin", body: "Yuksek hacimli depolama veya bolucu elemanlar pencere aksini kesiyorsa calisma kalitesi dogrudan etkilenir." },
    ];
  }
  return [
    { title: "Gorsel odagi sabitleyin", body: "Bekleme, lounge veya lobi gibi alanlarda ilk bakista anlasilan bir odak noktasi plan okumayi rahatlatir." },
    { title: "Oturum mahremiyeti ve dolasim dengesini kurun", body: "Serbest oturum cepleri ana dolasim aksinin ustune yikilmadan, rahat ama kontrollu bir dagilim kurmali." },
    { title: "Sirkulasyonu rahat tutun", body: "Mekan sakin akmali; yon degistiren cepler, ana aks ve bekleme cepleri birbirini bozmadan calismali." },
  ];
}

