function renderAcousticsInsights() {
  const regions = appState.segmentation?.regions || [];
  const surfaceData = estimateAcousticSurfaces(regions);
  const programContext = inferSceneProgramContext();
  const rt60 = estimateRT60(surfaceData);
  const sti = estimateSTI(rt60);
  const simulations = buildAcousticSimulations(surfaceData, rt60, sti, programContext.acousticTargets);
  const absorbersHtml = surfaceData.absorbers.map((s) => `<div class="hub-eval-rec-item"><strong>${escapeHtml(s.label)}</strong><p>NRC ${s.nrc.toFixed(2)} · ${Math.round(s.areaPercent)}% alan</p></div>`).join("");
  const reflectorsHtml = surfaceData.reflectors.slice(0, 5).map((s) => `<div class="hub-eval-rec-item"><strong>${escapeHtml(s.label)}</strong><p>NRC ${s.nrc.toFixed(2)} · ${Math.round(s.areaPercent)}% alan</p></div>`).join("");
  return renderHubPanelSection("Ses Emici Yuzeyler", `<div class="hub-eval-recommendations">${absorbersHtml || '<div class="hub-eval-rec-item"><p>Belirgin emici yuzey okunmadi.</p></div>'}</div>`)
    + renderHubPanelSection("Yansitici Yuzeyler", `<div class="hub-eval-recommendations">${reflectorsHtml || '<div class="hub-eval-rec-item"><p>Belirgin yansitici yuzey okunmadi.</p></div>'}</div>`)
    + renderHubPanelSection("Ne Yaparsam Ne Olur?", `
      <div class="hub-eval-recommendations acoustic-simulation-grid">
        ${simulations.map((sim, index) => `
          <div class="hub-eval-rec-item acoustic-simulation-card">
            <strong>${escapeHtml(sim.title)}</strong>
            <p>${escapeHtml(`RT60: ${sim.currentRT60} sn -> ~${sim.nextRT60} sn ${sim.rtBadge}`)}</p>
            <p>${escapeHtml(`STI: ${sim.currentSTI} -> ~${sim.nextSTI} ${sim.stiBadge}`)}</p>
            <p class="resource-pool-meta">${escapeHtml(sim.summary)}</p>
            <div class="hub-tool-actions">
              <button type="button" class="ghost-button small-button" onclick="addAcousticSimulationToPool(${index})">Bu karari sepete ekle</button>
            </div>
          </div>
        `).join("")}
      </div>
    `);
}

