function buildAcousticsHubPanelConfig() {
  const cached = getValidHubCache("acoustics", null);
  const programContext = inferSceneProgramContext();
  const acousticTargets = programContext.acousticTargets;
  const surfaceData = estimateAcousticSurfaces(appState.segmentation?.regions || []);
  const rt60 = estimateRT60(surfaceData);
  const sti = estimateSTI(rt60);
  const heuristicScore = estimateProgramAwareAcousticScore(rt60, sti, acousticTargets);
  return {
    projectHookMarkup: renderHubProjectHook("acoustics", { badge: "Konfor + Emilim" }),
    kicker: "Akustik Performans",
    score: cached?.score || heuristicScore.toFixed(1),
    source: getHubDisplaySource(cached?.source || HUB_SOURCE_HEURISTIC),
    timestamp: cached?._timestamp,
    summary: cached?.summary || `${programContext.summary} Akustik hedefler ${programContext.primaryLabel} standardina gore okunuyor.`,
    contextNote: `${cached?.spaceUseSummary || ""}${cached?.spaceUseSummary ? " " : ""}Akustik oncelik: ${programContext.acousticFocus}`,
    metrics: getHubMetricRows(cached, [
      { label: "RT60", value: `${rt60.toFixed(2)} sn`, percent: String(Math.min(100, rt60 * 40)), comment: describeAcousticTargets(acousticTargets, programContext.primaryLabel) },
      { label: "STI", value: sti.toFixed(2), percent: String(Math.round(sti * 100)), comment: `Hedef STI >= ${acousticTargets.stiMin.toFixed(2)}` },
    ]),
    insightMarkup: renderAcousticsInsights(),
    toolsMarkup: renderAcousticsTools(),
    positives: cached?.positives || [],
    positiveTitle: cached?.positiveTitle || "Iyi Durum",
    negatives: cached?.negatives || [],
    negativeTitle: cached?.negativeTitle || "Kritik",
    recommendations: cached?.recommendations || [],
    poolWidgetMarkup: renderHubPoolWidget("acoustics"),
    actionsMarkup: renderHubActions("acoustics"),
  };
}

