function buildSelectedMaterialRecommendations(selectedRegion) {
  const label = selectedRegion.detectedMaterial || selectedRegion.label;
  const normalized = normalizeName(label);
  if (/koltuk|sandalye|doseme|kumas/.test(normalized)) {
    return [
      { title: "Doseme ailesi alternatifleri", body: `${label} icin boucle etkili kumas, daha sik dokulu yalin kumas veya akustik destekli doseme ailesi denenebilir.` },
      { title: "Renkten once doku karar verin", body: "Bu tip yuzeyde algisal farki genelde yalniz renk degil, yuzeyin matligi ve dokusal derinligi belirler." },
      { title: "Temizlik ve dayanim filtresi", body: "Yogun kullanimli oturma gruplarinda asiri acik tonlara gecmeden once leke direnci ve asindirma sinifi kontrol edilmeli." },
    ];
  }
  if (/ahsap|tavan|panel/.test(normalized)) {
    return [
      { title: "Ahsapta ton merdiveni deneyin", body: `${label} icin mevcut damari koruyup sadece tonu acan veya sicakligi azaltan varyantlar daha rafine gorunur.` },
      { title: "Matlik / yarimatlik karari", body: "Ayni ahsap tonu, finish degistikce ciddi fark yaratir; renk degismeden once finish seviyesi test edilmeli." },
      { title: "Komşu yuzey gecisi", body: "Ahsap eleman komsu duvar ve isik rengiyle birlikte degerlendirilirse daha kontrollu sonuc verir." },
    ];
  }
  return [
    { title: "Finish once, sistem sonra", body: `${label} icin once ayni ailenin finish ve ton varyasyonlarini deneyin; tam malzeme degisimi ikinci faz olsun.` },
    { title: "Komsu malzemeyle birlikte karar verin", body: "Secili yuzey tek basina degil, en yakin komsu yuzeyle birlikte degerlendirilirse daha dogru okunur." },
    { title: "Numune bazli ilerleyin", body: "Bu kalem icin dijital preview sonrasi fiziksel numune ile parlaklik ve doku algisini mutlaka dogrulayin." },
  ];
}

