async function addNewAlternativeFromContext(sourceId, requestedCount = 1) {
  if (appState.alternatives.length >= MAX_ALTERNATIVES) {
    showAlert("Maksimum 15 alternatif sÄ±nÄ±rÄ±na ulaÅŸÄ±ldÄ±.", "warning");
    return;
  }
  const remainingCapacity = Math.max(0, MAX_ALTERNATIVES - appState.alternatives.length);
  const targetCount = Math.max(1, Math.min(Number(requestedCount || 1), remainingCapacity));
  if (!targetCount) {
    showAlert("Yeni alternatif icin yer kalmadi.", "warning");
    return;
  }
  const sourceAlternative = findAlternativeById(sourceId);
  try {
    const generatedAlternatives = await generateDesignAlternativesWithAI(
      `${buildUnifiedDesignPrompt({ includeProjectDirective: false })}\nReferans alternatif: ${sourceAlternative?.concept || ""}`,
      appState.quantityTakeoff,
      appState.scopeSelections,
      { min: targetCount, max: targetCount, target: targetCount, isSingle: targetCount === 1 },
    );
    appState.alternatives.push(...generatedAlternatives);
    appState.materialAtlas = createInitialState().materialAtlas;
    syncUnknownMaterialsFromAlternatives();
    saveState();
    renderAlternatives();
    renderProjectSummary();
    renderDatabaseTables();
    showAlert(targetCount === 1 ? "Baglamdan yeni bir alternatif turetildi." : `AI ${targetCount} yeni alternatif onerdi.`, "success");
  } catch (error) {
    showAlert(`Yeni alternatif uretilemedi: ${error.message || "AI baglantisi kontrol edilmeli."}`, "warning");
  }
}

function deleteAlternative(id) {
  appState.alternatives = appState.alternatives.filter((alternative) => alternative.id !== id);
  appState.approvedAlternatives = appState.approvedAlternatives.filter((approvedId) => approvedId !== id);
  appState.reportBasket = (appState.reportBasket || []).filter((entry) => entry.altId !== id);
  if (appState.reportData.selectedDesignId === id) appState.reportData.selectedDesignId = "";
  delete appState.generatedVisuals[id];
  appState.materialAtlas = createInitialState().materialAtlas;
  invalidateRefinedReportData();
  syncUnknownMaterialsFromAlternatives();
  saveState();
  renderAlternatives();
  renderVisualPanels();
  renderProjectSummary();
  renderDatabaseTables();
  renderReport();
}

