function downloadGeneratedImage(url, title) {
  if (!url) {
    showAlert("Indirilecek gorsel bulunamadi.", "warning");
    return;
  }

  const extension = inferImageExtension(url);
  const safeTitle = String(title || "designloop-render")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "") || "designloop-render";

  const link = document.createElement("a");
  link.href = url;
  link.download = `${safeTitle}.${extension}`;
  link.rel = "noopener";
  document.body.appendChild(link);
  link.click();
  link.remove();
}

function inferImageExtension(url) {
  if (typeof url !== "string") return "png";
  if (url.startsWith("data:image/")) {
    const match = url.match(/^data:image\/([a-zA-Z0-9+.-]+);/);
    if (!match) return "png";
    if (match[1] === "jpeg") return "jpg";
    if (match[1].includes("svg")) return "svg";
    return match[1];
  }
  const cleanUrl = url.split("?")[0].split("#")[0];
  const fileMatch = cleanUrl.match(/\.([a-zA-Z0-9]+)$/);
  return fileMatch ? fileMatch[1].toLowerCase() : "png";
}

