async function analyzeUploadedImagesWithAI(files, planFile) {
  const visionApiKey = getApiKeyForCapability("vision");
  if (!visionApiKey) {
    throw new Error("Analiz icin bir Gemini API key gerekli. AI Ayarlari'ndan vision veya ana Gemini key ekleyin.");
  }
  try {
    return await analyzeUploadedImagesWithBackend(files, planFile, visionApiKey);
  } catch (backendError) {
    console.error("Backend vision analysis failed, falling back to direct Gemini:", backendError);
  }
  try {
    return await analyzeUploadedImagesWithGemini(files, planFile, visionApiKey);
  } catch (error) {
    console.error("Vision analysis failed:", error);
    throw new Error(error?.message || "Vision analizi gercek API ile tamamlanamadi.");
  }
}

async function analyzeUploadedImagesWithBackend(files, planFile, apiKey) {
  const serializedFiles = await Promise.all((files || []).slice(0, 4).map(async (file) => ({
    name: file?.name || "",
    preview: await ensureDataUrlPreview(file),
  })));
  const serializedPlan = planFile
    ? {
      name: planFile.name || "",
      preview: await ensureDataUrlPreview(planFile),
    }
    : null;

  const response = await fetch("/api/analyze", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      apiKey,
      files: serializedFiles.filter((file) => file.preview),
      planFile: serializedPlan?.preview ? serializedPlan : null,
      projectContext: buildProjectContextPayload(),
      models: {
        vision: resolveTaskModel("vision"),
      },
    }),
  });

  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(errorData.error || `Analiz API hatasi: ${response.status}`);
  }

  const result = await response.json();
  return {
    summary: {
      ...(result.summary || {}),
      briefOptionPools: normalizeBriefOptionPools(result.summary?.briefOptionPools),
      mode: "api",
    },
    quantityTakeoff: normalizeQuantityTakeoffItems(result.quantityTakeoff || [], result.recommendedScopeSelections),
    recommendedScopeSelections: normalizeScopeSelections(result.recommendedScopeSelections),
  };
}

async function generateDesignAlternativesWithAI(prompt, quantityData, scopeSelections, alternativeCountConfig) {
  const countRequest = normalizeAlternativeCountRequest(alternativeCountConfig);
  const brief = buildStructuredBriefContract(prompt, quantityData, scopeSelections, countRequest);
  const llmApiKey = getApiKeyForCapability("llm");
  if (!llmApiKey) {
    throw new Error("Alternatif uretimi icin bir Gemini API key gerekli.");
  }
  try {
    return await generateDesignAlternativesWithStructuredPipeline(brief, quantityData, scopeSelections, countRequest, llmApiKey);
  } catch (error) {
    console.error("Alternative generation failed:", error);
    throw new Error(error?.message || "Alternatif uretimi gercek API ile tamamlanamadi.");
  }
}

async function generateDesignAlternativesWithStructuredPipeline(brief, quantityData, scopeSelections, countRequest, apiKey) {
  const conceptAlternatives = await generateConceptAlternativesWithGemini(brief, quantityData, countRequest, apiKey);
  let resolvedAlternatives = await resolveAlternativeDNAsWithGemini(brief, conceptAlternatives, quantityData, scopeSelections, apiKey);
  let renderPackage = await composeAlternativeRenderPackageWithGemini(brief, resolvedAlternatives, apiKey);
  let mergedAlternatives = mergeStructuredAlternativePipeline(brief, conceptAlternatives, resolvedAlternatives, renderPackage, quantityData);
  let validation = validateStructuredAlternativePipeline(brief, mergedAlternatives, quantityData);

  if (validation.failed.length) {
    const retryConcepts = conceptAlternatives.filter((item) => validation.failed.some((failure) => failure.pipelineId === item.id));
    if (retryConcepts.length) {
      resolvedAlternatives = mergeResolvedAlternativeMaps(
        resolvedAlternatives,
        await resolveAlternativeDNAsWithGemini(brief, retryConcepts, quantityData, scopeSelections, apiKey),
      );
      renderPackage = mergeRenderPackageMaps(
        renderPackage,
        await composeAlternativeRenderPackageWithGemini(
          brief,
          resolvedAlternatives.filter((item) => retryConcepts.some((retry) => retry.id === item.id)),
          apiKey,
        ),
      );
      mergedAlternatives = mergeStructuredAlternativePipeline(brief, conceptAlternatives, resolvedAlternatives, renderPackage, quantityData);
      validation = validateStructuredAlternativePipeline(brief, mergedAlternatives, quantityData);
    }
  }

  return mergedAlternatives.map((alternative, index) => finalizeStructuredAlternative(alternative, quantityData, index));
}

function generateDesignAlternativesLocallyFromPipeline(brief, quantityData, scopeSelections, countRequest) {
  const conceptAlternatives = generateConceptAlternativesLocally(brief, quantityData, countRequest);
  const resolvedAlternatives = resolveAlternativeDNAsLocally(brief, conceptAlternatives, quantityData, scopeSelections);
  const renderPackage = composeAlternativeRenderPackageLocally(brief, resolvedAlternatives);
  const mergedAlternatives = mergeStructuredAlternativePipeline(brief, conceptAlternatives, resolvedAlternatives, renderPackage, quantityData);
  const repairedAlternatives = mergedAlternatives.map((alternative) => repairStructuredAlternativeLocally(alternative, quantityData));
  return repairedAlternatives.map((alternative, index) => finalizeStructuredAlternative(alternative, quantityData, index));
}

function buildStructuredBriefContract(prompt, quantityData, scopeSelections, alternativeCountConfig) {
  const countRequest = normalizeAlternativeCountRequest(alternativeCountConfig);
  const selections = appState.promptSelections || createInitialState().promptSelections;
  const scopedItems = (quantityData || []).filter((item) => item.inScope);
  const scopedScopeSelections = Object.fromEntries(Object.entries(scopeSelections || {}).filter(([, value]) => value));
  return {
    unifiedPrompt: buildUnifiedDesignPrompt({ includeProjectDirective: false }),
    userPrompt: prompt,
    designDirection: resolvePromptSelectionLabel("designDirection", selections.designDirection, selections.designDirectionCustom),
    spatialProblem: resolvePromptSelectionLabel("spatialProblem", selections.spatialProblem, selections.spatialProblemCustom),
    palette: resolvePromptSelectionLabel("palette", selections.palette, selections.paletteCustom),
    globalColorPalette: getGlobalColorPaletteState(),
    styleGoal: resolvePromptSelectionLabel("styleGoal", selections.styleGoal, selections.styleGoalCustom),
    budgetProfile: getBudgetRangeProfile(),
    aggressivenessProfile: getAggressivenessRangeProfile(),
    alternativeCountProfile: getAlternativeCountRangeProfile(countRequest),
    referenceRender: getSelectedReferenceRender()?.name || "",
    renderNames: appState.uploadedRenders.map((file) => file.name),
    planName: appState.uploadedPlan?.name || "",
    scopedItems: scopedItems.map((item) => ({
      element: item.element,
      unit: item.unit,
      quantity: item.quantity,
      action: item.designAction,
      formDNA: item.formDNA,
      materialDNA: item.materialDNA,
      colorDNA: item.colorDNA,
      colorSource: item.colorSource || "local",
      note: item.note,
    })),
    scopeSelections: scopedScopeSelections,
    dnaLocks: summarizeDNALocks(scopedItems),
  };
}

async function buildGeminiDesignContextParts(text) {
  const renderParts = await resolveInlineDataParts(appState.uploadedRenders.slice(0, 4));
  const planParts = await resolveInlineDataParts([appState.uploadedPlan]);
  return [
    { text },
    ...renderParts,
    ...planParts,
  ];
}

function buildConceptGenerationPrompt(brief, quantityData, countRequest) {
  const alternativeCountInstruction = countRequest.isSingle
    ? `Tam olarak ${countRequest.target} alternatif don.`
    : `Minimum ${countRequest.min}, maksimum ${countRequest.max} alternatif don. Eger ${countRequest.max}. alternatif oncekilerden anlamli bicimde ayrismiyorsa ${countRequest.min} alternatifte kal. Sadece gercekten yeni deger katan alternatifleri ekle.`;
  return [
    buildProjectContextDirective(buildProjectContextPayload(), "konsept alternatifi uretimi"),
    "Bir ic mimari konsept ajani olarak calis.",
    "Yuklenen render ve planlari oku, sadece alternatiflerin ana fikrini ve hikayesini kur.",
    "Teknik cozumleme, dnaDecisions, malzeme listesi veya render promptu yazma.",
    `Birlesik brief: ${brief.unifiedPrompt}`,
    `Kullanici promptu: ${brief.userPrompt}`,
    `Kapsamdaki elemanlar: ${JSON.stringify(brief.scopedItems.map((item) => item.element))}.`,
    `Butce: ${brief.budgetProfile.label}. Mudahale: ${brief.aggressivenessProfile.label}. Alternatif hedefi: ${brief.alternativeCountProfile.label}.`,
    "Sadece JSON don.",
    'Beklenen JSON: {"conceptAlternatives":[{"id":"A1","title":"","concept":"","reasonWhy":"","differenceSummary":"","budgetPosture":"","statusLabel":""}]}',
    alternativeCountInstruction,
    "Alternatifler birbirinden anlamli bicimde ayrissin; sadece baslik degistirme.",
    "Konsept en fazla 2 cumle, differenceSummary tek cümle olsun.",
  ].join(" ");
}

async function generateConceptAlternativesWithGemini(brief, quantityData, countRequest, apiKey) {
  const model = resolveTaskModel("concept");
  const promptText = buildConceptGenerationPrompt(brief, quantityData, countRequest);
  const parts = await buildGeminiDesignContextParts(promptText);
  const response = await callGeminiGenerateContent({
    apiKey,
    model,
    contents: [{ role: "user", parts }],
    generationConfig: { responseMimeType: "application/json" },
  });
  const responseText = extractTextFromGeminiResponse(response);
  const parsed = parseJsonResponse(responseText);
  recordDebugExchange("Concept Agent", { model, prompt: promptText, response: responseText, parsed });
  const items = Array.isArray(parsed.conceptAlternatives) ? parsed.conceptAlternatives : [];
  if (!items.length) throw new Error("Konsept ajani alternatif donmedi.");
  const normalizedItems = items.slice(0, countRequest.max).map((item, index) => ({
    id: item.id || `A${index + 1}`,
    title: item.title || "",
    concept: truncateConcept(item.concept || ""),
    reasonWhy: item.reasonWhy || "",
    differenceSummary: item.differenceSummary || "",
    budgetPosture: item.budgetPosture || "",
    statusLabel: item.statusLabel || (index === 0 ? "Onerilen baslangic alternatifi" : "Taslak"),
  }));
  if (normalizedItems.length >= countRequest.min) return normalizedItems;
  const fallbackItems = generateConceptAlternativesLocally(brief, quantityData, countRequest).slice(normalizedItems.length, countRequest.min);
  return [...normalizedItems, ...fallbackItems].slice(0, countRequest.max);
}

function generateConceptAlternativesLocally(brief, quantityData, countRequest) {
  const theme = inferTheme(brief.userPrompt || brief.unifiedPrompt);
  return Array.from({ length: countRequest.target }).map((_, index) => {
    const profile = getAggressivenessProfileForIndex(index, countRequest.target);
    const title = buildAlternativeTitle(brief.userPrompt || brief.unifiedPrompt, theme, index, quantityData, profile);
    const concept = buildAlternativeConcept(brief.userPrompt || brief.unifiedPrompt, theme, index, quantityData, profile);
    return {
      id: `A${index + 1}`,
      title,
      concept,
      reasonWhy: summarizeAlternativeReason({ changedItems: quantityData.filter((item) => item.inScope).map((item) => item.element) }),
      differenceSummary: summarizeAlternativeDifference({ changedItems: quantityData.filter((item) => item.inScope).map((item) => item.element), colorDNA: brief.palette, costSummary: { designDeltaTotal: index * 1000, baseTotal: 10000 } }),
      budgetPosture: brief.budgetProfile.label,
      statusLabel: index === 0 ? "Onerilen baslangic alternatifi" : "Taslak",
    };
  });
}

function buildDNAResolutionPrompt(brief, conceptAlternatives, quantityData, scopeSelections) {
  const scopedElements = quantityData.filter((item) => item.inScope).map((item) => item.element);
  return [
    buildProjectContextDirective(buildProjectContextPayload(), "alternatif DNA cozumleme"),
    "Bir ic mimari malzeme ve DNA ajani olarak calis.",
    "Konsept alternatiflerini al ve sadece teknik karar setlerini cozumle.",
    "Her alternatif icin malzemeler, renk kimligi, onerilen palet, changedItems ve dnaDecisions don.",
    "Yeni konsept yazma; mevcut konseptlerin teknik acilimini yap.",
    `Birlesik brief: ${brief.unifiedPrompt}`,
    `Konsept alternatifleri: ${JSON.stringify(conceptAlternatives)}`,
    `Metraj verisi: ${JSON.stringify(quantityData.filter((item) => item.inScope))}`,
    `Kapsam secimleri: ${JSON.stringify(Object.fromEntries(Object.entries(scopeSelections || {}).filter(([, value]) => value)))}`,
    `DNA kilitleri: ${JSON.stringify(summarizeDNALocks(quantityData.filter((item) => item.inScope)))}`,
    briefGlobalPalettePromptLine(),
    "Renk hedefi: Her alternatif icin en az 3 iliskili renk uret; palet alternatifin karakterine gore kontrast ve sicaklik acisindan farklilasabilsin; renk kararlari malzeme diliyle uyumlu olsun; renklerin mekandaki rol ve dagilimi kullanici secimlerinden turetilsin.",
    "Sadece JSON don.",
    'Beklenen JSON: {"resolvedAlternatives":[{"id":"A1","changedItems":[],"preservedItems":[],"materials":[{"name":"","quantity":0}],"colorDNA":"","suggestedColors":[{"role":"","hex":"","name":""}],"budgetImpact":"","statusLabel":"","dnaDecisions":[{"element":"","reason":"","formOptions":["",""],"materialOptions":["",""],"colorOptions":[{"label":"","hexes":["#E8DED1","#C9B59A","#6E6052"]}]}]}]}',
    `Her alternatifte dnaDecisions listesi tam olarak ${scopedElements.length} eleman donsun ve her entry kapsamdaki elemanlardan biriyle birebir eslessin.`,
    "Malzemeler buildable ve ic mekan odakli olsun; renkler gercekci hex kodlariyla donsun.",
  ].join(" ");
}

async function resolveAlternativeDNAsWithGemini(brief, conceptAlternatives, quantityData, scopeSelections, apiKey) {
  const model = resolveTaskModel("dna");
  const promptText = buildDNAResolutionPrompt(brief, conceptAlternatives, quantityData, scopeSelections);
  const parts = await buildGeminiDesignContextParts(promptText);
  const response = await callGeminiGenerateContent({
    apiKey,
    model,
    contents: [{ role: "user", parts }],
    generationConfig: { responseMimeType: "application/json" },
  });
  const responseText = extractTextFromGeminiResponse(response);
  const parsed = parseJsonResponse(responseText);
  recordDebugExchange("DNA Resolution", { model, prompt: promptText, response: responseText, parsed });
  const items = Array.isArray(parsed.resolvedAlternatives) ? parsed.resolvedAlternatives : [];
  if (!items.length) throw new Error("DNA ajani alternatif cozumlemesi donmedi.");
  return items.map((item) => ({
    id: item.id,
    changedItems: Array.isArray(item.changedItems) ? item.changedItems : [],
    preservedItems: Array.isArray(item.preservedItems) ? item.preservedItems : [],
    materials: Array.isArray(item.materials) ? item.materials : [],
    colorDNA: item.colorDNA || "",
    suggestedColors: Array.isArray(item.suggestedColors) ? item.suggestedColors : [],
    budgetImpact: item.budgetImpact || "",
    statusLabel: item.statusLabel || "",
    dnaDecisions: Array.isArray(item.dnaDecisions) ? item.dnaDecisions : [],
  }));
}

function resolveAlternativeDNAsLocally(brief, conceptAlternatives, quantityData) {
  const theme = inferTheme(brief.userPrompt || brief.unifiedPrompt);
  const selectedScope = quantityData.filter((item) => item.inScope).map((item) => item.element);
  return conceptAlternatives.map((conceptAlternative, index) => {
    const materials = rotateArray(getBudgetAwareMaterialPool(theme, quantityData), index)
      .slice(0, 4)
      .map((name, materialIndex) => buildMaterialLine(name, quantityData, materialIndex, index));
    const seed = {
      id: conceptAlternative.id,
      title: conceptAlternative.title,
      concept: conceptAlternative.concept,
      materials,
      colorDNA: buildAlternativeColorDNALabel({ title: conceptAlternative.title, concept: conceptAlternative.concept, materials }),
      suggestedColors: buildFallbackSuggestedColors({ title: conceptAlternative.title, concept: conceptAlternative.concept, materials }),
      changedItems: selectedScope,
      preservedItems: [],
      dnaDecisions: [],
      statusLabel: conceptAlternative.statusLabel,
      budgetImpact: conceptAlternative.budgetPosture || "",
    };
    seed.dnaDecisions = normalizeAlternativeDNADecisions([], seed);
    return seed;
  });
}

function buildPromptComposerPrompt(brief, resolvedAlternatives) {
  return [
    buildProjectContextDirective(buildProjectContextPayload(), "render prompt paketi olusturma"),
    "Bir ic mimari prompt composer ajani olarak calis.",
    "Alternatifleri gorsel modelin anlayacagi kontrollu metinsel tasarim promptlarina cevir.",
    "Her alternatif icin designIntentPrompt ve renderPrompt don.",
    "Yeni tasarim karari ekleme; sadece mevcut alternatif kararlarini netlestir.",
    `Birlesik brief: ${brief.unifiedPrompt}`,
    `Referans render: ${brief.referenceRender || "yok"}`,
    `Cozumlenmis alternatifler: ${JSON.stringify(resolvedAlternatives)}`,
    "Sadece JSON don.",
    'Beklenen JSON: {"renderPackage":[{"id":"A1","designIntentPrompt":"","renderPrompt":""}]}',
    "designIntentPrompt Turkce olabilir; renderPrompt gorsel model icin daha teknik ve acik yazilsin.",
  ].join(" ");
}

async function composeAlternativeRenderPackageWithGemini(brief, resolvedAlternatives, apiKey) {
  const model = resolveTaskModel("promptComposer");
  const promptText = buildPromptComposerPrompt(brief, resolvedAlternatives);
  const parts = await buildGeminiDesignContextParts(promptText);
  const response = await callGeminiGenerateContent({
    apiKey,
    model,
    contents: [{ role: "user", parts }],
    generationConfig: { responseMimeType: "application/json" },
  });
  const responseText = extractTextFromGeminiResponse(response);
  const parsed = parseJsonResponse(responseText);
  recordDebugExchange("Prompt Composer", { model, prompt: promptText, response: responseText, parsed });
  const items = Array.isArray(parsed.renderPackage) ? parsed.renderPackage : [];
  if (!items.length) throw new Error("Prompt composer render paketi donmedi.");
  return items.map((item) => ({
    id: item.id,
    designIntentPrompt: String(item.designIntentPrompt || "").trim(),
    renderPrompt: String(item.renderPrompt || "").trim(),
  }));
}

function composeAlternativeRenderPackageLocally(brief, resolvedAlternatives) {
  return resolvedAlternatives.map((alternative) => {
    const designIntentPrompt = buildAlternativeTextDesignIntent(alternative);
    return {
      id: alternative.id,
      designIntentPrompt,
      renderPrompt: [
        `Referans renderdaki bakis acisini ve geometriyi koru.`,
        `${alternative.changedItems?.join(", ") || "Secili kapsam"} uzerinde kontrollu varyasyon uygula.`,
        `Malzeme yonu: ${(alternative.materials || []).map((material) => material.name).join(", ")}.`,
        `Renk DNA: ${alternative.colorDNA || buildAlternativeColorDNALabel(alternative)}.`,
      ].join(" "),
    };
  });
}

function mergeStructuredAlternativePipeline(brief, conceptAlternatives, resolvedAlternatives, renderPackage, quantityData) {
  const resolvedMap = new Map((resolvedAlternatives || []).map((item) => [item.id, item]));
  const renderMap = new Map((renderPackage || []).map((item) => [item.id, item]));
  return (conceptAlternatives || []).map((conceptAlternative) => {
    const resolved = resolvedMap.get(conceptAlternative.id) || {};
    const renderEntry = renderMap.get(conceptAlternative.id) || {};
    return {
      pipelineId: conceptAlternative.id,
      title: conceptAlternative.title,
      concept: conceptAlternative.concept,
      reasonWhy: conceptAlternative.reasonWhy,
      differenceSummary: conceptAlternative.differenceSummary,
      budgetImpact: resolved.budgetImpact || conceptAlternative.budgetPosture || "",
      changedItems: resolved.changedItems || quantityData.filter((item) => item.inScope).map((item) => item.element),
      preservedItems: resolved.preservedItems || [],
      statusLabel: resolved.statusLabel || conceptAlternative.statusLabel || "Taslak",
      materials: resolved.materials || [],
      colorDNA: resolved.colorDNA || "",
      suggestedColors: resolved.suggestedColors || [],
      dnaDecisions: resolved.dnaDecisions || [],
      designIntentPrompt: renderEntry.designIntentPrompt || "",
      visualPrompt: renderEntry.renderPrompt || "",
    };
  });
}

function validateStructuredAlternativePipeline(brief, alternatives, quantityData) {
  const scopedCount = quantityData.filter((item) => item.inScope).length;
  const failed = (alternatives || []).map((alternative) => {
    const reasons = [];
    if (!alternative.title) reasons.push("missing-title");
    if (!alternative.concept) reasons.push("missing-concept");
    if (!alternative.reasonWhy) reasons.push("missing-reason");
    if (!alternative.differenceSummary) reasons.push("missing-difference");
    if (!Array.isArray(alternative.materials) || !alternative.materials.length) reasons.push("missing-materials");
    if (!Array.isArray(alternative.dnaDecisions) || alternative.dnaDecisions.length !== scopedCount) reasons.push("invalid-dna-decisions");
    if (!alternative.designIntentPrompt) reasons.push("missing-design-intent");
    if (!alternative.visualPrompt) reasons.push("missing-render-prompt");
    return reasons.length ? { pipelineId: alternative.pipelineId, reasons } : null;
  }).filter(Boolean);
  return { failed };
}

function repairStructuredAlternativeLocally(alternative, quantityData) {
  const repaired = { ...alternative };
  if (!repaired.materials?.length) {
    const theme = inferTheme(buildUnifiedDesignPrompt());
    repaired.materials = rotateArray(getBudgetAwareMaterialPool(theme, quantityData), 0)
      .slice(0, 4)
      .map((name, materialIndex) => buildMaterialLine(name, quantityData, materialIndex, 0));
  }
  if (!repaired.colorDNA) repaired.colorDNA = buildAlternativeColorDNALabel(repaired);
  if (!repaired.suggestedColors?.length) repaired.suggestedColors = buildFallbackSuggestedColors(repaired);
  repaired.dnaDecisions = normalizeAlternativeDNADecisions(repaired.dnaDecisions, repaired);
  repaired.designIntentPrompt = repaired.designIntentPrompt || buildAlternativeTextDesignIntent(repaired);
  repaired.visualPrompt = repaired.visualPrompt || buildControlledVisualPrompt(repaired, repaired.revisionPrompt || "", appState.preserveGeometry);
  repaired.reasonWhy = repaired.reasonWhy || summarizeAlternativeReason(repaired);
  repaired.differenceSummary = repaired.differenceSummary || summarizeAlternativeDifference(repaired);
  repaired.budgetImpact = repaired.budgetImpact || summarizeAlternativeBudgetEffect({ ...repaired, costSummary: repaired.costSummary || calculateCostSummary(repaired.materials, quantityData) });
  return repaired;
}

function finalizeStructuredAlternative(alternative, quantityData, index) {
  const materials = (alternative.materials || []).slice(0, 6).map((material, materialIndex) => {
    const fallbackQuantity = estimateMaterialQuantity(material.name, quantityData, materialIndex, index);
    return hydrateMaterial(material.name, Number(material.quantity || fallbackQuantity), createId("mat"));
  });
  const merged = {
    id: createId("alt"),
    pipelineId: alternative.pipelineId || `A${index + 1}`,
    title: alternative.title || buildAlternativeTitle(buildUnifiedDesignPrompt(), inferTheme(buildUnifiedDesignPrompt()), index, quantityData, getAggressivenessProfileForIndex(index, Math.max(1, quantityData.length))),
    concept: truncateConcept(alternative.concept || buildAlternativeConcept(buildUnifiedDesignPrompt(), inferTheme(buildUnifiedDesignPrompt()), index, quantityData, getAggressivenessProfileForIndex(index, Math.max(1, quantityData.length)))),
    materials,
    costSummary: calculateCostSummary(materials, quantityData),
    changedItems: Array.isArray(alternative.changedItems) && alternative.changedItems.length ? alternative.changedItems : quantityData.filter((entry) => entry.inScope).map((entry) => entry.element),
    preservedItems: Array.isArray(alternative.preservedItems) ? alternative.preservedItems : [],
    statusLabel: alternative.statusLabel || (index === 0 ? "Onerilen baslangic alternatifi" : "Taslak"),
    selected: index === 0,
    reviewStatus: index === 0 ? "kept" : "draft",
    isBaseAlternative: index === 0,
    reasonWhy: alternative.reasonWhy || "",
    budgetImpact: alternative.budgetImpact || "",
    differenceSummary: alternative.differenceSummary || "",
    designIntentPrompt: alternative.designIntentPrompt || "",
    colorDNA: alternative.colorDNA || "",
    suggestedColors: normalizeSuggestedColors(Array.isArray(alternative.suggestedColors) ? alternative.suggestedColors : []),
    dnaDecisions: normalizeAlternativeDNADecisions(Array.isArray(alternative.dnaDecisions) ? alternative.dnaDecisions : [], { ...alternative, materials }),
    priorityLabel: alternative.priorityLabel || "",
    priorityBadge: alternative.priorityBadge || "neutral",
    costRisk: alternative.costRisk || "",
    buildability: alternative.buildability || "",
    revisionPrompt: "",
    visualPrompt: alternative.visualPrompt || "",
    visualSeed: index + 1,
    unknownMaterialCount: materials.filter((material) => material.status === "unknown").length,
  };
  return normalizeAlternativeState(seedAlternativeDecisionChoices(merged, index));
}

function mergeResolvedAlternativeMaps(baseItems = [], updateItems = []) {
  const merged = new Map(baseItems.map((item) => [item.id, item]));
  updateItems.forEach((item) => merged.set(item.id, item));
  return Array.from(merged.values());
}

function mergeRenderPackageMaps(baseItems = [], updateItems = []) {
  const merged = new Map(baseItems.map((item) => [item.id, item]));
  updateItems.forEach((item) => merged.set(item.id, item));
  return Array.from(merged.values());
}

async function generateVisualPromptWithAI(alternative, revisionPrompt, preserveGeometry) {
  if (alternative.visualPrompt && !revisionPrompt) {
    recordDebugExchange("Visual Prompt (Pipeline)", { source: "pipeline", prompt: alternative.visualPrompt, response: alternative.visualPrompt });
    return {
      mode: "pipeline",
      prompt: normalizeVisualEditPrompt(alternative.visualPrompt, alternative, revisionPrompt, preserveGeometry),
    };
  }
  const llmApiKey = getApiKeyForCapability("llm");
  if (!llmApiKey) {
    throw new Error("Gorsel prompt uretimi icin bir Gemini API key gerekli.");
  }
  try {
    const result = await generateVisualPromptWithGemini(alternative, revisionPrompt, preserveGeometry, llmApiKey);
    return {
      ...result,
      prompt: normalizeVisualEditPrompt(result.prompt, alternative, revisionPrompt, preserveGeometry),
    };
  } catch (error) {
    console.error("Visual prompt generation failed:", error);
    throw new Error(error?.message || "Gorsel prompt gercek API ile uretilemedi.");
  }
}

async function generateVisualFromAPI(alternative, visualPrompt) {
  try {
    return await generateVisualWithBackend(alternative, visualPrompt);
  } catch (backendError) {
    console.warn("Backend image generation failed, trying direct Gemini:", backendError);
  }
  const imageApiKey = getApiKeyForCapability("image");
  if (!imageApiKey) {
    throw new Error("Gorsel uretimi icin bir Gemini API key gerekli.");
  }
  try {
    return await generateVisualWithGemini(alternative, visualPrompt, imageApiKey);
  } catch (error) {
    console.error("Image generation failed:", error);
    throw new Error(error?.message || "Gorsel uretimi gercek API ile tamamlanamadi.");
  }
}

async function generateVisualWithBackend(alternative, visualPrompt) {
  const referenceRender = getSelectedReferenceRender();
  const response = await fetch("/api/generate-image", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      apiKey: getApiKeyForCapability("image") || getApiKeyForCapability("llm"),
      visualPrompt,
      preserveGeometry: appState.preserveGeometry,
      referenceImage: referenceRender ? { preview: await ensureDataUrlPreview(referenceRender), name: referenceRender.name } : null,
      models: {
        image: resolvePreferredVisualEditModel(),
      },
    }),
  });
  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(errorData.error || `Image API hatasi: ${response.status}`);
  }
  const result = await response.json();
  if (!result?.url) throw new Error("Backend image generation did not return a URL.");
  appState.apiSettings.connectedOnce = true;
  return {
    mode: "api",
    seed: result.seed || Math.floor(Math.random() * 5000),
    engine: result.engine || resolvePreferredVisualEditModel(),
    url: result.url,
  };
}

async function rewriteDesignPromptWithAI(prompt) {
  const llmApiKey = getApiKeyForCapability("llm");
  if (llmApiKey) {
    try {
      const model = resolveTaskModel("brief");
      const basePrompt = String(prompt || "").trim();
      const contextDirective = basePrompt.startsWith("[UST PROJE BAGLAMI:")
        ? ""
        : buildProjectContextDirective(buildProjectContextPayload(), "brief yeniden yazimi");
      const promptText = [
        contextDirective,
        "Asagidaki Turkce ic mimari tasarim briefini daha kisa, net ve kontrollu bir yonerge olarak yeniden yaz.",
        "Ayni tasarim niyetini koru, duzenlenebilir kapsami degistirme ve yeni tasarim fikirleri ekleme.",
        "Cevap olarak sadece yeniden yazilmis Turkce promptu duz metin olarak don.",
        `Prompt: ${basePrompt}`,
      ].join("\n");
      const response = await callGeminiGenerateContent({
        apiKey: llmApiKey,
        model,
        contents: [{
          role: "user",
          parts: [{
            text: promptText,
          }],
        }],
      });
      const rewritten = extractTextFromGeminiResponse(response).trim();
      recordDebugExchange("Prompt Rewrite", { model, prompt: promptText, response: rewritten });
      if (rewritten) return rewritten;
    } catch (error) {
      console.error("Prompt rewrite fallback to local:", error);
      showAlert("AI ile yeniden yazim tamamlanamadi, yerel sadelestirme kullanildi.", "warning");
    }
  }
  return [
    "Secilen referans gorsel ve metraj kararlarini baz alarak, kapsam dahilindeki elemanlar icin kontrollu ve uygulanabilir tasarim alternatifleri uret.",
    `Korunacaklar: ${appState.promptBuilder.preservedElements || "mevcut mimari omurga"}.`,
    `Degisecekler: ${appState.promptBuilder.changeElements || "secili kapsam kalemleri"}.`,
    `Stil hedefi: ${appState.promptBuilder.styleGoal || "mevcut mekana uyumlu ve sakin bir yenileme"}.`,
  ].join(" ");
}

async function generateExecutiveSummaryDraft() {
  const reportPlan = buildReportPlan();
  const baseSummary = buildReportExecutiveSummary(reportPlan.finalAlternatives);
  const selectedDesignTitle = reportPlan.selectedAlternative?.title || "Secim yapilmadi";
  const llmApiKey = getApiKeyForCapability("llm");
  if (ui.generateExecutiveSummaryButton) {
    ui.generateExecutiveSummaryButton.disabled = true;
    ui.generateExecutiveSummaryButton.textContent = "Taslak Uretiliyor...";
  }
  try {
    if (llmApiKey) {
      const model = resolveTaskModel("executiveSummary");
      const promptText = [
        "Sen deneyimli bir ic mimari rapor yazicinsisin.",
        "Asagidaki proje verilerini kullanarak profesyonel, musteriye yonelik Turkce bir yonetici ozeti yaz.",
        "2 kisa paragraftan olusan, net ve rafine bir ozet olsun.",
        "",
        `Sunum tonu: ${getReportPublishTypeLabel(reportPlan.publishType)}.`,
        "Secilen tasarim yonu, referans gorsel, atmosfer, renk paleti kararlari ve butce durumunu ozetle.",
        "",
        `Proje: ${appState.reportData.projectTitle}`,
        `Referans render: ${getSelectedReferenceRender()?.name || "Secilmedi"}`,
        `Secilen tasarim: ${selectedDesignTitle}`,
        `Tasarim briefi: ${buildUnifiedDesignPrompt()}`,
        `Alternatifler: ${JSON.stringify(reportPlan.finalAlternatives.map((item) => ({ title: item.title, budget: item.costSummary?.total, concept: item.concept, reason: item.reasonWhy })))}`,
        "",
        "Sadece ozet metnini don; JSON, baslik veya ek aciklama ekleme.",
      ].join("\n");
      const response = await callGeminiGenerateContent({
        apiKey: llmApiKey,
        model,
        contents: [{
          role: "user",
          parts: [{
            text: promptText,
          }],
        }],
      });
      const text = extractTextFromGeminiResponse(response).trim();
      recordDebugExchange("Executive Summary", { model, prompt: promptText, response: text });
      appState.reportData.overallEvaluation = text || baseSummary;
    } else {
      appState.reportData.overallEvaluation = `${baseSummary} Secilen tasarim ${selectedDesignTitle} olarak isaretlendi; referans perspektife sadik kalarak renk, atmosfer ve malzeme kararlarinda kontrollu ama okunabilir bir fark olusturur. Sunum modu ${getReportPublishTypeLabel(reportPlan.publishType).toLowerCase()} olarak ayarlandigi icin icerik yogunlugu buna gore dengelenir.`;
    }
    saveState();
    renderReport();
    showAlert("Yonetici ozeti taslagi olusturuldu. Son duzenlemeyi sen yapabilirsin.", "success");
  } catch (error) {
    console.error("Executive summary draft fallback:", error);
    appState.reportData.overallEvaluation = baseSummary;
    saveState();
    renderReport();
    showAlert("AI ozeti olusturulamadi, yerel taslak kullanildi.", "warning");
  } finally {
    if (ui.generateExecutiveSummaryButton) {
      ui.generateExecutiveSummaryButton.disabled = false;
      ui.generateExecutiveSummaryButton.textContent = "Yonetici Ozetini Taslak Olarak Uret";
    }
  }
}

async function analyzeUploadedImagesWithGemini(files, planFile, apiKey) {
  const model = resolveTaskModel("vision");
  const quantityPrompt = buildVisionAnalysisQuantityPrompt(files, planFile);
  const critiquePrompt = buildVisionAnalysisCritiquePrompt(files, planFile);

  const renderImageParts = await resolveInlineDataParts(files.slice(0, 4));
  const qtyImageParts = [
    ...renderImageParts,
    ...(await resolveInlineDataParts([planFile])),
  ];
  const critiqueImageParts = [
    ...renderImageParts,
    ...(await resolveInlineDataParts([planFile])),
  ];

  const qtyContents = [{
    role: "user",
    parts: [
      { text: quantityPrompt },
      ...qtyImageParts
    ],
  }];

  const critiqueContents = [{
    role: "user",
    parts: [
      { text: critiquePrompt },
      ...critiqueImageParts
    ],
  }];

  const [qtyResponse, critiqueResponse] = await Promise.all([
    callGeminiGenerateContent({ apiKey, model, contents: qtyContents, generationConfig: { responseMimeType: "application/json", temperature: 0.2 } }),
    callGeminiGenerateContent({ apiKey, model, contents: critiqueContents, generationConfig: { responseMimeType: "application/json" } })
  ]);

  const qtyText = extractTextFromGeminiResponse(qtyResponse);
  const critiqueText = extractTextFromGeminiResponse(critiqueResponse);
  recordDebugExchange("Vision Quantity", {
    model,
    prompt: quantityPrompt,
    response: qtyText,
    uploadedRenderNames: files.map((file) => file.name),
    planName: planFile?.name || "",
    inlineImageParts: renderImageParts.length,
  });
  recordDebugExchange("Vision Critique", {
    model,
    prompt: critiquePrompt,
    response: critiqueText,
    uploadedRenderNames: files.map((file) => file.name),
    planName: planFile?.name || "",
    inlineImageParts: critiqueImageParts.length,
  });

  const parsedQty = parseJsonResponse(qtyText);
  const parsedCritique = parseJsonResponse(critiqueText);

  return {
    summary: {
      changeableItems: parsedQty.changeableItems || ["Duvar yÃ¼zeyleri", "Tavan katmanÄ±", "AydÄ±nlatma omurgasÄ±"],
      detectedSurfaces: parsedQty.detectedSurfaces || [`Plan referansÄ±: ${planFile.name}`],
      briefOptionPools: normalizeBriefOptionPools(parsedCritique.briefOptionPools),
      confidenceNote: parsedQty.confidenceNote || "Gemini metraj analizi dÃ¶ndÃ¼.",
      userReviewRecommendation: parsedQty.userReviewRecommendation || "SÄ±nÄ±r koÅŸullarÄ± ve adetleri kontrol edin.",
      analysisNotes: `(Metraj & Estetik Parcali Sistem) ${files.length} render incelendi.`,
      designCritique: parsedCritique.designCritique || null,
      mode: "api",
    },
    quantityTakeoff: (parsedQty.quantityTakeoff || []).map((item) => ({
      ...createQuantityTakeoffItem({
        element: item.element,
        unit: item.unit,
        quantity: Number(item.quantity || 0),
        editable: true,
        location: item.location || "",
        note: item.note || "Vision tahmini.",
        visionConfidence: item.confidence,
        inScope: typeof item.inScope === "boolean" ? item.inScope : inferInScopeFromLegacySelection(item.element, parsedQty.recommendedScopeSelections),
        includeInSegmentation: typeof item.includeInSegmentation === "boolean" ? item.includeInSegmentation : true,
        visibleInRenderIndices: Array.isArray(item.visibleInRenderIndices) ? item.visibleInRenderIndices : [],
        segmentationReason: item.segmentationReason || "auto",
      }),
    })),
    recommendedScopeSelections: normalizeScopeSelections(parsedQty.recommendedScopeSelections),
  };
}

async function generateDesignAlternativesWithGemini(prompt, quantityData, scopeSelections, alternativeCountConfig, apiKey) {
  const countRequest = normalizeAlternativeCountRequest(alternativeCountConfig);
  const model = resolveTaskModel("concept");
  const promptText = buildAlternativeGenerationPrompt(prompt, quantityData, scopeSelections, countRequest);
  const parts = [
    { text: promptText },
    ...(await resolveInlineDataParts([...appState.uploadedRenders.slice(0, 4), appState.uploadedPlan])),
  ];
  const response = await callGeminiGenerateContent({
    apiKey,
    model,
    contents: [{
      role: "user",
      parts,
    }],
    generationConfig: { responseMimeType: "application/json" },
  });
  const responseText = extractTextFromGeminiResponse(response);
  const parsed = parseJsonResponse(responseText);
  recordDebugExchange("Alternative Generation", { model, prompt: promptText, response: responseText, parsed });
  const items = Array.isArray(parsed.alternatives) ? parsed.alternatives : [];
  if (!items.length) throw new Error("Gemini alternatif listesi dÃ¶nmedi.");

  return items.slice(0, countRequest.target).map((item, index) => {
    const aggressivenessProfile = getAggressivenessProfileForIndex(index, Math.max(items.length, countRequest.target));
    const materials = (item.materials || []).slice(0, 6).map((material, materialIndex) => {
      const fallbackQuantity = estimateMaterialQuantity(material.name, quantityData, materialIndex, index);
      return hydrateMaterial(material.name, Number(material.quantity || fallbackQuantity), createId("mat"));
    });
    const alternative = {
      id: createId("alt"),
      title: item.title || buildAlternativeTitle(prompt, inferTheme(prompt), index, quantityData, aggressivenessProfile),
      concept: truncateConcept(item.concept || buildAlternativeConcept(prompt, inferTheme(prompt), index, quantityData, aggressivenessProfile)),
      materials,
      designIntentPrompt: String(item.designIntentPrompt || "").trim(),
      costSummary: calculateCostSummary(materials, quantityData),
      changedItems: Array.isArray(item.changedItems) && item.changedItems.length ? item.changedItems : quantityData.filter((entry) => entry.inScope).map((entry) => entry.element),
      preservedItems: [],
      statusLabel: item.statusLabel || (index === 0 ? "Ã–nerilen baÅŸlangÄ±Ã§ alternatifi" : "Taslak"),
      selected: index === 0,
      reviewStatus: index === 0 ? "kept" : "draft",
      isBaseAlternative: index === 0,
      reasonWhy: item.reasonWhy || "",
      budgetImpact: item.budgetImpact || "",
      differenceSummary: item.differenceSummary || "",
      colorDNA: item.colorDNA || "",
      suggestedColors: normalizeSuggestedColors(Array.isArray(item.suggestedColors) ? item.suggestedColors : []),
      dnaDecisions: normalizeAlternativeDNADecisions(Array.isArray(item.dnaDecisions) ? item.dnaDecisions : [], { materials }),
      revisionPrompt: "",
      visualPrompt: "",
      visualSeed: index + 1,
      unknownMaterialCount: materials.filter((material) => material.status === "unknown").length,
    };
    if (!alternative.designIntentPrompt) alternative.designIntentPrompt = buildAlternativeTextDesignIntent(alternative);
    return seedAlternativeDecisionChoices(alternative, index);
  });
}

