    `<button type="button" class="pill-toggle pill-tone-${option.tone}${option.value === activeAction ? " active" : ""}" data-alt-pill="true" data-alt-id="${escapeHtml(altId)}" data-dna-element="${escapeHtml(elementName)}" data-dna-field="${fieldName}" data-pill-value="${option.value}">${option.label}</button>`
