function getSegmentationReasonLabel(reason, included) {
  if (reason === "user-included") return "Kullanici bu kalemi ozellikle segmentasyona dahil etti.";
  if (reason === "user-excluded") return "Kullanici bu kalemi segmentasyon disinda tuttu.";
  if (reason === "auto-all-non-decorative") return "Dekoratif olmayan tum kalemler otomatik olarak segmentasyona dahil edilir.";
  if (reason === "auto-decorative-excluded") return "Dekoratif urunler segmentasyon listesine alinmaz.";
  return included
    ? "Kalem dekoratif olmadigi icin segmentasyon hedefine otomatik dahil edildi."
    : "Kalem dekoratif olarak siniflandigi icin segmentasyon disinda tutuldu.";
}

