function refreshAlternativeMetrics(alternative) {
  alternative.materials = alternative.materials.map((material) => hydrateMaterial(material.name, material.quantity, material.id, {
    unit: material.unit,
    unitPrice: material.unitPrice,
    laborPrice: material.laborPrice,
    manualPrice: material.manualPrice,
  }));
  alternative.dnaDecisions = normalizeAlternativeDNADecisions(alternative.dnaDecisions, alternative);
  alternative.changedItems = alternative.dnaDecisions.filter((item) => item.inScope).map((item) => item.element);
  alternative.preservedItems = alternative.dnaDecisions.filter((item) => !item.inScope).map((item) => item.element);
  alternative.costSummary = calculateCostSummary(alternative.materials, appState.quantityTakeoff);
  alternative.unknownMaterialCount = alternative.materials.filter((material) => material.status === "unknown").length;
}

function syncUnknownMaterialsFromAlternatives() {
  const byName = new Map();
  buildUnknownTakeoffCostEntries().forEach((item) => {
    byName.set(item.id, item);
  });
  appState.alternatives.forEach((alternative) => {
    alternative.materials?.forEach((material) => {
      if (findDatabaseMaterial(material.name)) return;
      const key = `alt:${normalizeName(material.name)}|${normalizeName(material.unit)}`;
      if (!byName.has(key)) {
        byName.set(key, {
          id: key,
          name: material.name,
          unit: material.unit,
          estimatedPrice: material.unitPrice,
          labor: material.laborPrice,
          status: "Onay bekliyor",
          sourceType: "alternative",
        });
      }
    });
    refreshAlternativeMetrics(alternative);
  });
  appState.unknownMaterials = Array.from(byName.values());
}

