function hydrateMaterial(name, quantity, existingId, overrides = {}) {
  const knownEntry = findDatabaseMaterial(name);
  const estimated = estimateUnknownMaterialPricing(name, overrides.unit || "mÂ²");
  return {
    id: existingId || createId("mat"),
    dbItemId: knownEntry?.id || overrides.dbItemId || "",
    name,
    unit: knownEntry?.unit || overrides.unit || estimated.unit,
    quantity: roundValue(quantity),
    unitPrice: knownEntry?.unitPrice || (overrides.manualPrice ? overrides.unitPrice : estimated.unitPrice),
    laborPrice: knownEntry?.labor || (overrides.manualPrice ? overrides.laborPrice : Math.round(estimated.unitPrice * estimated.laborFactor)),
    status: knownEntry ? "known" : "unknown",
    manualPrice: !!overrides.manualPrice && !knownEntry,
    note: knownEntry ? "VeritabanÄ± eÅŸleÅŸmesi bulundu." : "VeritabanÄ±nda bulunamadÄ±, tahmini fiyat kullanÄ±ldÄ±.",
  };
}

function calculateCostSummary(materials, quantityTakeoff = appState.quantityTakeoff) {
  const takeoffSummary = calculateTakeoffCostSummary(quantityTakeoff);
  const designMaterials = materials.reduce((sum, material) => sum + material.unitPrice * material.quantity, 0);
  const designLabor = materials.reduce((sum, material) => sum + material.laborPrice * Math.max(1, material.quantity / 3), 0);
  const designDeltaTotal = Math.round(designMaterials + designLabor);
  const totalMaterials = Math.round(takeoffSummary.baseMaterials + designMaterials);
  const totalLabor = Math.round(takeoffSummary.baseLabor + designLabor);
  return {
    baseMaterials: takeoffSummary.baseMaterials,
    baseLabor: takeoffSummary.baseLabor,
    baseTotal: takeoffSummary.baseTotal,
    scopedBaseTotal: takeoffSummary.scopedBaseTotal,
    preservedBaseTotal: takeoffSummary.preservedBaseTotal,
    designDeltaMaterials: Math.round(designMaterials),
    designDeltaLabor: Math.round(designLabor),
    designDeltaTotal,
    materials: totalMaterials,
    labor: totalLabor,
    totalMaterials,
    totalLabor,
    total: Math.round(takeoffSummary.baseTotal + designDeltaTotal),
  };
}

function estimateMaterialQuantity(name, quantityData, materialIndex, alternativeIndex) {
  const floor = getQuantityValue(quantityData, "Zemin");
  const wall = getQuantityValue(quantityData, "Duvar");
  const ceiling = getQuantityValue(quantityData, "Tavan");
  const lighting = getQuantityValue(quantityData, "Aydinlatma");
  const furniture = getQuantityValue(quantityData, "Sabit Mobilya");
  const normalized = normalizeName(name);
  let value = floor;
  if (normalized.includes("duvar") || normalized.includes("panel") || normalized.includes("kagidi") || normalized.includes("cita")) value = wall * 0.45;
  if (normalized.includes("tavan") || normalized.includes("akustik")) value = ceiling * 0.7;
  if (normalized.includes("armatur") || normalized.includes("aplik")) value = Math.max(6, lighting * 0.55);
  if (normalized.includes("mobilya") || normalized.includes("raf")) value = Math.max(2, furniture);
  return value * (1 + materialIndex * 0.08 + alternativeIndex * 0.03);
}

function getQuantityValue(quantityData, label) {
  const items = Array.isArray(quantityData) ? quantityData : [];
  const normalizedLabel = normalizeName(label);
  const positiveItems = items.filter((item) => Number(item?.quantity || 0) > 0);
  const exact = positiveItems.find((item) => normalizeName(item.element) === normalizedLabel);
  if (exact) return Number(exact.quantity || 0) || 1;

  const includes = positiveItems.filter((item) => {
    const normalizedElement = normalizeName(item.element);
    return normalizedElement.includes(normalizedLabel) || normalizedLabel.includes(normalizedElement);
  });
  if (includes.length) {
    return Math.max(...includes.map((item) => Number(item.quantity || 0)).filter((value) => Number.isFinite(value) && value > 0));
  }

  const labelPatterns = {
    zemin: /(zemin|doseme|kaplama|parke|seramik|karo|porselen|mikrosement|epoksi)/,
    duvar: /(duvar|panel|cita|kagidi|boya|kaplama)/,
    tavan: /(tavan|asma tavan|akustik|baffle|tas ?yunu|metal tavan|panel)/,
    aydinlatma: /(aydinlatma|armatur|spot|aplik|lineer|led|sarkit|avize)/,
    "sabit mobilya": /(sabit mobilya|dolap|banko|tezgah|nis|ankastre|raf)/,
  };
  const pattern = labelPatterns[normalizedLabel];
  if (pattern) {
    const patterned = positiveItems.filter((item) => pattern.test(normalizeName(item.element)));
    if (patterned.length) {
      return Math.max(...patterned.map((item) => Number(item.quantity || 0)).filter((value) => Number.isFinite(value) && value > 0));
    }
  }
  return 1;
}

function inferTheme(prompt) {
  const lowerPrompt = prompt.toLowerCase();
  if (lowerPrompt.includes("japandi") || lowerPrompt.includes("ahÅŸap") || lowerPrompt.includes("sÄ±cak") || lowerPrompt.includes("ahsap")) return "japandi";
  if (lowerPrompt.includes("lobi") || lowerPrompt.includes("premium") || lowerPrompt.includes("otel")) return "hospitality";
  if (lowerPrompt.includes("endustriyel") || lowerPrompt.includes("industrial") || lowerPrompt.includes("ham")) return "industrial";
  if (lowerPrompt.includes("minimal") || lowerPrompt.includes("sade")) return "minimal";
  return "warm";
}

