function truncateConcept(text, maxLength = 170) {
  const clean = String(text || "").replace(/\s+/g, " ").trim();
  if (clean.length <= maxLength) return clean;
  const sentences = clean.match(/[^.!?]+[.!?]?/g)?.map((part) => part.trim()).filter(Boolean) || [];
  let composed = "";
  for (const sentence of sentences) {
    const next = `${composed} ${sentence}`.trim();
    if (next.length > maxLength) break;
    composed = next;
  }
  if (composed) return composed;
  const sliced = clean.slice(0, maxLength).trim();
  const boundary = Math.max(sliced.lastIndexOf("."), sliced.lastIndexOf("!"), sliced.lastIndexOf("?"));
  if (boundary > 40) return sliced.slice(0, boundary + 1).trim();
  return `${sliced.replace(/[,:;/-]+$/, "").trim()}.`;
}

function buildAlternativeTitle(prompt, theme, index, quantityData = [], profile = getAggressivenessRangeProfile()) {
  const changedItems = quantityData.filter((item) => item.inScope).map((item) => item.element);
  const primaryChange = changedItems[0] || "Tavan";
  const themeTitles = {
    japandi: ["Sakin Akustik Seri", "AhÅŸap Ritim Revizyonu", "YumuÅŸak Yemekhane KabuÄŸu"],
    hospitality: ["Kurumsal Yemekhane Plus", "Sessiz Tavan Paketi", "Premium Servis Salonu"],
    minimal: ["Temiz Hat Tavan", "Sade Akustik Katman", "NÃ¶tr Yenileme Serisi"],
    industrial: ["AÃ§Ä±k Plenum Editi", "Teknik Tavan Varyasyonu", "Grafik Akustik Sistem"],
    warm: ["DoÄŸal Doku Yenilemesi", "Yemekhane Konfor Paketi", "SÄ±cak Ton Revizyonu"],
  };
  return `${(themeTitles[theme] || themeTitles.minimal)[index % 3]} / ${primaryChange} / ${profile.shortLabel} ${index + 1}`;
}

function buildAlternativeConcept(prompt, theme, index, quantityData = [], profile = getAggressivenessRangeProfile()) {
  const budgetProfile = getBudgetRangeProfile();
  const changedItems = quantityData.filter((item) => item.inScope).map((item) => item.element.toLowerCase());
  const redesignCount = quantityData.filter((item) => item.designAction === "redesign").length;
  const improveCount = quantityData.filter((item) => (item.designAction || inferDesignAction(item.inScope)) === "improve").length;
  const preserveCount = quantityData.filter((item) => (item.designAction || inferDesignAction(item.inScope)) === "preserve").length;
  const ceilingHint = changedItems.some((item) => item.includes("tavan")) ? getCeilingDirection(index, profile) : "MekanÄ±n mevcut mimari ritmini koruyan daha kontrollÃ¼ bir iyileÅŸtirme Ã¶nerir.";
  const chairHint = changedItems.some((item) => item.includes("sandalye") || item.includes("mobilya")) ? getChairDirection(index, profile) : "Oturma dili ikincil seviyede tutulur.";
  const actionHint = redesignCount
    ? `${redesignCount} kalemde daha belirgin yeniden tasarim karari uygulanir.`
    : improveCount
      ? `${improveCount} kalemde kontrollu iyilestirme onerilir.`
      : "Degisiklikler minimum tutulur.";
  const preserveHint = preserveCount ? `${preserveCount} kalem bilincli olarak korunur.` : "";
  const rawConcept = `${ceilingHint} ${chairHint} ${actionHint} ${preserveHint} Butce dili ${budgetProfile.materialTone} tutulur.`;
  return truncateConcept(rawConcept, 240);
}

function buildAlternativeTextDesignIntent(alternative) {
  const changedItems = alternative.changedItems?.length ? alternative.changedItems.join(", ") : "secili kapsam elemanlari";
  const preservedItems = alternative.preservedItems?.length ? alternative.preservedItems.join(", ") : "mevcut geometri ve yerlesim";
  const materialLine = (alternative.materials || []).map((material) => {
    const affix = getMaterialEngine()?.buildMaterialPromptAffix(material.dbItemId);
    return affix ? `${material.name} (${affix})` : material.name;
  }).join(", ") || "referans gorselle uyumlu buildable malzemeler";
  const colorLine = normalizeSuggestedColors(alternative.suggestedColors || [])
    .map((color) => `${color.role} ${color.hex}`)
    .join(", ");
  const boardSummary = buildAlternativeBoardSummary(alternative);
  return [
    `Referans renderdaki geometriyi, bakis acisini ve yerlesimi koru.`,
    `${changedItems} uzerinde kontrollu bir tasarim varyasyonu kur.`,
    `${preservedItems} alanlarini oldugu gibi tut.`,
    `Malzeme dili: ${materialLine}.`,
    `Renk yonu: ${alternative.colorDNA || buildAlternativeColorDNALabel(alternative)}${colorLine ? `; onerilen palet ${colorLine}` : ""}.`,
    boardSummary ? `Karar havuzu secimleri: ${boardSummary}.` : "",
    `Konsept niyeti: ${alternative.concept || "mevcut mimari dili bozmadan okunur bir iyilestirme"}.`,
  ].join(" ");
}

function buildControlledVisualPrompt(alternative, revisionPrompt, preserveGeometry) {
  const reference = getSelectedReferenceRender();
  const profile = getAggressivenessRangeProfile();
  const budgetProfile = getBudgetRangeProfile();
  const changedItems = alternative.changedItems?.length ? alternative.changedItems.join(", ") : "selected scope elements";
  const preservedItems = alternative.preservedItems?.length ? alternative.preservedItems.join(", ") : "all remaining architecture and furniture";
  const materialLine = alternative.materials.map((material) => material.name).join(", ");
  const colorLine = normalizeSuggestedColors(alternative.suggestedColors || []).map((color) => `${color.role} ${color.hex}`).join(", ");
  const dnaLocks = summarizeDNALocks(appState.quantityTakeoff)
    .map((item) => `${item.element}: action=${item.action}, form=${item.formDNA}, material=${item.materialDNA}, color=${item.colorDNA}`)
    .join(" | ");
  const alternativeDecisionLine = summarizeAlternativeDecisionChoices(alternative);
  const revisionSegment = revisionPrompt ? `Additional revision note: ${revisionPrompt}.` : "";

  const preserveSection = [
    "PRESERVE:",
    "- Use the uploaded image as the same room and same viewpoint reference, not as a pixel-identical clone.",
    preserveGeometry
      ? "- Keep the same camera angle, framing, perspective, room dimensions, structural shell, and overall spatial composition."
      : "- Preserve the same overall camera angle and spatial composition; do not reinterpret the architecture.",
    `- Everything not listed under MODIFY must remain unchanged: ${preservedItems}.`,
    `- DNA locks to respect: ${dnaLocks}.`,
  ].join("\n");

  const modifySection = [
    "MODIFY:",
    `- Only redesign these elements: ${changedItems}.`,
    `- Design intent: ${alternative.concept}`,
    `- Detailed design direction: ${alternative.designIntentPrompt || buildAlternativeTextDesignIntent(alternative)}.`,
    `- Material direction: ${materialLine}.`,
    `- Color DNA: ${alternative.colorDNA || buildAlternativeColorDNALabel(alternative)}.${colorLine ? ` Palette: ${colorLine}.` : ""}`,
    `- Intervention level: ${profile.label}. Keep the design ${profile.openness} with ${profile.contrast}.`,
    alternativeDecisionLine ? `- User selections: ${alternativeDecisionLine}.` : "",
  ].filter(Boolean).join("\n");

  const styleSection = [
    "STYLE:",
    `- Budget expression: ${budgetProfile.label}. Material expression should feel ${budgetProfile.materialTone}.`,
    `- Overall design brief: ${buildUnifiedDesignPrompt()}`,
    "- Generate a controlled architectural renovation edit, not a brand-new concept image.",
    "- The final result must be visibly different from the source image at first glance.",
    "- No new walls, no crop change, no viewpoint change, and no unrelated decorative clutter.",
    "- If the edit feels too subtle, strengthen material contrast, color balance, lighting mood, and surface detailing on the allowed elements until the change is clearly noticeable.",
    "- Photorealistic rendering, realistic materials, buildable interior design solution.",
    revisionSegment,
  ].filter(Boolean).join("\n");

  return [preserveSection, "", modifySection, "", styleSection].join("\n");
}

