function resolvePreferredVisualEditModel() {
  const configured = String(appState.apiSettings?.imageModel || "").trim().toLowerCase();
  if (!configured) return "nano-banana";
  if (configured.includes("pro-image") || configured.includes("3-pro-image-preview")) return "nano-banana";
  return configured;
}

function normalizeVisualEditPrompt(prompt, alternative, revisionPrompt, preserveGeometry) {
  const basePrompt = String(prompt || "").trim();
  if (!basePrompt) return "";
  if (basePrompt.includes("VISIBLE EDIT RULES:")) return basePrompt;
  const changedItems = alternative.changedItems?.length ? alternative.changedItems.join(", ") : "selected scope elements";
  const materialLine = alternative.materials.map((material) => material.name).join(", ");
  const colorLine = normalizeSuggestedColors(alternative.suggestedColors || []).map((color) => `${color.role} ${color.hex}`).join(", ");
  const guardLines = [
    "VISIBLE EDIT RULES:",
    "- Do not return the original image unchanged.",
    "- The result must be noticeably different from the source image at first glance.",
    `- Make clearly visible edits only on these target elements: ${changedItems}.`,
    preserveGeometry
      ? "- Keep the same camera angle, framing, perspective, and architectural shell."
      : "- Keep the same room identity and overall composition.",
    materialLine ? `- Make the material direction clearly visible: ${materialLine}.` : "",
    colorLine ? `- Make the palette direction clearly visible: ${colorLine}.` : "",
    "- Show at least 3 perceptible edit anchors through material tone, color balance, lighting atmosphere, or surface detailing on the allowed areas.",
    "- If the result still feels too subtle, push the allowed edits one step stronger while staying photorealistic and buildable.",
    revisionPrompt ? `- Honor this revision note: ${revisionPrompt}.` : "",
  ].filter(Boolean).join("\n");
  return `${basePrompt}\n\n${guardLines}`.trim();
}

function createMoodboardPresetRecord(overrides = {}) {
  return {
    id: overrides.id || createId("preset"),
    name: overrides.name || "Yeni Moodboard Preseti",
    description: overrides.description || "",
    materials: Array.isArray(overrides.materials) ? overrides.materials : [],
    colors: Array.isArray(overrides.colors) ? overrides.colors : [],
    keywords: Array.isArray(overrides.keywords) ? overrides.keywords : [],
    preview: overrides.preview || "",
    sourceImages: Array.isArray(overrides.sourceImages) ? overrides.sourceImages : [],
  };
}

function getActivePreset() {
  return currentProject?.moodboardPresets?.find((preset) => preset.id === projectEditorState.activePresetId) || null;
}

async function persistCurrentProjectIdentity(options = {}) {
  if (!currentProject?.id) return;
  currentProject = createDefaultProjectRecord(currentProject);
  await saveProject(currentProject);
  if (options.refreshDashboard) await showDashboard();
}

async function prepareLocalPresetDraft(file) {
  const optimized = await optimizeImageForUpload(file);
  const hubPreview = await createHubOptimizedPreview(optimized.dataUrl, optimized.mimeType, "Preset Gorseli");
  return {
    id: createId("preset-draft"),
    name: file.name,
    typeLabel: "Preset Gorseli",
    preview: optimized.dataUrl,
    hubPreview,
    mimeType: optimized.mimeType,
    size: optimized.size,
    width: optimized.width,
    height: optimized.height,
    originalWidth: optimized.originalWidth,
    originalHeight: optimized.originalHeight,
  };
}

function renderMoodboardPresets() {
  if (!ui.presetList || !ui.presetEditor || !ui.presetEditorEmpty) return;
  const presets = currentProject?.moodboardPresets || [];
  if (!presets.length) {
    ui.presetList.innerHTML = `<div class="empty-state compact"><strong>Preset yok.</strong><p>Renk ve malzeme dillerini burada biriktirebilirsiniz.</p></div>`;
  } else {
    ui.presetList.innerHTML = presets.map((preset) => {
      const miniSwatches = (preset.colors || []).slice(0, 4).map((hex) =>
        `<span class="preset-mini-dot" style="background:${escapeHtml(hex)}"></span>`
      ).join("");
      return `
      <button type="button" class="preset-list-item ${preset.id === projectEditorState.activePresetId ? "is-active" : ""}" data-preset-id="${preset.id}">
        <div>
          <strong>${escapeHtml(preset.name)}</strong>
          <span>${escapeHtml((preset.keywords || []).slice(0, 3).join(" / ") || "Moodboard preset")}</span>
        </div>
        ${miniSwatches ? `<div class="preset-mini-swatches">${miniSwatches}</div>` : ""}
      </button>`;
    }).join("");
  }
  renderPresetDraftImages();
  const preset = getActivePreset();
  ui.presetEditor.classList.toggle("hidden", !preset);
  ui.presetEditorEmpty.classList.toggle("hidden", !!preset);
  if (!preset) return;
  ui.presetNameInput.value = preset.name || "";
  ui.presetDescriptionInput.value = preset.description || "";
  ui.presetMaterialsInput.value = Array.isArray(preset.materials) ? preset.materials.join("\n") : "";
  ui.presetColorsInput.value = Array.isArray(preset.colors) ? preset.colors.join(", ") : "";
  ui.presetKeywordsInput.value = Array.isArray(preset.keywords) ? preset.keywords.join(", ") : "";
  const preview = preset.preview || preset.sourceImages?.[0]?.preview || "";
  ui.presetPreviewImage.classList.toggle("hidden", !preview);
  ui.presetPreviewFallback.classList.toggle("hidden", !!preview);
  if (preview) ui.presetPreviewImage.src = preview;
  sanitizeStaticUiText(document.getElementById("dashboard"));
}

function renderPresetDraftImages() {
  if (!ui.presetImageStrip) return;
  if (!projectEditorState.draftImages.length) {
    ui.presetImageStrip.innerHTML = `<p class="micro-copy">AI ile preset cikarmak icin 1-4 adet referans gorsel yukleyebilirsiniz.</p>`;
    return;
  }
  ui.presetImageStrip.innerHTML = projectEditorState.draftImages.map((image) => `
    <article class="preset-thumb-card">
      <img src="${image.preview}" alt="${escapeHtml(image.name)}">
      <div>
        <strong>${escapeHtml(truncateLabel(image.name, 28))}</strong>
        <button type="button" class="text-button" data-remove-preset-image="${image.id}">Sil</button>
      </div>
    </article>
  `).join("");
}

async function handlePresetImageUpload(files) {
  if (!files.length) return;
  const prepared = await Promise.all(files.slice(0, 4).map((file) => prepareLocalPresetDraft(file)));
  projectEditorState.draftImages = [...projectEditorState.draftImages, ...prepared].slice(0, 4);
  renderMoodboardPresets();
}

function handlePresetListClick(event) {
  const removeButton = event.target.closest("[data-remove-preset-image]");
  if (removeButton) {
    projectEditorState.draftImages = projectEditorState.draftImages.filter((image) => image.id !== removeButton.dataset.removePresetImage);
    renderMoodboardPresets();
    return;
  }
  const button = event.target.closest("[data-preset-id]");
  if (!button) return;
  projectEditorState.activePresetId = button.dataset.presetId;
  renderMoodboardPresets();
}

function syncPresetDraftFromInputs(options = {}) {
  const preset = getActivePreset();
  if (!preset) return;
  preset.name = ui.presetNameInput.value.trim() || "Yeni Moodboard Preseti";
  preset.description = ui.presetDescriptionInput.value.trim();
  preset.materials = ui.presetMaterialsInput.value.split("\n").map((item) => item.trim()).filter(Boolean).slice(0, 6);
  preset.colors = ui.presetColorsInput.value.split(",").map((item) => normalizeHexColor(item.trim())).filter(Boolean).slice(0, 5);
  preset.keywords = ui.presetKeywordsInput.value.split(",").map((item) => item.trim()).filter(Boolean).slice(0, 3);
  void persistCurrentProjectIdentity();
  if (options.rerender) renderMoodboardPresets();
}

function buildPresetIdentitySummary(preset = {}) {
  const lines = [`Preset referansi: ${String(preset.name || "Moodboard Preseti").trim()}`];
  const description = String(preset.description || "").trim();
  const materials = Array.isArray(preset.materials) ? preset.materials.filter(Boolean).slice(0, 6) : [];
  const keywords = Array.isArray(preset.keywords) ? preset.keywords.filter(Boolean).slice(0, 4) : [];
  if (description) lines.push(`Aciklama: ${description}`);
  if (materials.length) lines.push(`Ana malzemeler: ${materials.join(", ")}`);
  if (keywords.length) lines.push(`Ana sifatlar: ${keywords.join(", ")}`);
  return lines.join("\n");
}

function mergeProjectNotesWithPreset(projectNotes, preset = {}) {
  const cleanedNotes = String(projectNotes || "").replace(/\n*Preset referansi:[\s\S]*$/u, "").trim();
  const presetSummary = buildPresetIdentitySummary(preset);
  return cleanedNotes ? `${cleanedNotes}\n\n${presetSummary}` : presetSummary;
}

function applyActivePresetToProjectIdentity() {
  const preset = getActivePreset();
  if (!preset || !currentProject) {
    showAlert("Projeye uygulamak icin once bir preset secin.", "warning");
    return;
  }
  syncPresetDraftFromInputs();
  const paletteColors = Array.isArray(preset.colors)
    ? preset.colors.map((color) => normalizeHexColor(color)).filter(Boolean).slice(0, 5)
    : [];
  const hasIdentitySummary =
    !!String(preset.description || "").trim()
    || (Array.isArray(preset.materials) && preset.materials.some(Boolean))
    || (Array.isArray(preset.keywords) && preset.keywords.some(Boolean));
  if (!paletteColors.length && !hasIdentitySummary) {
    showAlert("Bu presette projeye aktarilacak renk veya kimlik bilgisi bulunmuyor.", "warning");
    return;
  }
  currentProject = createDefaultProjectRecord(currentProject);
  currentProject.globalPalette = deepClone(currentProject.globalPalette || createInitialState().globalColorPalette);
  if (paletteColors.length) {
    currentProject.globalPalette.colors = paletteColors;
    if (currentProject.globalPalette.mode === "off") currentProject.globalPalette.mode = "hybrid";
  }
  currentProject.notes = mergeProjectNotesWithPreset(currentProject.notes, preset);
  if (appState.projectId === currentProject.id) {
    applyProjectIdentityToState(currentProject, appState);
    renderProjectSummary();
  }
  markProjectIdentityDirty();
  showAlert("Preset projeye uygulandi. Degisiklikleri kaydetmeyi unutmayin.", "success");
}

function createMoodboardPreset() {
  const preset = createMoodboardPresetRecord({
    preview: projectEditorState.draftImages[0]?.preview || "",
    sourceImages: deepClone(projectEditorState.draftImages),
  });
  currentProject.moodboardPresets.unshift(preset);
  projectEditorState.activePresetId = preset.id;
  void persistCurrentProjectIdentity();
  renderMoodboardPresets();
}

function saveActivePreset() {
  const preset = getActivePreset();
  if (!preset) return;
  syncPresetDraftFromInputs({ rerender: true });
  preset.preview = preset.preview || projectEditorState.draftImages[0]?.preview || "";
  if (projectEditorState.draftImages.length) preset.sourceImages = deepClone(projectEditorState.draftImages);
  void persistCurrentProjectIdentity();
  renderMoodboardPresets();
  showAlert("Moodboard preset kaydedildi.", "success");
}

function deleteActivePreset() {
  const preset = getActivePreset();
  if (!preset) return;
  currentProject.moodboardPresets = currentProject.moodboardPresets.filter((item) => item.id !== preset.id);
  projectEditorState.activePresetId = currentProject.moodboardPresets[0]?.id || "";
  void persistCurrentProjectIdentity();
  renderMoodboardPresets();
  showAlert("Preset kaldirildi.", "info");
}

async function generatePresetFromDraftImages() {
  if (!projectEditorState.draftImages.length) {
    showAlert("AI ile preset cikarmak icin once birkac referans gorsel yukleyin.", "warning");
    return;
  }
  const visionApiKey = getApiKeyForCapability("vision");
  let presetData = null;
  if (visionApiKey) {
    try {
      const response = await callGeminiGenerateContent({
        apiKey: visionApiKey,
        model: resolveTaskModel("vision"),
        contents: [{
          role: "user",
          parts: [
            {
              text: [
                "Bir ic mimari moodboard preset asistani olarak calis.",
                "Yuklenen referans gorsellerden bir ofis moodboard preseti cikar.",
                "Sadece JSON don.",
                'Beklenen JSON: {"name":"","description":"","materials":[""],"colors":["#F1EDE6","#D4CDC4","#6E6052"],"keywords":["","",""]}',
                "Adi kisa ve ofis kullanimina uygun olsun.",
                "Description tek paragraf olsun.",
                "Materials 4 ile 6 arasi olsun.",
                "Colors 3 ile 5 hex renk olsun.",
                "Keywords 2 ile 3 sifat olsun.",
              ].join(" "),
            },
            ...(await resolveInlineDataParts(projectEditorState.draftImages.slice(0, 4))),
          ],
        }],
        generationConfig: { responseMimeType: "application/json" },
      });
      presetData = parseJsonResponse(extractTextFromGeminiResponse(response));
    } catch (error) {
      console.error("Preset generation fallback:", error);
    }
  }
  const fallback = {
    name: "Sakin Kurumsal",
    description: "Dusuk kontrastli, uygulamasi dengeli, acik notr tabanli ve kurumsal kullanima uygun bir renk-malzeme dili.",
    materials: ["Acik ahsap panel", "Yari mat boya", "Mikrosement kaplama", "Lineer LED", "Dosemeli sandalye"],
    colors: ["#F1EDE6", "#D4CDC4", "#6E6052"],
    keywords: ["sakin", "kurumsal", "temiz"],
  };
  const normalized = createMoodboardPresetRecord({
    ...(presetData || fallback),
    preview: projectEditorState.draftImages[0]?.preview || "",
    sourceImages: deepClone(projectEditorState.draftImages),
  });
  currentProject.moodboardPresets.unshift(normalized);
  projectEditorState.activePresetId = normalized.id;
  void persistCurrentProjectIdentity();
  renderMoodboardPresets();
  showAlert("AI preset taslagi olusturuldu. Son dokunuslari manuel tamamlayabilirsiniz.", "success");
}

