function getCurrentLightboxItem() {
  return lightboxState.items.find((item) => item.id === lightboxState.currentId) || lightboxState.items[0] || null;
}

function openImageLightbox(src, caption, options = {}) {
  lightboxState.items = Array.isArray(options.items) ? options.items : [];
  lightboxState.currentId = options.currentId || lightboxState.items[0]?.id || "single";
  lightboxState.allowReferenceSelection = !!options.allowReferenceSelection;
  if (!lightboxState.items.length) {
    lightboxState.items = [{ id: "single", src, caption: caption || "Buyuk gorsel" }];
    lightboxState.currentId = "single";
  }
  renderLightboxGallery();
  ui.imageLightbox.classList.remove("hidden");
  ui.imageLightbox.setAttribute("aria-hidden", "false");
  document.body.style.overflow = "hidden";
}

function closeImageLightbox() {
  ui.imageLightbox.classList.add("hidden");
  ui.imageLightbox.setAttribute("aria-hidden", "true");
  lightboxState.items = [];
  lightboxState.currentId = "";
  lightboxState.allowReferenceSelection = false;
  ui.lightboxImage.src = "";
  ui.lightboxCaption.textContent = "";
  if (ui.lightboxGallery) ui.lightboxGallery.innerHTML = "";
  if (ui.lightboxDownload) ui.lightboxDownload.disabled = true;
  document.body.style.overflow = "";
}

function renderLightboxGallery() {
  const currentItem = getCurrentLightboxItem();
  if (!currentItem) return;
  ui.lightboxImage.src = currentItem.src;
  ui.lightboxImage.alt = currentItem.caption || "Buyuk gorsel";
  ui.lightboxCaption.textContent = currentItem.caption || "";
  if (ui.lightboxDownload) {
    ui.lightboxDownload.disabled = !currentItem.src;
    ui.lightboxDownload.setAttribute("aria-label", `${currentItem.caption || "Gorsel"} indir`);
  }
  if (!ui.lightboxGallery) return;
  if (lightboxState.items.length <= 1) {
    ui.lightboxGallery.innerHTML = "";
    return;
  }
  ui.lightboxGallery.innerHTML = `
    <div class="lightbox-gallery-grid">
      ${lightboxState.items.map((item) => {
    const isActive = item.id === lightboxState.currentId;
    const isReference = item.id === appState.selectedReferenceRenderId;
    return `
          <article class="lightbox-gallery-item ${isActive ? "is-active" : ""}">
            <button type="button" class="lightbox-gallery-thumb" data-lightbox-item="${item.id}">
              <img src="${item.thumb || item.src}" alt="${escapeHtml(item.caption || "Render")}">
              <span>${escapeHtml(item.caption || "Render")}</span>
            </button>
            ${lightboxState.allowReferenceSelection
        ? `<button type="button" class="lightbox-reference-button ${isReference ? "is-active" : ""}" data-lightbox-set-reference="${item.id}">${isReference ? "Kullaniliyor" : "Referans Yap"}</button>`
        : ""}
          </article>
        `;
  }).join("")}
    </div>
  `;
  sanitizeStaticUiText(ui.lightboxGallery);
}

function openReferenceGallery(startId = appState.selectedReferenceRenderId) {
  const items = appState.uploadedRenders.map((file) => ({
    id: file.id,
    src: file.preview,
    thumb: file.preview,
    caption: file.name,
  }));
  const firstId = startId || items[0]?.id;
  if (!items.length || !firstId) return;
  const currentItem = items.find((item) => item.id === firstId) || items[0];
  openImageLightbox(currentItem.src, currentItem.caption, {
    items,
    currentId: currentItem.id,
    allowReferenceSelection: true,
  });
}

