function showAlert(message, type = "info") {
  ui.alertRegion.innerHTML = `<div class="alert ${type}"><span>${escapeHtml(message)}</span><button type="button" class="text-button" id="dismiss-alert">Kapat</button></div>`;
  ui.alertRegion.querySelector("#dismiss-alert")?.addEventListener("click", () => { ui.alertRegion.innerHTML = ""; });
  clearTimeout(showAlert.timeoutId);
  showAlert.timeoutId = setTimeout(() => { ui.alertRegion.innerHTML = ""; }, 4200);
}


async function prepareUploadedFile(file, typeLabel) {
  let preview = createFilePlaceholder(file.name, typeLabel, "#53606b", "#e1e5e8");
  let hubPreview = preview;
  let uploadMeta = {
    mimeType: file.type || "application/octet-stream",
    size: file.size,
    optimized: false,
    width: null, height: null, originalWidth: null, originalHeight: null,
  };

  const mediaObj = {
    id: createId("media"),
    spaceId: appState.id,
    projectId: appState.projectId,
    type: typeLabel === "Render"
      ? "render"
      : typeLabel === "Plan"
        ? "plan"
        : typeLabel === "Preset Gorseli"
          ? "preset"
          : "external",
    name: file.name,
    mimeType: file.type || "application/octet-stream",
    metadata: {},
  };

  if (file.type.startsWith("image/")) {
    const optimized = await optimizeImageForUpload(file);
    const hubPreviewB64 = await createHubOptimizedPreview(optimized.dataUrl, optimized.mimeType, typeLabel);
    
    mediaObj.blob = base64ToBlob(optimized.dataUrl, optimized.mimeType);
    mediaObj.hubPreviewBlob = base64ToBlob(hubPreviewB64, "image/jpeg");
    
    preview = trackObjectUrl(URL.createObjectURL(mediaObj.blob));
    hubPreview = trackObjectUrl(URL.createObjectURL(mediaObj.hubPreviewBlob));
    
    uploadMeta = {
      ...uploadMeta,
      mimeType: optimized.mimeType, size: optimized.size,
      optimized: optimized.optimized, width: optimized.width, height: optimized.height,
      originalWidth: optimized.originalWidth, originalHeight: optimized.originalHeight,
    };
  } else {
    mediaObj.blob = file;
  }

  mediaObj.width = uploadMeta.width;
  mediaObj.height = uploadMeta.height;
  mediaObj.sizeBytes = uploadMeta.size;
  await saveMedia(mediaObj);
  return { id: createId("file"), mediaId: mediaObj.id, name: file.name, typeLabel, preview, hubPreview, ...uploadMeta };
}

